-- Poems batch 211
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('641e2119-1f62-48f6-be8d-7ecf2a29353a','道傍松一首','劉克莊','宋','宋诗','song-poetry','','[]','入閩多古松，夾道疎復密。',120,'全唐诗/poet.song.198000.json','["入閩多古松，夾道疎復密。", "未嘗識兵火，既久蔽雲日。", "蠢茲惰游民，深夜腰斧出。", "斸根取脂肪，竊負如鬼疾。", "譬諸人刖趾，僵仆立可必。", "供君一瞬光，夭彼千歲質。", "暴殄聖垂誡，樵採官著律。", "徼吏嗜雞豚，熟視不訶詰。", "登高撫逵路，巨幹日蕭瑟。", "哀哉暑行人，暍死誰汝恤。"]'),
('dafb3e44-a32b-4d75-a024-73a2ad916fb5','枕峰寺','劉克莊','宋','宋诗','song-poetry','','[]','夜深投寺解行裝，一點寒燈照上方。',32,'全唐诗/poet.song.198000.json','["夜深投寺解行裝，一點寒燈照上方。", "老宿問余何處去，年年來此借禪床。"]'),
('a2b80a4b-3b9c-4c5c-bafb-fcc69ed8ab78','乍歸九首  其一','劉克莊','宋','宋诗','song-poetry','','[]','官滿無南物，飄然匹馬還。',24,'全唐诗/poet.song.198000.json','["官滿無南物，飄然匹馬還。", "惟應詩卷裏，偷畫桂州山。"]'),
('a025929b-beec-4085-8b46-c0a222c6bcb8','乍歸九首  其二','劉克莊','宋','宋诗','song-poetry','','[]','兒童娛膝下，母子話燈前。',24,'全唐诗/poet.song.198000.json','["兒童娛膝下，母子話燈前。", "却憶江湖上，家書動隔年。"]'),
('050a2f22-a75c-4f04-aa61-70a1501090c1','乍歸九首  其三','劉克莊','宋','宋诗','song-poetry','','[]','北戍邊城下，南遊瘴海頭。',24,'全唐诗/poet.song.198000.json','["北戍邊城下，南遊瘴海頭。", "不知天地內，何處可逃愁。"]'),
('28d14490-f790-4434-9909-717eed38d183','乍歸九首  其四','劉克莊','宋','宋诗','song-poetry','','[]','絕愛牆陰橘，花開滿院香。',24,'全唐诗/poet.song.198000.json','["絕愛牆陰橘，花開滿院香。", "鄰人欺不在，稍覺北枝傷。"]'),
('dfa2186c-5690-461f-8f20-0b40fdda6167','乍歸九首  其五','劉克莊','宋','宋诗','song-poetry','','[]','孚若如天馬，軒昂不可羈。',24,'全唐诗/poet.song.198000.json','["孚若如天馬，軒昂不可羈。", "爲貧疎飲客，因病出名姬。"]'),
('df0fb0ff-9917-4bbd-a171-11ba232e08b0','乍歸九首  其六','劉克莊','宋','宋诗','song-poetry','','[]','弛檐逢除夕，檀欒共擁鑪。',24,'全唐诗/poet.song.198000.json','["弛檐逢除夕，檀欒共擁鑪。", "把如爲客看，還得似家無。"]'),
('34f6b61e-ce19-4db8-8a3f-244b98505373','乍歸九首  其七','劉克莊','宋','宋诗','song-poetry','','[]','架書多散亂，信手偶拈開。',24,'全唐诗/poet.song.198000.json','["架書多散亂，信手偶拈開。", "匹似前生讀，茫然記不來。"]'),
('15d00d00-b4fb-4984-9e74-e785636dec81','乍歸九首  其八','劉克莊','宋','宋诗','song-poetry','','[]','手種梅無恙，蒼苔滿樹身。',24,'全唐诗/poet.song.198000.json','["手種梅無恙，蒼苔滿樹身。", "可憐開較早，不待遠歸人。"]'),
('c8f55635-a593-40ad-a47d-86471d0c2ee8','乍歸九首  其九','劉克莊','宋','宋诗','song-poetry','','[]','格力窮方進，功夫老始知。',24,'全唐诗/poet.song.198000.json','["格力窮方進，功夫老始知。", "儘教人貶駁，喚作嶺南詩。"]'),
('139fa3d0-46b8-4e02-a99d-8ee27eeaa5b1','題坡公贈鄭介夫詩三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','玉座見圖歎，纍纍菜色民。',24,'全唐诗/poet.song.198000.json','["玉座見圖歎，纍纍菜色民。", "如何崔白輩，只寫蔡奴真。"]'),
('0049feaf-79cb-408a-9994-21cea90c5af6','題坡公贈鄭介夫詩三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','向來與相國，投分自鍾山。',24,'全唐诗/poet.song.198000.json','["向來與相國，投分自鍾山。", "不入翹材館，甘爲老抱關。"]'),
('db2d86ac-36b3-447f-959d-7ab22cfd3d84','題坡公贈鄭介夫詩三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','下吏語尤硬，投荒身轉輕。',24,'全唐诗/poet.song.198000.json','["下吏語尤硬，投荒身轉輕。", "不然玉局老，肯喚作先生。"]'),
('dd2014ba-4c9b-4a66-888f-6072b90ba919','蔡忠惠家觀墨蹟','劉克莊','宋','宋诗','song-poetry','','[]','維蔡郡之望，過者必式閭。',192,'全唐诗/poet.song.198000.json','["維蔡郡之望，過者必式閭。", "嚴嚴端明廳，遺像猶肅如。", "頗聞手澤富，儻許窺珍儲。", "主人命發笥，棐几同卷舒。", "比顔倍秀麗，眡柳加敷腴。", "亳杭兩記在，妙與蠟本殊。", "洛橋字尤佳，其大徑尺餘。", "班班名臣帖，煌煌昭陵書。", "坐令承學士，若覩慶曆初。", "向來故家物，聚散何忽諸。", "祭器抱它適，玉軸棄路隅。", "端明夢奠時，譍門惟一孤。", "厥裔日以蕃，廟院蜂房居。", "寸紙惜如命，不博明月珠。", "乃知儒澤遠，浮榮無根株。", "勗哉守視者，巾襲防蠹魚。"]'),
('2df1f092-cff8-471c-b0d0-54dc97ac2b94','昔方孚若主管雲臺予監衡嶽每歲瑞慶節常聚廣化寺拈香癸未此日獨至寺中輒題一絕','劉克莊','宋','宋诗','song-poetry','','[]','同作祠官荷聖朝，年年相待放生橋。',32,'全唐诗/poet.song.198000.json','["同作祠官荷聖朝，年年相待放生橋。", "精廬此日來無伴，稽首爐熏自祝堯。"]'),
('fc22d4a9-88a1-4594-b739-4ac8b1bf679c','有感','劉克莊','宋','宋诗','song-poetry','','[]','策策秋聲起樹枝，遥憐塞下鴈來時。',64,'全唐诗/poet.song.198000.json','["策策秋聲起樹枝，遥憐塞下鴈來時。", "寧聞中夜荒雞舞，肯拾他人竹馬騎。", "短劍舊曾交俠客，小詩猶足將偏師。", "無情却是青銅鏡，剛照書生兩鬢絲。"]'),
('cf7762ba-4472-49f9-8cd7-87bad7ac7469','挽水心先生二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','一夢孝皇初，悽然四紀餘。',48,'全唐诗/poet.song.198000.json','["一夢孝皇初，悽然四紀餘。", "國人莫知我，天下孰宗予。", "散地雖無柄，名山儘有書。", "烏虖傳萬世，猶足矯玄虛。"]'),
('a6e3c97a-04b7-4343-89b4-94996a781026','挽水心先生二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','所學如山海，吁嗟不一施。',48,'全唐诗/poet.song.198000.json','["所學如山海，吁嗟不一施。", "未聞訪箕子，但見誄宣尼。", "空郡來陪哭，無人敢撰碑。", "紛紛門弟子，若箇解稱師。"]'),
('1896f74f-66d7-48bb-8824-3c7a418751e7','林容州別墅','劉克莊','宋','宋诗','song-poetry','','[]','出郭五里强，治地十畝寬。',96,'全唐诗/poet.song.198000.json','["出郭五里强，治地十畝寬。", "奇峰面朝挹，高阜背屈蟠。", "忽獻若神授，久閟由天慳。", "茲焉卜壽宮，朱堊浮林端。", "使君世慮澹，出嶺顔如丹。", "靜思三窟危，孰如一丘安。", "蒔松既森秀，引泉亦甘寒。", "願言奉巾屨，暇日來盤桓。"]'),
('1eb5320c-18e2-4027-a259-c4cc45223a76','哭林山人','劉克莊','宋','宋诗','song-poetry','','[]','僵卧茅簷下，怡然八十春。',48,'全唐诗/poet.song.198000.json','["僵卧茅簷下，怡然八十春。", "竟無衾覆首，惟有鍾隨身。", "賻吊稀來客，封崇託外親。", "自言墳出貴，後必産奇人。"]'),
('e65f1559-64ed-40cc-8331-cf1961407ddf','挽方孚若寺丞二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','使君神雋似龍麟，行地飛空不可馴。',64,'全唐诗/poet.song.198000.json','["使君神雋似龍麟，行地飛空不可馴。", "詩裏得朋卿與我，酒邊爭霸世無人。", "寶釵去盡中年病，珠履來疎晚節貧。", "昔共誅茅聽瀑處，溪雲谷月亦悲辛。"]'),
('cb248c61-0b6c-4249-92c4-10450dbee4da','挽方孚若寺丞二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','斯人詎意掩斯丘，六合茫茫不可求。',64,'全唐诗/poet.song.198000.json','["斯人詎意掩斯丘，六合茫茫不可求。", "射虎山中如昨日，騎鯨海上忽千秋。", "帝方欲老長沙傅，虜尚能言博望侯。", "回首瀨溪溪畔路，跛馿無復從公遊。"]'),
('3cf80784-6de6-491c-9e5a-125fb9be100b','挽方武成二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','頗有翁標致，唐衣折角巾。',48,'全唐诗/poet.song.198000.json','["頗有翁標致，唐衣折角巾。", "雖疑頭小銳，極愛腹精神。", "闊矣雲霄志，悲哉露電身。", "世間無妙質，一慟惜斯人。"]'),
('df5aad2c-0587-4ceb-848b-d563cb60ffc7','挽方武成二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','丱角詩名出，流傳海內誇。',48,'全唐诗/poet.song.198000.json','["丱角詩名出，流傳海內誇。", "師稱起予者，翁問倩人邪。", "惜未參諸老，猶堪擅一家。", "從今崖瀑上，誰共訪梅花。"]'),
('733e8a3d-5ef8-4f50-b35c-b01f781a7646','福州道山亭','劉克莊','宋','宋诗','song-poetry','','[]','絕頂煙開霽色新，萬家臺觀密如鱗。',32,'全唐诗/poet.song.198000.json','["絕頂煙開霽色新，萬家臺觀密如鱗。", "城中楚楚銀袍子，來讀曾碑有幾人。"]'),
('d1c8f1e3-7a48-4711-b576-fdad0554aefe','建州','劉克莊','宋','宋诗','song-poetry','','[]','風緊雲高雪尚慳，建州城北倚闌干。',32,'全唐诗/poet.song.198000.json','["風緊雲高雪尚慳，建州城北倚闌干。", "林梢淡日紅如綫，應爲梅花煖晚寒。"]'),
('c1370113-d151-4ff2-ad7a-2d67f2973ff5','起來','劉克莊','宋','宋诗','song-poetry','','[]','起來呵手檢衣篝，燭影蛩聲伴小樓。',32,'全唐诗/poet.song.198000.json','["起來呵手檢衣篝，燭影蛩聲伴小樓。", "頼有夢中堪細說，錦牋寫不盡離愁。"]'),
('0bbb9f98-70c7-4add-b329-ec768b36af9b','入浙','劉克莊','宋','宋诗','song-poetry','','[]','浦城南畔只輕陰，入浙方驚雪許深。',32,'全唐诗/poet.song.198000.json','["浦城南畔只輕陰，入浙方驚雪許深。", "梅皜楓丹三百里，笑人短幅寫寒林。"]'),
('0904fd7b-ca3b-44ed-9eb0-2ac6b3071542','寄人','劉克莊','宋','宋诗','song-poetry','','[]','老携詩卷入京華，覓店先須近酒家。',32,'全唐诗/poet.song.198000.json','["老携詩卷入京華，覓店先須近酒家。", "白髮但能妨進取，未妨痛飲插梅花。"]'),
('90566890-c032-4787-8370-5b32365b8236','壽昌','劉克莊','宋','宋诗','song-poetry','','[]','山路泥深雪未乾，病身初怕浙西寒。',32,'全唐诗/poet.song.198000.json','["山路泥深雪未乾，病身初怕浙西寒。", "新年臺曆無人寄，且就村翁壁上看。"]'),
('3f427b18-a467-45ba-8547-43aca0d9e6cd','桐廬','劉克莊','宋','宋诗','song-poetry','','[]','桐廬道上雪花飛，一客騎馿覓雪詩。',32,'全唐诗/poet.song.198000.json','["桐廬道上雪花飛，一客騎馿覓雪詩。", "亦有扁舟蓑笠興，江行却怕子陵知。"]'),
('b406fbfa-14cb-4f75-8d4c-58077e0e09ec','富陽','劉克莊','宋','宋诗','song-poetry','','[]','便著羊裘也不難，山林未有一枝安。',32,'全唐诗/poet.song.198000.json','["便著羊裘也不難，山林未有一枝安。", "富春耕種桐江釣，却羨先生別墅寬。"]'),
('58cae95f-9122-4105-9483-1f9211eb3224','記夢','劉克莊','宋','宋诗','song-poetry','','[]','父兄誨我髧髦初，老不成名鬢髮疎。',32,'全唐诗/poet.song.198000.json','["父兄誨我髧髦初，老不成名鬢髮疎。", "紙帳鐵檠風雪夜，夢中猶誦小時書。"]'),
('1f5e9b00-66d1-4d74-9edf-66ab16d0f961','出都','劉克莊','宋','宋诗','song-poetry','','[]','客子來時臘雪飛，出城忽已試單衣。',32,'全唐诗/poet.song.198000.json','["客子來時臘雪飛，出城忽已試單衣。", "湖邊移店非無意，要共林逋話別歸。"]'),
('cee41adc-2164-439e-b378-27d7fb5d6c45','題硯','劉克莊','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吾硯平生極自珍，塗雲抹月發清新。',32,'全唐诗/poet.song.198000.json','["吾硯平生極自珍，塗雲抹月發清新。", "臨歸携就西湖洗，不受東華一點塵。"]'),
('f3b8fee6-cc4f-4634-ae86-58fc42d243e7','杜丞','劉克莊','宋','宋诗','song-poetry','','[]','憶冒重圍入，孤城頼不亡。',48,'全唐诗/poet.song.198000.json','["憶冒重圍入，孤城頼不亡。", "戰功何日賞，檄草至今藏。", "舊事歸詩卷，新寒入箭創。", "江邊逢杜杲，鬢髮各蒼蒼。"]'),
('f66fc093-2874-49b5-94ad-eea8b1372460','久客','劉克莊','宋','宋诗','song-poetry','','[]','久客長安市，人情薄似雲。',48,'全唐诗/poet.song.198000.json','["久客長安市，人情薄似雲。", "寧爲絕交論，不著送窮文。", "白髮長千丈，黄金盡百斤。", "故山春事動，深恐廢耕耘。"]'),
('128645df-dc04-4359-aa70-cfc374722304','贈陳起','劉克莊','宋','宋诗','song-poetry','','[]','陳侯生長紛華地，却以芸香自沐熏。',64,'全唐诗/poet.song.198000.json','["陳侯生長紛華地，却以芸香自沐熏。", "鍊句豈非林處士，鬻書莫是穆參軍。", "雨簷兀坐忘春去，雪案清談至夜分。", "何日我閑君閉肆，扁舟同泛北山雲。"]'),
('cb8aa74d-663d-45ef-8650-d968135e3896','贈翁卷','劉克莊','宋','宋诗','song-poetry','','[]','非止擅唐風，尤於選體工。',48,'全唐诗/poet.song.198000.json','["非止擅唐風，尤於選體工。", "有時千載事，祇在一聯中。", "世自輕前輩，天猶活此翁。", "江湖不相見，纔見又西東。"]'),
('1b9d8d08-ce4e-4329-9cc6-33a68bf5bd06','路傍桃樹','劉克莊','宋','宋诗','song-poetry','','[]','爲愛橋邊半樹斜，解衣貰酒隔橋家。',32,'全唐诗/poet.song.198000.json','["爲愛橋邊半樹斜，解衣貰酒隔橋家。", "唐人苦死無標致，只識玄都觀裏花。"]'),
('d4b78ff6-9d36-4794-9465-d3e1ffab6074','題壁','劉克莊','宋','宋诗','song-poetry','','[]','兒時挾彈長安市，不信人間果有愁。',32,'全唐诗/poet.song.198000.json','["兒時挾彈長安市，不信人間果有愁。", "行遍江南江北路，始知愁會白人頭。"]'),
('9edb4f11-9dc6-450c-95a3-794e1085eeee','馬上口占','劉克莊','宋','宋诗','song-poetry','','[]','陌上鞦韆索漸收，金鞭懶逐少年遊。',32,'全唐诗/poet.song.198000.json','["陌上鞦韆索漸收，金鞭懶逐少年遊。", "晚風細落梨花點，飛上春衫總是愁。"]'),
('2f4eb6d8-c350-44d2-b6d6-455db670c737','挽李尚書二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','韓范止如此，公乎事又艱。',48,'全唐诗/poet.song.198000.json','["韓范止如此，公乎事又艱。", "不陪冶城廟，合殉定軍山。", "璽出千官賀，弓藏一老閑。", "琱戈提十萬，猶記凱歌還。"]'),
('79249b5a-4420-4941-8025-3265cff48319','挽李尚書二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','幕下多材雋，于今盡策勳。',48,'全唐诗/poet.song.198000.json','["幕下多材雋，于今盡策勳。", "可憐狂處士，曾揖大將軍。", "久戍兒郎老，新招部曲分。", "此生甘寂寞，有淚濕高墳。"]'),
('53f97be3-cc4e-49d4-b32c-aaa472cad172','橋西','劉克莊','宋','宋诗','song-poetry','','[]','昔飲橋西歲月多，梨花深處待郎過。',32,'全唐诗/poet.song.198000.json','["昔飲橋西歲月多，梨花深處待郎過。", "垂鞭欲訪湔裙約，奈此蕭蕭鬢雪何。"]'),
('fc068e73-a2ab-4d49-a8d3-ae67d6ad309f','黄田人家別墅繚山種海棠爲賦二絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','萬紅扶路笑相迎，彷彿前身石曼卿。',32,'全唐诗/poet.song.198000.json','["萬紅扶路笑相迎，彷彿前身石曼卿。", "若向花中論富貴，芙蓉城劣海棠城。"]'),
('c99d7308-fbf3-4205-899c-b7392affbe03','黄田人家別墅繚山種海棠爲賦二絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','海棠妙處有誰知，全在臙脂乍染時。',32,'全唐诗/poet.song.198000.json','["海棠妙處有誰知，全在臙脂乍染時。", "試問玉環堪比否，玉環猶自覺離披。"]'),
('05b714dc-eb25-4b1d-8bd8-2b7a3400de6a','郭熙山水障子','劉克莊','宋','宋诗','song-poetry','','[]','高爲峯嵐下濤江，極目森秀涵蒼凉。',194,'全唐诗/poet.song.198000.json','["高爲峯嵐下濤江，極目森秀涵蒼凉。", "始知著色未造極，壹似醜女施鉛黄。", "驚泉駭石聚幽怪，巨楠穹柏蟠老蒼。", "鹿門寺，華子岡，是耶非耶遠莫詳。", "疑聞鍾聲起晻靄，似有帆影來微茫。", "陌窮渡絕雪滿坂，馿鞍釣笠分毫芒。", "炎曦亭午試展玩，坐覺煙雨生縑緗。", "古來絕藝必名士，俗史辟易安敢當。", "大年脂粉米老狂，先朝僅數燕侍郎。", "吾聞汾陽子，貴購父畫一筆不許它人藏。", "矮屏短軸已可寶，况此四幅垂華堂。", "嗚呼主人謹護守，神雷鬼電或取將。"]'),
('780d0932-5b4e-4caf-9b73-5a62d4b29aa3','挽林夫人','劉克莊','宋','宋诗','song-poetry','','[]','奉使年三十，聲名滿四夷。',48,'全唐诗/poet.song.198000.json','["奉使年三十，聲名滿四夷。", "奇哉何物媼，生此丈夫兒。", "墓竟同孫窆，家猶有婦持。", "向來稱壽地，忍聽鼓簫悲。"]'),
('c4f90c47-dbda-41bb-bd72-d397e7a5d047','挽葉夫人','劉克莊','宋','宋诗','song-poetry','','[]','年與藁砧齊，來嬪自始笄。',48,'全唐诗/poet.song.198000.json','["年與藁砧齊，來嬪自始笄。", "典刑丞相子，禮法大夫妻。", "怪鵩驚頻集，離鸞忍隻棲。", "傷心衾含等，猶是嫁時齎。"]'),
('5e43a41a-7256-4763-814b-23d85c28410c','題洪使君詩卷','劉克莊','宋','宋诗','song-poetry','','[]','刻於芹泮士爭披，傳到茅廬我竊窺。',64,'全唐诗/poet.song.198000.json','["刻於芹泮士爭披，傳到茅廬我竊窺。", "突過韋郎森戟句，高如柳惲采蘋詩。", "日惟坐嘯熏沉水，間亦摇毫品荔支。", "况有太丘爲小序，遥知流布滿京師。"]'),
('63be5388-9f47-47a1-9015-33c515c81207','關仝驟雨圖','劉克莊','宋','宋诗','song-poetry','','[]','四山昏昏如潑墨，行人對面不相覿。',226,'全唐诗/poet.song.198000.json','["四山昏昏如潑墨，行人對面不相覿。", "淒乎太陰布肅殺，闇然混沌未開闢。", "千丈拏空蟄龍起，一聲破柱春雷疾。", "我疑人間瓠子决，或是天上銀河溢。", "異哉煙霏變態中，山川墟市明歷歷。", "茅寮竹寺互掩映，疎舂殘磬渺愁寂。", "叟提魚出寒裂面，童叱牛歸泥沒膝。", "羊腸峻坂去天尺，馿饑僕瘦行安適。", "林僧卸笠窘迴步，海商拋矴憂形色。", "縱覽鯤鵬信奇偉，戲看鳧鴈亦蕭瑟。", "乃知畫妙與天通，模寫萬殊由寸筆。", "大而海嶽既盡包，細如針粟皆可識。", "向來關生何似人，想見丘壑橫胸臆。", "嗚呼使移此手爲文章，豈不擅場稱巨擘。"]'),
('4675c2db-8d0d-4ff0-9837-1b2238164e09','哭左次魏二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','少日一編書，中年丈二殳。',48,'全唐诗/poet.song.198000.json','["少日一編書，中年丈二殳。", "乃知杜預智，誰謂狄山愚。", "小試飛箝策，方爲進築圖。", "到頭麟閣上，終不著臞儒。"]'),
('e935e856-dc33-4f09-9779-718ae476404c','哭左次魏二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','甫痛何郎夭，丘明亦復然。',48,'全唐诗/poet.song.198000.json','["甫痛何郎夭，丘明亦復然。", "因思題墓上，不若鬭樽前。", "劍馬爲誰得，琴書有女傳。", "惟應千載下，配食雪堂僊。"]'),
('d96e4cf5-edfb-41a8-8da8-c7280e8d48fd','寄永嘉王侍郎','劉克莊','宋','宋诗','song-poetry','','[]','珍重西清老，書來訪薜蘿。',48,'全唐诗/poet.song.198000.json','["珍重西清老，書來訪薜蘿。", "爲邦應好在，作佛竟如何。", "花押常衙少，柑香靜坐多。", "聞公鬚尚黑，未害小婆娑。"]'),
('79e3e1b1-bf20-42e8-a8c6-827480805990','秋熱憶舊遊二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','憶昔浮江更涉淮，早秋天氣最佳哉。',64,'全唐诗/poet.song.198000.json','["憶昔浮江更涉淮，早秋天氣最佳哉。", "塞垣榆落蟬初少，澤國蘆疎鴈已來。", "風露入懷詩筆健，關山滿目笛聲哀。", "南州九月猶絺綌，縱有清樽底處開。"]'),
('ce5a4d8a-4cf4-4f07-a430-4e5c18eb6e86','秋熱憶舊遊二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','塞上秋光冷似冰，當年豪舉氣憑陵。',64,'全唐诗/poet.song.198000.json','["塞上秋光冷似冰，當年豪舉氣憑陵。", "打毬不用炎方馬，按獵初調異國鷹。", "山寨凄凉聞戍鼓，水村摇落見漁燈。", "而今病暍茅簷底，追記猶堪洗鬰蒸。"]'),
('065c0235-591b-4ae5-82f0-737ea7adb1db','哭李景溫架閣','劉克莊','宋','宋诗','song-poetry','','[]','挾策說荆州，那知亦闇投。',48,'全唐诗/poet.song.198000.json','["挾策說荆州，那知亦闇投。", "漫招溫處士，幾殺杜參謀。", "出幕有清議，還鄉空白頭。", "人間容不得，下與阿翁遊。"]'),
('9128f3e5-b308-4ad5-b890-0d1453bea14b','送鄭端州','劉克莊','宋','宋诗','song-poetry','','[]','想入漳潮境，牙旗夾路紅。',48,'全唐诗/poet.song.198000.json','["想入漳潮境，牙旗夾路紅。", "帝方憂瘴俗，君可惠清風。", "海有沉珠戶，巖無斲硯工。", "它年循吏傳，要雜古人中。"]'),
('5239292c-6074-4fa1-b878-921b83da6db0','送方子約赴衢教','劉克莊','宋','宋诗','song-poetry','','[]','博士非如吏，巍然道自居。',48,'全唐诗/poet.song.198000.json','["博士非如吏，巍然道自居。", "諸生趨避席，太守揖升車。", "朱筆濃批卷，青燈細勘書。", "漢廷重文藻，行矣召嚴徐。"]'),
('c43e95bc-1296-4974-8c2f-02039e6198ce','李園有懷孚若','劉克莊','宋','宋诗','song-poetry','','[]','曾與山公醉不歸，李園水竹尚依稀。',64,'全唐诗/poet.song.198000.json','["曾與山公醉不歸，李園水竹尚依稀。", "鈿車疾取春鶑唱，鐵笛潜驚宿鳥飛。", "昔把蟹螯同酒琖，今持馬策叩城扉。", "溪頭一片無情月，偏照愁人淚滿衣。"]'),
('edf0747a-18a4-456f-bbe5-a455c422876e','送方阜高赴衡州法掾','劉克莊','宋','宋诗','song-poetry','','[]','仕不論高下，絲毫要及民。',48,'全唐诗/poet.song.198000.json','["仕不論高下，絲毫要及民。", "君其守三尺，古有活千人。", "嶽樹侵雲杪，江蘺滿水濱。", "楚芳饑可薦，切莫歎清貧。"]'),
('d0c0c4fa-1f93-48fd-b5cf-e5571ba497e2','答敖茂才','劉克莊','宋','宋诗','song-poetry','','[]','太傅品胡兒，樊川譽阿宜。',48,'全唐诗/poet.song.198000.json','["太傅品胡兒，樊川譽阿宜。", "既爲諸父賞，焉用外人知。", "曉月家山夢，秋風客舍詩。", "桐城逢汝伯，一爲說相思。"]'),
('40c72030-13e7-4a35-88f9-8c2a001b2ffc','失貓','劉克莊','宋','宋诗','song-poetry','','[]','飼養年深性已馴，攀牆上樹可曾嗔。',64,'全唐诗/poet.song.198000.json','["飼養年深性已馴，攀牆上樹可曾嗔。", "擊鮮偶羨鄰翁富，食淡因嫌舊主貧。", "蛙跳階庭殊得意，鼠行几案若無人。", "籬間薄荷堪謀醉，何必區區慕細鱗。"]'),
('86faf782-f1c3-4ed8-9380-2c33f86e2bc0','送張應斗還番昜','劉克莊','宋','宋诗','song-poetry','','[]','蕉荔漫山霧雨繁，虬鬚客子悔南轅。',64,'全唐诗/poet.song.198000.json','["蕉荔漫山霧雨繁，虬鬚客子悔南轅。", "久留閩囝誰堪語，却憶番君可與言。", "豪傑雖窮留氣在，聖賢不死有書存。", "歸時洗換征衣了，揀箇深山緊閉門。"]'),
('4e047130-bc25-4db3-beec-9227361482b5','爲圃二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','屋邊廢地稍平治，裝點風光要自怡。',64,'全唐诗/poet.song.198000.json','["屋邊廢地稍平治，裝點風光要自怡。", "愛敬古梅如宿士，護持新筍似嬰兒。", "花窠易買姑添價，亭子難營且築基。", "老矣四科無入處，旋鉏小圃學樊遲。"]'),
('766f89f8-1ea3-46ef-9c2e-8cd0168ccc56','爲圃二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','衰病歸來占把茅，譬如僧葺退居寮。',64,'全唐诗/poet.song.198000.json','["衰病歸來占把茅，譬如僧葺退居寮。", "因存橘樹斜通徑，怕礙荷花小著橋。", "古有功名興釣築，今無物色到漁樵。", "可憐歲晚閑雙手，種罷蕪菁擷菊苗。"]'),
('4a659aa1-ddd0-4138-a01f-9e62516b24ca','送黄舒文赴欽教','劉克莊','宋','宋诗','song-poetry','','[]','博士文中虎，垂髫已定交。',48,'全唐诗/poet.song.198000.json','["博士文中虎，垂髫已定交。", "雅宜對紅藥，胡乃涉黄茅。", "薄有先生飯，全無弟子嘲。", "猶勝迂闊者，荷鍤墾荒郊。"]'),
('63d3fa74-a032-416f-af5b-fd9b1e3317fc','挽袁侍郎二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','華髮始遭逢，其如道不同。',48,'全唐诗/poet.song.198000.json','["華髮始遭逢，其如道不同。", "可曾留孟叟，俄已罷申公。", "諫草多傳出，經疑盡解通。", "豈無南董氏，奮筆紀孤忠。"]'),
('03ee7268-cc3b-49a1-97a3-8c8a9cecca1a','挽袁侍郎二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','遺誥兼新訃，同時至蓽門。',48,'全唐诗/poet.song.198000.json','["遺誥兼新訃，同時至蓽門。", "龍髯先帝遠，鮐背幾公存。", "方恨三旌晚，俄驚一鑑昏。", "潸然關世道，不是哭私恩。"]'),
('46aea541-661c-438a-a6e7-0ecea7a8ce00','敖器之宅子落成','劉克莊','宋','宋诗','song-poetry','','[]','臞翁卜築向東臯，小憩江湖半世勞。',64,'全唐诗/poet.song.198000.json','["臞翁卜築向東臯，小憩江湖半世勞。", "遶屋樹陰供杖屨，登樓山色發詩騷。", "客來賀厦杯行闊，市寫拋梁紙價高。", "白虎漸臺何處在，不如茅舍尚堅牢。"]'),
('d911dd80-ba6a-40fc-bc81-5dde44f63429','答陳珍','劉克莊','宋','宋诗','song-poetry','','[]','寂寂少游從，斯人未易逢。',48,'全唐诗/poet.song.198000.json','["寂寂少游從，斯人未易逢。", "清貧今仲子，疎雋小元龍。", "君謹提詩筆，吾當避箭鋒。", "勉旃鳴盛世，切勿效寒蛩。"]'),
('dfcffe18-4b02-49bb-9be6-dccaa069e858','挽表叔趙君任安撫二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','丞相規恢策，家庭已習聞。',48,'全唐诗/poet.song.198000.json','["丞相規恢策，家庭已習聞。", "寧論乘一障，真可帥中軍。", "玉麈無能對，金錢有即分。", "心知伏波病，多半爲忠勤。"]'),
('b0197efa-9855-4b6b-9692-5a2ba54d0613','挽表叔趙君任安撫二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','叔在兵間日，書常笑我孱。',48,'全唐诗/poet.song.198000.json','["叔在兵間日，書常笑我孱。", "初云機會易，晚歎事功難。", "寂寞郎官省，荒凉上將壇。", "遥憐會稽窆，新種短松寒。"]'),
('fbcb1166-c27a-4db4-82d0-6edc52b53608','池上榴花一本盛開','劉克莊','宋','宋诗','song-poetry','','[]','炎州氣序異，十月榴始華。',132,'全唐诗/poet.song.198000.json','["炎州氣序異，十月榴始華。", "是誰初植此，石罅抽根斜。", "綠陰蔽朝曦，朱艷奪暮霞。", "始猶一二枝，俄已千百葩。", "染人不能就，畫史無以加。", "洛陽擅牡丹，久矣埋胡沙。", "蜀州夸海棠，邈然隔夔巴。", "安知籬壁間，亦有尤物耶。", "坐令農圃室，化爲金張家。", "詩人好模擬，凍蕊并寒槎。", "斯篇儻令見，無乃譏吾奢。"]'),
('70045bea-d571-4958-a25d-988cee46c32c','蘇李泣別圖','劉克莊','宋','宋诗','song-poetry','','[]','風雲慘悽，草樹枯死。',132,'全唐诗/poet.song.198000.json','["風雲慘悽，草樹枯死。", "笳鳴馬嘶，弦驚鶻起。", "熟看境色非人間，祁連山下想如此。", "手持尊酒別故人，此生再面真無因。", "胡兒漢兒俱動色，路傍觀者爲悲辛。", "歸來暗灑茂陵淚，子孟少叔方用事。", "白頭屬國冷如冰，空使穹廬歎忠義。", "茫茫事往頼畫存，每愁歲久縑素昏。", "即今畫亦落人手，古意淒涼誰復論。"]'),
('153fb16d-751b-4da6-99f2-e768bb55030b','芙蓉二絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','湖上秋風起櫂歌，萬株映柳更依荷。',32,'全唐诗/poet.song.198000.json','["湖上秋風起櫂歌，萬株映柳更依荷。", "老來不作繁華夢，一樹池邊已覺多。"]'),
('c5898578-9074-42bb-81ab-28da45067be9','芙蓉二絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','池上秋開一兩叢，未妨冷淡伴詩翁。',32,'全唐诗/poet.song.198000.json','["池上秋開一兩叢，未妨冷淡伴詩翁。", "而今縱有看花意，不愛深紅愛淺紅。"]'),
('8d8d47ad-93f4-4c41-a991-6c1ed2404fcf','鄒莆田見傳葬書','劉克莊','宋','宋诗','song-poetry','','[]','令君葬說其傳遠，一字真堪直一縑。',64,'全唐诗/poet.song.198000.json','["令君葬說其傳遠，一字真堪直一縑。", "惜似辨材藏禊帖，愛如房相筆楞嚴。", "略疏脫誤煩重校，盡扣精微恐不廉。", "欲卜寢丘何處是，憑高試爲指東崦。"]'),
('d5df9b3c-bdf1-430a-975b-ed546b7ef366','挽鄭參議','劉克莊','宋','宋诗','song-poetry','','[]','同牓飛騰盡，君初拜小侯。',48,'全唐诗/poet.song.198000.json','["同牓飛騰盡，君初拜小侯。", "地寒推易去，天遠借難留。", "新壠家山畔，生祠嶺海頭。", "歷官如杜老，白首止參謀。"]'),
('0bd020ee-062b-44bb-a568-9744fc0ef0e7','同鄭君瑞出瀨溪即事十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','汗血名駒白玉鞭，本初父子喜華鮮。',32,'全唐诗/poet.song.198000.json','["汗血名駒白玉鞭，本初父子喜華鮮。", "只今無復狂遊侶，自卸馿鞍古店前。"]'),
('4cdb8ae0-8c55-49d2-9b1d-55d894f14c5a','同鄭君瑞出瀨溪即事十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','妓有香分客有魚，主君頭白總因渠。',32,'全唐诗/poet.song.198000.json','["妓有香分客有魚，主君頭白總因渠。", "枯楊此日悲風起，寂寞無人哭墓廬。"]'),
('b7a440b1-3584-4dec-b04d-eb745dccf6f5','同鄭君瑞出瀨溪即事十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','元凱平生以智推，今看往事一何癡。',32,'全唐诗/poet.song.198000.json','["元凱平生以智推，今看往事一何癡。", "山頭螭首猶蕪沒，那有人觀水底碑。"]'),
('2b5f557b-734c-4e3f-ab31-ae0ba4b5b511','同鄭君瑞出瀨溪即事十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','昔結精廬在半崖，苔扉無主闔還開。',32,'全唐诗/poet.song.198000.json','["昔結精廬在半崖，苔扉無主闔還開。", "近聞有虎爲看守，應是防閑俗子來。"]'),
('ef1af0d7-f069-4543-8ab5-d186fd220ba8','同鄭君瑞出瀨溪即事十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','豪士寧淪鬼趣中，曼卿昔去管芙蓉。',32,'全唐诗/poet.song.198000.json','["豪士寧淪鬼趣中，曼卿昔去管芙蓉。", "君今定作梅花主，來往山間儻一逢。"]'),
('cabd7d4f-070d-42f6-b1cc-f0c8cd69a7d0','同鄭君瑞出瀨溪即事十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','虆梩而掩古無譏，何必封崇揭禍機。',32,'全唐诗/poet.song.198000.json','["虆梩而掩古無譏，何必封崇揭禍機。", "到得珠襦金椀出，始知臝葬不爲非。"]'),
('6f98bd04-1500-455c-ad3b-68c854bda8ae','同鄭君瑞出瀨溪即事十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','古於生死驗交情，何况臺欹沼漸平。',32,'全唐诗/poet.song.198000.json','["古於生死驗交情，何况臺欹沼漸平。", "不是劉君同鄭老，苔深草合斷人行。"]'),
('4852b166-503b-4347-8d8d-0539346d8c84','同鄭君瑞出瀨溪即事十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','鐵馬防秋記昔曾，晚涂消縮似寒蠅。',32,'全唐诗/poet.song.198000.json','["鐵馬防秋記昔曾，晚涂消縮似寒蠅。", "同時校尉俱封拜，誰伴將軍獵霸陵。"]'),
('1a6dbb8d-16f0-4a4d-bf4c-f0eb231fb408','同鄭君瑞出瀨溪即事十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','北耗而今杳不知，路傍羽檄走無時。',32,'全唐诗/poet.song.198000.json','["北耗而今杳不知，路傍羽檄走無時。", "自憐滿鏡星星髮，羞見官中募士旗。"]'),
('23e40504-d8a2-4a78-ba7a-d914188adab0','同鄭君瑞出瀨溪即事十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','老奴昔逐我西東，捷似猿猱跳絕峯。',32,'全唐诗/poet.song.198000.json','["老奴昔逐我西東，捷似猿猱跳絕峯。", "今日道旁扶一拐，汝公安得不龍鍾。"]'),
('a62e93c9-29ac-474e-bcc8-865e91abacbc','敖茂才論詩','劉克莊','宋','宋诗','song-poetry','','[]','詩道不勝玄，難於問性天。',48,'全唐诗/poet.song.198000.json','["詩道不勝玄，難於問性天。", "莫求鄰媼誦，姑付後儒箋。", "至質翻如俚，尤癯始似僊。", "吾非肝肺異，先得子同然。"]'),
('862f9dfe-1550-4dac-800c-934d8b707aab','鎖諫圖','劉克莊','宋','宋诗','song-poetry','','[]','讜言直觸大單于，頼有閼氏上諫書。',32,'全唐诗/poet.song.198000.json','["讜言直觸大單于，頼有閼氏上諫書。", "若把漢唐宮苑比，玉環飛燕總輸渠。"]'),
('14999b83-a8d3-44c5-9d80-86d7680e2189','哭劉連江','劉克莊','宋','宋诗','song-poetry','','[]','晚唐才調晉風期，一片胸襟頗涉奇。',64,'全唐诗/poet.song.198000.json','["晚唐才調晉風期，一片胸襟頗涉奇。", "每過鄰家因貰酒，偶添別墅爲贏碁。", "議郎秩淺無超拜，令尹官清有去思。", "種得花成身不見，江邊父老至今悲。"]'),
('8139ceb8-c0d3-42cb-8609-c23a3d905428','明皇按樂圖','劉克莊','宋','宋诗','song-poetry','','[]','鶑啼花開春晝遲，掖庭無事方遨嬉。',192,'全唐诗/poet.song.198000.json','["鶑啼花開春晝遲，掖庭無事方遨嬉。", "廣平策免曲江去，十郎談笑居台司。", "屏間無逸不復覩，教雞能鬭馬能舞。", "戲呼寧哥吹玉笛，催喚花奴打羯鼓。", "南衙群臣朝見疎，老伶巨璫前後趨。", "阿瞞半醉倚玉座，袖有曲譜無諫書。", "金盆皇孫真龍種，浴罷六宮競圍擁。", "惜哉傍有錦綳兒，蹴破咸秦跳河隴。", "古來治亂本無常，東封未了西幸忙。", "輦邊貴人亦何罪，禍胎似在偃月堂。", "今人不識前朝事，但見斷縑粧束異。", "豈知當日亂離人，說著開元總垂淚。"]'),
('e88665fc-e604-4dc6-8a0b-1ee658ad0821','哭李公晦二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','不會蒼天意，令君死五谿。',48,'全唐诗/poet.song.198000.json','["不會蒼天意，令君死五谿。", "少曾游洛下，晚乃相膠西。", "白首尊師說，丹心對御題。", "悲乎成底事，路遠客魂迷。"]'),
('5df10553-101a-42d3-abdf-cbcd75a2d33a','哭李公晦二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','洲邊三畝宅，有竹有梅花。',48,'全唐诗/poet.song.198000.json','["洲邊三畝宅，有竹有梅花。", "豈不堪名世，何如勿起家。", "身纔著朱綬，州謾出丹砂。", "渺渺重湖外，悲風咽暮笳。"]'),
('0a158f0d-f837-4afa-82a2-9ac1797e4fca','送鄒莆田','劉克莊','宋','宋诗','song-poetry','','[]','日日焚香出，天知令尹心。',48,'全唐诗/poet.song.198000.json','["日日焚香出，天知令尹心。", "租符環境少，花判入人深。", "發路惟詩卷，般家亦俸金。", "極爲鄉井惜，不是愴分襟。"]'),
('d9865479-e885-4eec-ad3b-aae6cdb62004','即事四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','買得荒郊五畝餘，旋營花木置琴書。',64,'全唐诗/poet.song.198000.json','["買得荒郊五畝餘，旋營花木置琴書。", "柳能樊圃猶須種，蘭縱當門亦不鋤。", "無力改牆姑覆草，多方存井要澆蔬。", "區區才志聊如此，誰謂先生廣且疎。"]'),
('29bda2d0-646b-409b-815e-eb78625b2f4c','即事四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','目爲詩客不勝慙，喚作園翁定自堪。',64,'全唐诗/poet.song.198000.json','["目爲詩客不勝慙，喚作園翁定自堪。", "抱甕荷鋤非鄙事，栽花移竹似清談。", "野人只識羹芹美，相國安知食笋甘。", "晚覺齊民書最要，惜無幽士肯同參。"]'),
('062aacb7-c770-428a-8d30-95d5562f6d11','即事四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','牆角新開白版扉，時尋樵牧弄煙霏。',64,'全唐诗/poet.song.198000.json','["牆角新開白版扉，時尋樵牧弄煙霏。", "代耕豈若收躬稼，賜帛何如出自機。", "湖海浪遊今已倦，山林獨往未全非。", "百年只願身强健，長爲慈親負米歸。"]'),
('b3c7889d-9c0f-4fea-bb33-5f84b71ed6f3','即事四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','待鑿新池引一灣，更規高阜敞三間。',64,'全唐诗/poet.song.198000.json','["待鑿新池引一灣，更規高阜敞三間。", "縮牆恐犯鄰家地，減樹圖看屋後山。", "身隠免貽千載笑，書成猶要十年閑。", "門前驀有相尋者，但說翁今怕往還。"]'),
('4886c680-1486-42a2-a1c5-dc99796a4fb7','梅花五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','髣髴瑶姬擁仗來，茆簷化作玉樓臺。',32,'全唐诗/poet.song.198000.json','["髣髴瑶姬擁仗來，茆簷化作玉樓臺。", "平明遶砌圓殘夢，元是梅花數樹開。"]'),
('68d75c45-86c5-43c9-818e-97cf1c77b461','梅花五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','糝地紛紛著樹稀，歲華摇落慘將歸。',32,'全唐诗/poet.song.198000.json','["糝地紛紛著樹稀，歲華摇落慘將歸。", "世間尤物難調護，寒怕開遲暖怕飛。"]'),
('8732078e-30e5-4758-b968-ca9cfa4bc512','梅花五首  其三','劉克莊','宋','宋诗','song-poetry','','["\u897f\u6e56"]','籬邊屋角立多時，試爲騷人拾棄遺。',32,'全唐诗/poet.song.198000.json','["籬邊屋角立多時，試爲騷人拾棄遺。", "不信西湖高士死，梅花寂寞便無詩。"]'),
('782cf926-21a2-4f04-88a5-1ef94088ea7b','梅花五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','肯因冷澹怨年芳，霜滿寒林月滿塘。',32,'全唐诗/poet.song.198000.json','["肯因冷澹怨年芳，霜滿寒林月滿塘。", "至白世間惟玉雪，不如伊處爲無香。"]'),
('6b7def9c-210e-42c0-bc08-fedeb6748335','梅花五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','夜來幾陣隔窗風，便恐明朝已掃空。',32,'全唐诗/poet.song.198000.json','["夜來幾陣隔窗風，便恐明朝已掃空。", "點在青苔真可惜，不如吹入酒杯中。"]'),
('ea075e8b-7085-4315-9554-8f5e114fee0b','送邢仙遊','劉克莊','宋','宋诗','song-poetry','','[]','彼美邢侯者，逢人滿口夸。',48,'全唐诗/poet.song.198000.json','["彼美邢侯者，逢人滿口夸。", "有恩霑小戶，無勢撓公家。", "拔盡民間薤，栽添境內花。", "吾詩采清論，一字不曾加。"]'),
('b06d6edd-6912-487c-b853-7ad2c3bcbe6e','夜登甘露山二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','小家三兩戶，荒巘萬千重。',24,'全唐诗/poet.song.198000.json','["小家三兩戶，荒巘萬千重。", "有月犬時吠，無人泉自舂。"]'),
('54aa0b51-51bd-4d07-a38a-61c1ce2ffb38','夜登甘露山二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','月落宿禽起，幽人殊未迴。',24,'全唐诗/poet.song.198000.json','["月落宿禽起，幽人殊未迴。", "不知何處磬，迢遞過山來。"]'),
('fd9df18d-b61d-4eb5-a82b-a037c75722d1','書事二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','竭海夷山氣力雄，只愁無術駐顔紅。',32,'全唐诗/poet.song.198000.json','["竭海夷山氣力雄，只愁無術駐顔紅。", "却須擘劃千餘歲，多買丹砂置女僮。"]'),
('66b340e9-5a80-4127-b7d5-64c73541715a','書事二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','因治陶朱術太精，世間無物足經營。',32,'全唐诗/poet.song.198000.json','["因治陶朱術太精，世間無物足經營。", "更將郭璞書頻看，只恐青山盡鑿平。"]'),
('efb48adf-6ab0-4cd7-9ec7-28d2a6ff1542','送權郡詹通判','劉克莊','宋','宋诗','song-poetry','','[]','鎮靜一如無，頒條甫月餘。',48,'全唐诗/poet.song.198000.json','["鎮靜一如無，頒條甫月餘。", "來惟居傳舍，去不識兵厨。", "健判風生筆，精祈雨灑車。", "丈夫何必假，行矣兩輪朱。"]'),
('b816e3ec-2eac-425b-b51d-bd5300804e77','再題鍾賢良詠歸堂','劉克莊','宋','宋诗','song-poetry','','[]','伏戲以來凡幾年，六經之外凡幾書。',192,'全唐诗/poet.song.198000.json','["伏戲以來凡幾年，六經之外凡幾書。", "人間簡冊渺烟海，君以約法包無餘。", "往年華轂臨敝廬，舌端霆卷俄電舒。", "平欺賈董等下駟，冷笑服鄭真蠹魚。", "千詢萬扣答如響，捫腹始媿吾空虛。", "伯高辟易季度走，六論三策何時攄。", "又言諸子皆丈夫，經笥武庫隨所須。", "觀君毛骨老猶爾，惜也未見雛與駒。", "方今主相求極諫，君曷不携軾轍俱。", "自云素鄙從橫學，尚友洙泗談古初。", "堂堂冕輅豈不好，却慕點也寧非迂。", "行當端委秉周禮，未可春服從魯儒。"]'),
('0db14a3c-b93f-4a03-9692-4216e6e8a552','送洪使君','劉克莊','宋','宋诗','song-poetry','','[]','雖擁朱轓貴，清臞兩鬢霜。',48,'全唐诗/poet.song.198000.json','["雖擁朱轓貴，清臞兩鬢霜。", "判花人競誦，詩草士深藏。", "農飽因蠲賦，州貧爲捄荒。", "公歸無媿面，應可見嚴光。"]'),
('dae0378e-18e7-49ad-a372-f89d20d67677','送陳魯叟使君赴廣西漕  其一','劉克莊','宋','宋诗','song-poetry','','[]','闔郡留無計，匆匆奪父師。',48,'全唐诗/poet.song.198000.json','["闔郡留無計，匆匆奪父師。", "使君三月政，遺老百年思。", "遠宦生華髮，輕裝載舊碑。", "海山應有恨，未得謝公詩。"]'),
('8ddd33c8-0855-49a0-ad90-a6b5f7bcaa8a','送陳魯叟使君赴廣西漕  其二','劉克莊','宋','宋诗','song-poetry','','[]','韓杜曾遊處，君行得細尋。',48,'全唐诗/poet.song.198000.json','["韓杜曾遊處，君行得細尋。", "那知瘴煙裏，忽有福星臨。", "竭海求珠蚌，搜山採翠禽。", "定將冰與檗，一洗濁夫心。"]'),
('5d3cec03-fe86-4124-9d21-827ab155f92e','永嘉黄九萬見訪','劉克莊','宋','宋诗','song-poetry','','[]','避暑惟高卧，柴門閉不通。',48,'全唐诗/poet.song.198000.json','["避暑惟高卧，柴門閉不通。", "子來佩明月，予起濯清風。", "有墅猶當贈，無城可得攻。", "靈舒如見問，今作灌園翁。"]'),
('5a5b2065-0204-4407-9030-42c3ee6eec18','別宋斌文叔','劉克莊','宋','宋诗','song-poetry','','[]','天下書無數，君專治四書。',48,'全唐诗/poet.song.198000.json','["天下書無數，君專治四書。", "因留精舍久，遂向舉場疎。", "山路挑包去，秋風罷講餘。", "故園荒草合，似欠一番鋤。"]'),
('b3babb39-f4be-42db-9788-ab2a8deffd80','熊主簿示梅花十絕詩至梅花已過因觀海棠輒次其韻  其一','劉克莊','宋','宋诗','song-poetry','','[]','萬蘂千葩染似紅，停盃無語恨東風。',32,'全唐诗/poet.song.198000.json','["萬蘂千葩染似紅，停盃無語恨東風。", "薄寒且爲花愁惱，何况開時值雨中。"]'),
('b3b6034d-ff30-4489-ae14-d5e21f714cbd','熊主簿示梅花十絕詩至梅花已過因觀海棠輒次其韻  其二','劉克莊','宋','宋诗','song-poetry','','[]','紅點霏霏似撒沙，荒園幻作五侯家。',32,'全唐诗/poet.song.198000.json','["紅點霏霏似撒沙，荒園幻作五侯家。", "自憐改盡青青鬢，無力栽花且看花。"]'),
('262303a3-bc8e-44a2-b9aa-0991b9de0997','熊主簿示梅花十絕詩至梅花已過因觀海棠輒次其韻  其三','劉克莊','宋','宋诗','song-poetry','','[]','幾樹繁紅映碧灣，苧蘿山下見芳顔。',32,'全唐诗/poet.song.198000.json','["幾樹繁紅映碧灣，苧蘿山下見芳顔。", "分明消得黄金屋，却墮荒蹊野徑間。"]'),
('02c9e0af-8ada-4beb-9fd5-b42c7e53cd91','熊主簿示梅花十絕詩至梅花已過因觀海棠輒次其韻  其四','劉克莊','宋','宋诗','song-poetry','','[]','顛風猛雨阻追攀，欲問春留數日間。',32,'全唐诗/poet.song.198000.json','["顛風猛雨阻追攀，欲問春留數日間。", "過眼紅雲成白雪，到晴祇恐沒花看。"]'),
('d12556f7-8235-4f51-8406-4169e5e04c81','熊主簿示梅花十絕詩至梅花已過因觀海棠輒次其韻  其五','劉克莊','宋','宋诗','song-poetry','','[]','梅太酸寒蘭太清，海棠方可入丹青。',32,'全唐诗/poet.song.198000.json','["梅太酸寒蘭太清，海棠方可入丹青。", "趙昌骨朽徐熙死，誰寫春風上錦屏。"]'),
('f681d955-58c5-4c40-9bd1-215ad1c612ab','熊主簿示梅花十絕詩至梅花已過因觀海棠輒次其韻  其六','劉克莊','宋','宋诗','song-poetry','','[]','特以穠纖壓衆芳，癡人癡殺恨無香。',32,'全唐诗/poet.song.198000.json','["特以穠纖壓衆芳，癡人癡殺恨無香。", "問渠嫵媚房櫳裏，何似莊嚴几研傍。"]'),
('36444c72-9c4a-4695-841a-90d91f3bc34b','熊主簿示梅花十絕詩至梅花已過因觀海棠輒次其韻  其七','劉克莊','宋','宋诗','song-poetry','','[]','共倒殘尊過日西，重來花事想參差。',32,'全唐诗/poet.song.198000.json','["共倒殘尊過日西，重來花事想參差。", "建陽主簿今才子，焉可無詩補杜詩。"]'),
('2312ca22-7eb6-467d-950a-918f067088e1','熊主簿示梅花十絕詩至梅花已過因觀海棠輒次其韻  其八','劉克莊','宋','宋诗','song-poetry','','[]','歸騎何須抵死催，且拈落蕊藉蒼苔。',32,'全唐诗/poet.song.198000.json','["歸騎何須抵死催，且拈落蕊藉蒼苔。", "平生酷喜坡長句，筆力今誰可奪胎。"]'),
('1edcfdb1-4520-459d-b980-8c83e8710315','熊主簿示梅花十絕詩至梅花已過因觀海棠輒次其韻  其九','劉克莊','宋','宋诗','song-poetry','','[]','暮雨廉纖似入梅，一春花月欠攀陪。',32,'全唐诗/poet.song.198000.json','["暮雨廉纖似入梅，一春花月欠攀陪。", "草生後圃深三尺，也道身爲縣令來。"]'),
('d9c195a2-fb54-43ee-abf4-efec3a0a66b9','熊主簿示梅花十絕詩至梅花已過因觀海棠輒次其韻  其一○','劉克莊','宋','宋诗','song-poetry','','[]','海棠洞下醉忘歸，歲月如馳不可追。',32,'全唐诗/poet.song.198000.json','["海棠洞下醉忘歸，歲月如馳不可追。", "想得千株今合抱，此生未卜再遊時。"]'),
('70190eb5-fc9e-46c2-b4a7-a73daf258566','再和十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','色深乍擣守宮紅，片細俄隨蛺蝶風。',32,'全唐诗/poet.song.198000.json','["色深乍擣守宮紅，片細俄隨蛺蝶風。", "到得離披無意緒，精神全在半開中。"]'),
('a7bb2d8a-99b7-4e55-9976-850a4a5b47c6','再和十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','薔薇難比况金沙，一種風標富貴家。',32,'全唐诗/poet.song.198000.json','["薔薇難比况金沙，一種風標富貴家。", "我有公評君記取，惜花須惜海棠花。"]'),
('88ea6c4b-990c-4c97-bbbb-c0e006f9c7af','再和十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','千株絳雪照滄灣，應笑劉郎带老顔。',32,'全唐诗/poet.song.198000.json','["千株絳雪照滄灣，應笑劉郎带老顔。", "尚有少年情味在，戲搜綺語續花間。"]'),
('a867a5ad-a132-4d79-8ccd-b0ab9bcdea50','再和十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','鳳州宮柳昔曾攀，亦醉瓊花芍藥間。',32,'全唐诗/poet.song.198000.json','["鳳州宮柳昔曾攀，亦醉瓊花芍藥間。", "獨有海棠心未足，每逢多處必來看。"]'),
('34e5bb8f-584c-4a84-930d-d7d782e978a3','再和十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','劉園水竹絕幽清，花徑繁紅蘚砌青。',32,'全唐诗/poet.song.198000.json','["劉園水竹絕幽清，花徑繁紅蘚砌青。", "何處貴游開步障，誰家生色畫深屏。"]'),
('52d79b9e-4fee-4f39-a22a-566410bbfb36','再和十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','徙倚溪亭惜墜芳，恨無異域返魂香。',32,'全唐诗/poet.song.198000.json','["徙倚溪亭惜墜芳，恨無異域返魂香。", "殘枝併恐風吹去，插在金瓶置坐傍。"]'),
('afb7678d-fd2d-49d7-8cbc-69c226b6c396','再和十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','忽憶聯鞍過水西，重尋前約未參差。',32,'全唐诗/poet.song.198000.json','["忽憶聯鞍過水西，重尋前約未參差。", "祇愁人議風流罪，屢出看花數賦詩。"]'),
('a7163bf1-286f-472c-bc8c-ad49f4106a96','再和十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','淡賞無煩羯鼓催，解鞍便可坐莓苔。',32,'全唐诗/poet.song.198000.json','["淡賞無煩羯鼓催，解鞍便可坐莓苔。", "莫將花與楊妃比，能與三郎作禍胎。"]'),
('3afceb2e-e491-4060-aff3-84b6be24d2fd','再和十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','旋挑野菜拾青梅，又向花邊得暫陪。',32,'全唐诗/poet.song.198000.json','["旋挑野菜拾青梅，又向花邊得暫陪。", "各選一枝簪白髮，明年知與阿誰來。"]'),
('f0ac9c1e-f146-473d-98a1-531efbe74e41','再和十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','君憶東湖不久歸，我思陳迹恍難追。',32,'全唐诗/poet.song.198000.json','["君憶東湖不久歸，我思陳迹恍難追。", "殷勤爲報鶑花說，止有詩情似舊時。"]'),
('cfb8fe53-1b7a-45ae-b124-ce135a7e9412','水心先生爲趙振文作馬堘歌次韻','劉克莊','宋','宋诗','song-poetry','','[]','洛陽牡丹隔萬里，棘荒姚魏扶不起。',195,'全唐诗/poet.song.198000.json','["洛陽牡丹隔萬里，棘荒姚魏扶不起。", "馬堘近在杭州陌，野人只向詩中識。", "勻朱傅粉初窺牆，海棠爲屋辛夷房。", "千林春色已呈露，一株國艷猶閟藏。", "多情荀令香透袖，俊遊恐落都人後。", "摇鞭深入紅雲鄉，解衣旋貰黄縢酒。", "淮南芍藥初過兵，人生何必塞上行。", "墜裀委壤各有命，肯學凍士鳴不平。", "移家欲傍園翁住，手開蕪地通蘋渚。", "尋芳栩栩趁蝶飛，逐臭紛紛憐蚋聚。", "君不見玄都吟筆妙燕許，詩人却遣世人怒。", "君若拏舟獨往時，我亦荷鋤相隨去。"]'),
('0d15c56f-c68f-43db-a045-56a7d9a18fba','贈高九萬并寄孫季蕃二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','諸人凋落盡，高叟亦中年。',48,'全唐诗/poet.song.198000.json','["諸人凋落盡，高叟亦中年。", "行世有千首，買山無一錢。", "紫髯長拂地，白眼冷看天。", "古道微如綫，吾儕各勉旃。"]'),
('3be02303-a612-4769-93ac-4c92d19029e7','贈高九萬并寄孫季蕃二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','菊磵說花翁，飄蓬向浙中。',48,'全唐诗/poet.song.198000.json','["菊磵說花翁，飄蓬向浙中。", "無書上皇帝，有句惱天公。", "世事年年異，詩人箇箇窮。", "築臺并下榻，今豈乏英雄。"]'),
('bd15e429-c230-4623-a90b-d86ebfd7e369','題何秀才詩禪方丈','劉克莊','宋','宋诗','song-poetry','','[]','景建談之子，詩禪丈室寬。',48,'全唐诗/poet.song.198000.json','["景建談之子，詩禪丈室寬。", "能將鉛槧事，止作葛藤看。", "壞衲蒙頭易，玄機得髓難。", "何因清夜話，分我一蒲團。"]'),
('703308c4-67b0-4215-a3a2-6c474daf03ee','挽邵武洪倅','劉克莊','宋','宋诗','song-poetry','','[]','不識監州面，聞名似舊知。',48,'全唐诗/poet.song.198000.json','["不識監州面，聞名似舊知。", "空餘商榷恨，竟失合并時。", "昔作大蘇客，今觀小謝詩。", "西風丹旐過，一爲士林悲。"]'),
('6d14158e-522d-4681-996f-285defbf57e6','挽夔漕王中甫二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','羽書堆裏挾遺編，往古來今盡粲然。',64,'全唐诗/poet.song.198000.json','["羽書堆裏挾遺編，往古來今盡粲然。", "白髮晚持川口節，丹旌暑下峽門船。", "生前多半遊榆塞，身後纔方領木天。", "老去一雙懷舊淚，誰知滴向建溪邊。"]'),
('54375fe6-f4ab-4863-84f5-e860192a3528','挽夔漕王中甫二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','半瓢丹藥一邛枝，萬里西來撫事悲。',64,'全唐诗/poet.song.198000.json','["半瓢丹藥一邛枝，萬里西來撫事悲。", "綬著藏中公事定，劍鳴匣內我年衰。", "可憐檄筆今零落，尚記綸巾共指麾。", "身在滄洲搔白首，斷腸吟就八哀詩。"]'),
('712d4b82-ccb7-45cb-86f3-78ae350d3aed','挽葉潜仲運幹二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','雖出自貂蟬，清貧雪滿顛。',48,'全唐诗/poet.song.198000.json','["雖出自貂蟬，清貧雪滿顛。", "若無槐簡後，一似布衣然。", "讀久遺編絕，藏深拱璧全。", "悲乎如此士，不貴又無年。"]'),
('f0c29520-3057-49ae-98ca-09b9e5639521','挽葉潜仲運幹二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','俱入平蠻幙，同登出嶺舟。',48,'全唐诗/poet.song.198000.json','["俱入平蠻幙，同登出嶺舟。", "交情傾蓋盡，世事闔棺休。", "客致生芻去，家惟斷藁留。", "遥知風雨夜，愁絕老參謀。"]'),
('9685dec4-75e3-4113-be30-e74d27c58b5e','送熊主簿','劉克莊','宋','宋诗','song-poetry','','[]','邑事多商榷，惟詩未暇論。',48,'全唐诗/poet.song.198000.json','["邑事多商榷，惟詩未暇論。", "母慈催扇枕，父老謾攀轅。", "新戍謀何地，初程宿某村。", "西風有來鴈，書札儻相存。"]'),
('025646ac-9673-4695-ab06-4a358edc4733','送徐夏叔','劉克莊','宋','宋诗','song-poetry','','[]','昔與長君親，今方識少君。',48,'全唐诗/poet.song.198000.json','["昔與長君親，今方識少君。", "極知皆造理，何止並能文。", "讀照湘中雪，吟開嶽頂雲。", "老余才思竭，搔首念離羣。"]'),
('da79fa0e-55f4-49bf-9b94-45ed493ecc26','和答北山','劉克莊','宋','宋诗','song-poetry','','[]','北山當代文章祖，孔思周情幸未泯。',64,'全唐诗/poet.song.198000.json','["北山當代文章祖，孔思周情幸未泯。", "弟子力疲心尚在，先生齒宿意逾新。", "今無斲鼻成風手，古有埋腰立雪人。", "不向師門勤稽首，一生懷抱對誰伸。"]'),
('282a0d15-149b-477c-8fb1-8ac56fc0b846','挽樓暘叔二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','白首臨凋瘵，虀鹽似舊時。',48,'全唐诗/poet.song.198000.json','["白首臨凋瘵，虀鹽似舊時。", "僅持一麾止，安用五車爲。", "庫有留州賦，家無葬地資。", "空餘清儉字，長使郡人思。"]'),
('37092a5b-da30-4f2f-9d0b-07b84d085be3','挽樓暘叔二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','平生所歷最崎嶔，不覺周南歲月深。',64,'全唐诗/poet.song.198000.json','["平生所歷最崎嶔，不覺周南歲月深。", "拙宦元無金潤屋，悼亡新有雪盈簪。", "淒淒德曜齊眉案，草草黔婁覆首衾。", "曾忝郡民漸教化，眼看雙旐一沾襟。"]'),
('026cd2df-d96c-4cf9-9e39-9a0a64f581ab','勞農二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','江浙膏腴動渺然，惟閩磽薄少平川。',64,'全唐诗/poet.song.198000.json','["江浙膏腴動渺然，惟閩磽薄少平川。", "可憐老子扶凋邑，絕似吾民墾瘠田。", "稍喜一犂翻宿雨，聊爲三爵禮高年。", "太平主相調元氣，春在桑畦麥壠邊。"]'),
('f78a8f9f-993b-4377-9a5e-93e278d26ede','勞農二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','畫簷一夜雨飄蕭，際曉陰霾掃碧霄。',64,'全唐诗/poet.song.198000.json','["畫簷一夜雨飄蕭，際曉陰霾掃碧霄。", "有日暫看旗脚展，無風初覺鼓声調。", "紛紛竭作趨南畝，稍稍新粧出北橋。", "白髮長官塵土殺，尚能覓句補風謠。"]'),
('f173dfb8-3d35-4501-bb0e-b305aa07cc77','答惠州曾使君韻二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','瀟灑使君風度峻，神仙謫墮在人間。',32,'全唐诗/poet.song.198000.json','["瀟灑使君風度峻，神仙謫墮在人間。", "只今坐嘯凝香處，帝賜羅浮作鎮山。"]'),
('1ceab3b9-2ffc-47f6-b23e-1268048ca835','答惠州曾使君韻二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','先賢平易以觀詩，不曉尖新與崛奇。',32,'全唐诗/poet.song.198000.json','["先賢平易以觀詩，不曉尖新與崛奇。", "若似後儒穿鑿說，占人字字總堪疑。"]'),
('d99ed04c-886a-478c-a223-99ab177156c3','送參議滕告院挂冠','劉克莊','宋','宋诗','song-poetry','','[]','由來恬退士，史冊亦稀疎。',48,'全唐诗/poet.song.198000.json','["由來恬退士，史冊亦稀疎。", "唐有楊少尹，漢惟疏大夫。", "翁能辭祿去，我欲殺青書。", "今世無名筆，誰爲寫作圖。"]'),
('187ccac8-cba9-431a-9860-b2faf3a5fbc4','挽建昌詹使君二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','南渡鈞樞後，宣和節義門。',48,'全唐诗/poet.song.198000.json','["南渡鈞樞後，宣和節義門。", "依然窶人子，不似貴公孫。", "苦李無誰採，甘棠在處存。", "遥知宦遊地，巷哭更招魂。"]'),
('d9a7485c-68db-4b66-a01e-7896b98b7e28','挽建昌詹使君二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','稍喜佩銅魚，邅迴四紀餘。',48,'全唐诗/poet.song.198000.json','["稍喜佩銅魚，邅迴四紀餘。", "早無人料理，晚有鬼揶揄。", "把酒言猶在，凝香夢竟虛。", "斯人止如此，恐坐太清臞。"]'),
('f0d33422-a8e4-41b2-a74d-946fba9d1695','和葉尚書解印二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','郡人不識疾呼聲，甘雨和風徧一城。',64,'全唐诗/poet.song.198000.json','["郡人不識疾呼聲，甘雨和風徧一城。", "歲久偏多遺愛事，天高未察借留情。", "舟行精舍漁歌晚，家近華亭鶴唳清。", "莫比歸雲并倦翼，先生此念素來輕。"]'),
('5dc18de5-8e75-4592-b35f-062e743f83ba','和葉尚書解印二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','倦入承明聽履聲，朱轓今復厭專城。',64,'全唐诗/poet.song.198000.json','["倦入承明聽履聲，朱轓今復厭專城。", "盪胸太華供吟興，照眼伊川洗宦情。", "蓴鱠何慙高士决，琴龜不減昔賢清。", "未應便葺東山墅，出處方關世重輕。"]'),
('531d7ba2-afbf-4caa-9a24-71a053e0cd3f','送葉尚書奉祠二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','先生清夢繞林泉，黄紙除書拜地僊。',64,'全唐诗/poet.song.198000.json','["先生清夢繞林泉，黄紙除書拜地僊。", "報答吾君吾相了，徜徉某水某丘邊。", "事光白傅求閑後，銜似溫公約史年。", "笑向故山猨鶴說，古來晚節幾人全。"]'),
('45302542-ae1b-489b-bdc5-9a9aa100c611','送葉尚書奉祠二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','身於七邑最孤寒，每辱黄堂刮眼看。',64,'全唐诗/poet.song.198000.json','["身於七邑最孤寒，每辱黄堂刮眼看。", "乍可郡無九年蓄，要令民受一分寬。", "公閑去伴种司諫，我懶思尋靖長官。", "曾出龍門稱弟子，感知惟有寸心丹。"]'),
('d1086a62-5a16-43db-8117-89055b06cc1e','挽盧母黄太孺人','劉克莊','宋','宋诗','song-poetry','','[]','太孺賢聲衆論推，府君經學里人師。',64,'全唐诗/poet.song.198000.json','["太孺賢聲衆論推，府君經學里人師。", "牛衣隠約能偕老，螢火淒涼自課兒。", "疇昔黄齏曾百甕，只今丹桂已雙枝。", "烏虖盧母哀榮甚，何必人題墓上碑。"]'),
('f7e1469d-adf2-4d96-92a7-ad334f7b6f2d','寄熊主簿','劉克莊','宋','宋诗','song-poetry','','[]','一出懸知計已非，更堪留滯未成歸。',64,'全唐诗/poet.song.198000.json','["一出懸知計已非，更堪留滯未成歸。", "即今白首負松菊，何處青山無蕨薇。", "不恨老從中歲至，但悲事與素心違。", "當齋寂寞生秋草，幾度臨風憶杜微。"]'),
('e83b7264-78f5-4352-a848-60779c38a748','寄徐夏叔','劉克莊','宋','宋诗','song-poetry','','[]','曾識徐卿二子奇，秋來往往夢瓊枝。',64,'全唐诗/poet.song.198000.json','["曾識徐卿二子奇，秋來往往夢瓊枝。", "明時莫作沉湘賦，暇日應題望嶽詩。", "主愛客卿寧忍舍，兄嗟予季若爲思。", "湖南歲晚多迴鴈，頻寄書歸尉別離。"]'),
('5466e98f-c282-43ee-b8ab-34ab5995875e','贈趙醫立之','劉克莊','宋','宋诗','song-poetry','','[]','世醫多孟浪，趙子獨專精。',48,'全唐诗/poet.song.198000.json','["世醫多孟浪，趙子獨專精。", "術穩常無誤，能高素有名。", "方書真爛熟，裘馬極鮮明。", "自笑貧兼病，將何贈宋清。"]'),
('5c11b0ee-9ee1-4552-af97-bfcaed27e952','與北山陳龍圖','劉克莊','宋','宋诗','song-poetry','','[]','小兒膽大說文章，螢火難爭兩曜光。',64,'全唐诗/poet.song.198000.json','["小兒膽大說文章，螢火難爭兩曜光。", "侍講先生今寂寂，龍圖老子尚堂堂。", "鄰無羊仲并求仲，家有元方與季方。", "想見瘦梅疎竹下，深衣如雪鬢鬚蒼。"]'),
('3a581e62-5997-4baa-80f4-8659eb8e97c4','答陳龍圖','劉克莊','宋','宋诗','song-poetry','','[]','耆舊凋零盡，吾猶及太丘。',48,'全唐诗/poet.song.198000.json','["耆舊凋零盡，吾猶及太丘。", "豈云清易挹，自是廣難周。", "尚絅煩翁教，書紳到老休。", "何由陪几杖，共看海山秋。"]'),
('9a2a9232-9379-498f-9838-b1b5c19bd70f','和趙吉州三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','學者當窮理，工詩豈美名。',48,'全唐诗/poet.song.198000.json','["學者當窮理，工詩豈美名。", "不能禆采訪，徒自取譏評。", "責己希韋孟，休官慕尚平。", "如今成病鶴，垂首噤無聲。"]'),
('315a64c0-9dc2-425c-8f9f-792193013324','和趙吉州三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','憔悴東陽令，區區謾自疲。',48,'全唐诗/poet.song.198000.json','["憔悴東陽令，區區謾自疲。", "斷無問牛智，寧受放魚欺。", "儉陋交游笑，低平父老知。", "向來子元子，髣髴是吾師。"]'),
('61ce98db-7ef9-47ac-af96-09847d36f67e','和趙吉州三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','今代廬陵牧，蒼生屬意深。',48,'全唐诗/poet.song.198000.json','["今代廬陵牧，蒼生屬意深。", "胸中絲補衮，肘後藥成金。", "僕自操齊瑟，公宜和舜琴。", "篝燈精舍裏，何日共論心。"]'),
('b6193e5a-d88d-4be4-a2e2-e69cf353ca52','挽傅諫議三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','昔事先皇帝，堂堂立玉墀。',48,'全唐诗/poet.song.198000.json','["昔事先皇帝，堂堂立玉墀。", "進懷伏蒲疏，退誦考槃詩。", "哀郢遺言切，憂周素髮垂。", "它年耆舊傳，此筆屬諸誰。"]'),
('b910f6d1-8d90-46d8-85ed-e6a050e2e127','挽傅諫議三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','今上龍飛始，先生驛召頻。',48,'全唐诗/poet.song.198000.json','["今上龍飛始，先生驛召頻。", "頗聞曾草疏，終不就蒲輪。", "勘破邯鄲夢，抽回洛社身。", "也令千載下，知世有全人。"]'),
('633521fb-f992-4001-8b44-68f486bcedca','挽傅諫議三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','憶昔南山寺，微言叩未終。',48,'全唐诗/poet.song.198000.json','["憶昔南山寺，微言叩未終。", "晚猶溫薦語，病尚寄書筒。", "駿廐誰收我，蟇陵合殉公。", "春風溪上淚，還與海潮東。"]'),
('813d78b2-2911-419b-86f7-52f92913404d','寄二徐','劉克莊','宋','宋诗','song-poetry','','[]','珍重渠家大小君，分明二陸是前身。',32,'全唐诗/poet.song.198000.json','["珍重渠家大小君，分明二陸是前身。", "遥知洛下傾城看，錦樣文章玉樣人。"]'),
('1b0156f5-d809-4349-b6e7-31b75074f5e1','答留通判元崇','劉克莊','宋','宋诗','song-poetry','','[]','不見龍驤與驥馳，紛紛蟲篆鬭蛛絲。',64,'全唐诗/poet.song.198000.json','["不見龍驤與驥馳，紛紛蟲篆鬭蛛絲。", "君侯傑出南方者，老僕終當北面之。", "憶玉樹枝勞遠夢，熏薔薇水讀來詩。", "自慙眼力非關令，紫氣浮空懵不知。"]'),
('42e12b19-dd2d-4e8e-adc1-0929f05fa649','以王家酒寄陳北山得二絕句誚酒味不如舊日之勁峭用韻二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','先生詩酒令俱嚴，一掃哇簧與市帘。',32,'全唐诗/poet.song.198000.json','["先生詩酒令俱嚴，一掃哇簧與市帘。", "戶大才高今吏部，故應笑小更嫌甜。"]'),
('d99939fb-0085-4e35-a473-3ab92cb87f1a','以王家酒寄陳北山得二絕句誚酒味不如舊日之勁峭用韻二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','醇醪易入醉人鄉，勁酒難逢醒者嘗。',32,'全唐诗/poet.song.198000.json','["醇醪易入醉人鄉，勁酒難逢醒者嘗。", "王媼區區真小黠，隨時增損甕中方。"]'),
('3ccb3e53-67f7-4bcd-9ab9-a4981f465d9a','和北山一首','劉克莊','宋','宋诗','song-poetry','','[]','幅巾高蹈挹洪崖，閑灑銀鉤著玉杯。',64,'全唐诗/poet.song.198000.json','["幅巾高蹈挹洪崖，閑灑銀鉤著玉杯。", "文律不論先漢後，詩源遠自國風來。", "却愁小子方攻冉，未必吾師肯鑄回。", "極欲去修床下拜，扁舟歸夢繞南臺。"]'),
('8f860952-2d39-4305-900f-f34906601683','送建安鄭尉','劉克莊','宋','宋诗','song-poetry','','[]','路人能說尉，壹似建溪清。',48,'全唐诗/poet.song.198000.json','["路人能說尉，壹似建溪清。", "寸錦不携去，束書相伴行。", "無心干舉將，有面見賢兄。", "應笑東陽令，淹留白髮生。"]'),
('542748e8-6148-4e02-b8f2-cdcf3d8c8bb5','答范叔範','劉克莊','宋','宋诗','song-poetry','','[]','闊矣別離久，颯焉顔髮蒼。',48,'全唐诗/poet.song.198000.json','["闊矣別離久，颯焉顔髮蒼。", "殷勤大范子，問訊老劉郎。", "渴睡添新懶，清談減昔狂。", "今無望氣者，寶劍且深藏。"]'),
('e43cd526-1f3c-454c-92b0-30b33ff47823','送楊休文','劉克莊','宋','宋诗','song-poetry','','[]','寂寞鰥翁揜縣齋，吏傳刺字睡驚回。',64,'全唐诗/poet.song.198000.json','["寂寞鰥翁揜縣齋，吏傳刺字睡驚回。", "自從黄鶴仙人去，誰遣青牛道士來。", "適夢羽衣良有徵，共吟石鼎愧無才。", "殷勤問訊西山老，何日山中伴訪梅。"]'),
('2dc876ee-65d6-4177-8b47-28b55f77e093','答羅天驥','劉克莊','宋','宋诗','song-poetry','','[]','乃祖曾吞鳳，郎君豈後身。',48,'全唐诗/poet.song.198000.json','["乃祖曾吞鳳，郎君豈後身。", "頗聞精選理，何必慕唐人。", "玉麈王夷甫，烏絛呂洞賓。", "客談溪墅勝，終擬卜比鄰。"]'),
('ba604fbe-0ce9-409e-8ea8-f0f4d7a9e60c','太守林太博贈瑞香花  其一','劉克莊','宋','宋诗','song-poetry','','[]','一樹婆娑整復斜，使君輟贈到田家。',64,'全唐诗/poet.song.198000.json','["一樹婆娑整復斜，使君輟贈到田家。", "自慙甕牖繩樞子，不稱香囊錦傘花。", "小借煖風爲破萼，旋澆新水待抽芽。", "丁寧童子勤封植，留與甘棠一樣誇。"]'),
('cb3c2b94-ffec-4fe1-882b-60ecadfea1fd','太守林太博贈瑞香花  其二','劉克莊','宋','宋诗','song-poetry','','[]','壞徑泥深古檻斜，居然幻作貴游家。',64,'全唐诗/poet.song.198000.json','["壞徑泥深古檻斜，居然幻作貴游家。", "小亭自課僮鉏草，空室俄驚女散花。", "便覺麝囊無遠韻，頻挑蟻蠹有新芽。", "紫薇紅藥催公去，獨許詩留野老誇。"]'),
('c39bd173-e250-4331-85ca-d4151977378e','太守林太博贈瑞香花  其三','劉克莊','宋','宋诗','song-poetry','','[]','吏散庭空戟影斜，吟牋飛到野人家。',64,'全唐诗/poet.song.198000.json','["吏散庭空戟影斜，吟牋飛到野人家。", "隋珠和璧難酬價，禪榻茶甌忒負花。", "譜欠名人爲品藻，詩因尤物始萌芽。", "近公匹似熏班馬，荀令風流未足誇。"]'),
('b8cf4f4b-6d6d-45a1-a712-f85e39ba406e','太守林太博贈瑞香花  其四','劉克莊','宋','宋诗','song-poetry','','[]','吟諷攀翻到月斜，衆驚奇寶聚貧家。',64,'全唐诗/poet.song.198000.json','["吟諷攀翻到月斜，衆驚奇寶聚貧家。", "高才盍視宮中草，退士聊看屋角花。", "未必園丁諳樹性，更愁墨客笑薑芽。", "畫堂金鼎熏蘭麝，豈有天然韻可誇。"]'),
('56ab5412-6d93-4910-9a5f-ffe0bef76707','太守林太博贈瑞香花  其五','劉克莊','宋','宋诗','song-poetry','','[]','幾點朝來小雨斜，未應造物妬山家。',64,'全唐诗/poet.song.198000.json','["幾點朝來小雨斜，未應造物妬山家。", "陡驚春報千林信，擬問天留數日花。", "寫物祇今須老筆，染根何處有靈芽。", "彩雲過眼真如夢，著意追摹豈好誇。"]'),
('c409b471-5dfd-48a5-9329-6267bed2bfdc','太守林太博贈瑞香花  其六','劉克莊','宋','宋诗','song-poetry','','[]','拙筆蕪辭字半斜，情知見笑大方家。',64,'全唐诗/poet.song.198000.json','["拙筆蕪辭字半斜，情知見笑大方家。", "放教吉甫獨哦句，除却微之誰別花。", "勾引親朋需果核，隄防風日損根芽。", "玉津應制須公等，林下樵歌敢自誇。"]'),
('db224768-f6fd-446a-a29f-46c634eee064','太守林太博贈瑞香花  其七','劉克莊','宋','宋诗','song-poetry','','[]','短牋小草墨痕斜，句法來從和靖家。',64,'全唐诗/poet.song.198000.json','["短牋小草墨痕斜，句法來從和靖家。", "吟賞豈無神助筆，護持疑有物司花。", "莫因山鳥啼榕樹，便憶河豚飽荻芽。", "多少邦人沾賸馥，願碑遺愛永傳誇。"]'),
('281d307c-3a58-4bc1-b2a0-af002ff5ac47','和趙南塘離支五絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','側生海畔遠難將，風日尤能變色漿。',32,'全唐诗/poet.song.198000.json','["側生海畔遠難將，風日尤能變色漿。", "借問驛馳丞相府，何如輦致道山堂。"]'),
('20794792-c786-42cf-9612-2c998e4fd6c5','和趙南塘離支五絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','却貢無因送上天，漫山如錦但堪憐。',32,'全唐诗/poet.song.198000.json','["却貢無因送上天，漫山如錦但堪憐。", "羅浮所産真奴隸，只爲曾逢玉局僊。"]'),
('0c1ed794-1c8d-4058-a81a-4e4ce5d5c31a','和趙南塘離支五絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','十顆千錢品最珍，北人鮐背未濡脣。',32,'全唐诗/poet.song.198000.json','["十顆千錢品最珍，北人鮐背未濡脣。", "若生京洛豪華土，買斷丹林肯算緡。"]'),
('4c308804-2d05-40c5-8bd2-683384821963','和趙南塘離支五絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','輦轂嘗新著價高，土人棄擲梗弁髦。',32,'全唐诗/poet.song.198000.json','["輦轂嘗新著價高，土人棄擲梗弁髦。", "不嗔園客工偷竊，絕喜天公享老饕。"]'),
('bb5116f8-9ab9-4221-9f2d-4707f2bfe87c','和趙南塘離支五絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','風韻能令百果低，難將盧橘鬭新奇。',32,'全唐诗/poet.song.198000.json','["風韻能令百果低，難將盧橘鬭新奇。", "品題自合還詩祖，模寫何須覓畫師。"]'),
('abffdeb9-c1f1-4ef5-959e-6b6ad89d31a2','築城行','劉克莊','宋','宋诗','song-poetry','','[]','萬夫喧喧不停杵，杵聲丁丁驚后土。',99,'全唐诗/poet.song.198000.json','["萬夫喧喧不停杵，杵聲丁丁驚后土。", "徧村開田起窯竈，望青斫木作樓櫓。", "天寒日短工役急，白棒訶責如風雨。", "漢家丞相方憂邊，築城功高除美官。", "舊時廣野無城處，而今烽火列屯戍。", "君不見高城齾齾如魚鱗，城中蕭疎空無人。"]'),
('08e352ea-c9be-49e5-b4e6-0f0945a192cc','開壕行','劉克莊','宋','宋诗','song-poetry','','[]','前人築城官已高，後人下車來開壕。',80,'全唐诗/poet.song.198000.json','["前人築城官已高，後人下車來開壕。", "畫圖先至中書省，諸公聚看稱賢勞。", "壕深數丈周十里，役兵太半化爲鬼。", "傳聞又起旁縣夫，鑿教四面皆成水。", "何時此地不爲邊，使我地脈重相連。"]'),
('ca87d6af-a706-4c99-951d-77d8f00d4c70','運糧行','劉克莊','宋','宋诗','song-poetry','','[]','極邊官軍守戰場，次邊丁壯俱運糧。',66,'全唐诗/poet.song.198000.json','["極邊官軍守戰場，次邊丁壯俱運糧。", "縣符旁午催調發，大車小車聲軋軋。", "霜寒晷短路又滑，檐夫肩穿牛蹏脫。", "嗚呼漢軍何日屯渭濱，營中子弟皆耕人。"]'),
('d80f695f-bb6a-48ff-9c15-834196641925','苦寒行','劉克莊','宋','宋诗','song-poetry','','[]','十月邊頭風色惡，官軍身上衣裘薄。',64,'全唐诗/poet.song.198000.json','["十月邊頭風色惡，官軍身上衣裘薄。", "押衣敕使來不來，夜長甲冷睡難著。", "長安城中多熱官，朱門日高未啟關。", "重重幃箔施屏山，中酒不知屏外寒。"]'),
('3c2e888f-ffcb-48cc-b556-feea9fcd7346','國殤行','劉克莊','宋','宋诗','song-poetry','','[]','官軍半夜血戰來，平明軍中收遺骸。',64,'全唐诗/poet.song.198000.json','["官軍半夜血戰來，平明軍中收遺骸。", "埋時先剝身上甲，標成叢塚高崔嵬。", "姓名虛掛陣亡籍，家寒無俸孤無澤。", "烏虖諸將官日穹，豈知萬鬼號陰風。"]'),
('12383aeb-81f5-4219-87d2-93fd4b858ab3','軍中樂','劉克莊','宋','宋诗','song-poetry','','[]','行營面面設刁斗，帳門深深萬人守。',80,'全唐诗/poet.song.198000.json','["行營面面設刁斗，帳門深深萬人守。", "將軍貴重不據鞍，夜夜發兵防隘口。", "自言虜畏不敢犯，射麋捕鹿來行酒。", "更闌酒醒山月落，綵縑百段支女樂。", "誰知營中血戰人，無錢得合金瘡藥。"]'),
('c0785c1f-5fb2-4311-9c0f-0f4e26017f98','寄衣曲','劉克莊','宋','宋诗','song-poetry','','[]','征夫去時著紵葛，征夫未回天雨雪。',80,'全唐诗/poet.song.198000.json','["征夫去時著紵葛，征夫未回天雨雪。", "夜呵刀尺製寒衣，兒小却倩人封題。", "上有淚痕不教洗，征夫見時認針指。", "殷勤著向邊城裏，莫遣寒風吹腠理。", "江南江北一水間，古人萬里戍玉關。"]'),
('78d6d03f-d96d-4451-afdb-ad450647f78a','大梁老人行','劉克莊','宋','宋诗','song-poetry','','[]','大梁宮中設氈屋，大梁少年胡結束。',66,'全唐诗/poet.song.198000.json','["大梁宮中設氈屋，大梁少年胡結束。", "少年嘻笑老人悲，尚記二帝蒙塵時。", "烏虖國君之讎通百世，無人按劍決大議。", "何當偏師縛頡利，一馿馱載送都市。"]'),
('6eb6fa44-6a38-4ff0-874f-b7a66f649711','朝陵行','劉克莊','宋','宋诗','song-poetry','','[]','國家諸陵陷河北，盜發寶衣斧陵木。',67,'全唐诗/poet.song.198000.json','["國家諸陵陷河北，盜發寶衣斧陵木。", "或言陵下往來人，夜聞翁仲草間哭。", "何年却遣朝陵官，含桃璀粲登金槃。", "悲哉，人家墳墓各有主，誰修永昌一抔土。"]'),
('0e4ab509-2a9b-4ee1-8a22-398340325d68','破陣曲','劉克莊','宋','宋诗','song-poetry','','[]','黄旗一片邊頭迴，兩河百郡送款來。',64,'全唐诗/poet.song.198000.json','["黄旗一片邊頭迴，兩河百郡送款來。", "至尊御殿受捷奏，六軍張凱聲如雷。", "元戎劍履雲臺上，麾下偏禆皆將相。", "腐儒筆力尚跌宕，燕山之銘高十丈。"]'),
('93aa384b-dc7f-4e1e-9b44-e99555163f8c','村居書事四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','有客相逢說坎離，葫蘆中藥不容窺。',32,'全唐诗/poet.song.198000.json','["有客相逢說坎離，葫蘆中藥不容窺。", "扣頭無力營丹竈，聊奉先生一醉資。"]'),
('5d5be50d-92ce-4afc-b5af-5b8d903c1dd6','村居書事四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','新剃闍梨頂尚青，滿村看說法華經。',32,'全唐诗/poet.song.198000.json','["新剃闍梨頂尚青，滿村看說法華經。", "安知世有彌天釋，萬衲如雲座下聽。"]'),
('17c86915-8fdc-4111-8fad-23fd14de8ac0','村居書事四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','卜叟囊書繫肘邊，兒童尊信等神仙。',32,'全唐诗/poet.song.198000.json','["卜叟囊書繫肘邊，兒童尊信等神仙。", "立談算盡平生事，問到封侯拜相年。"]'),
('c4ff53c3-981c-42bc-9c95-b7dc792c415d','村居書事四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','刮膜神方直萬金，國醫曾費一生心。',32,'全唐诗/poet.song.198000.json','["刮膜神方直萬金，國醫曾費一生心。", "可憐髽髻提籃者，也有盲人問點鍼。"]'),
('b378e30b-b604-40fb-acf3-77ddbb207cb5','挽陳北山二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','雖拜龍圖號，自稱槃澗翁。',48,'全唐诗/poet.song.198000.json','["雖拜龍圖號，自稱槃澗翁。", "生難招此老，死可見文公。", "斷簡功夫久，深衣笑語終。", "空餘藏藁在，虹氣貫山中。"]'),
('84b86d9f-5fb4-4c58-92d8-b0f63536ab5e','挽陳北山二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','握筆臨池慣，殘書映雪勤。',48,'全唐诗/poet.song.198000.json','["握筆臨池慣，殘書映雪勤。", "今寧無古篆，宋復有唐文。", "荒草周顒宅，空山董相墳。", "何時携斗酒，一酹墨溪雲。"]'),
('80861c63-fa3b-416b-ab48-fe6b1a3c0a3f','送五六弟赴四明倉官','劉克莊','宋','宋诗','song-poetry','','[]','子去爲倉氏，人應重客卿。',48,'全唐诗/poet.song.198000.json','["子去爲倉氏，人應重客卿。", "須憐舂簸苦，勿愛釜鍾贏。", "羊貴脾神厄，葠佳肺氣平。", "親闈最關念，頻寄鴈傳聲。"]'),
('22127d3d-9f27-431f-93cf-ae0c2012de35','挽龔汀州二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','早日曾廬墓，中年懶建牙。',48,'全唐诗/poet.song.198000.json','["早日曾廬墓，中年懶建牙。", "的無金遺子，僅有笏傳家。", "窮巷觀時事，叢祠閲歲華。", "天乎清白吏，名位止斯耶。"]'),
('5fc9b03e-28ab-4284-8b69-8399b7beae96','挽龔汀州二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','所守老尤剛，清風凜不亡。',48,'全唐诗/poet.song.198000.json','["所守老尤剛，清風凜不亡。", "洞房無粉黛，堊室屏緇黄。", "東閣遵遺令，南山獻吉藏。", "百年耆舊盡，里社轉凄凉。"]'),
('6a80d01e-bb72-460c-9e96-f7198f20e247','送戴復古謁陳延平','劉克莊','宋','宋诗','song-poetry','','[]','倉部當今第一流，艱難有詔起分憂。',64,'全唐诗/poet.song.198000.json','["倉部當今第一流，艱難有詔起分憂。", "城危如卵支群盜，膽大於身蔽上游。", "應是孔明親治事，豈無子美可參謀。", "君行必上轅門謁，爲說披簑弄釣舟。"]'),
('2a9dd4c4-1b47-4677-9fdb-fbee1b947b8d','挽外舅林明道二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','閙處功名少，閑中歲月長。',48,'全唐诗/poet.song.198000.json','["閙處功名少，閑中歲月長。", "漢曾招綺季，魯僅有靈光。", "玉雪生難涴，淵冰死未忘。", "兩州殘父老，懷惠各悲凉。"]'),
('b19b4f5e-4243-4a95-b7ca-d3ddb5ce096e','挽外舅林明道二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','少小親函丈，而今白髮生。',48,'全唐诗/poet.song.198000.json','["少小親函丈，而今白髮生。", "居然明我穢，久矣愧翁清。", "川逝悲賢淑，山頹惜老成。", "年來得瘖疾，相挽不能鳴。"]'),
('204e0e71-0d6c-4439-88d8-fb7182d58e59','柬陳寺丞築城','劉克莊','宋','宋诗','song-poetry','','[]','事變相尋智亦新，爛泥堆起石嶙峋。',64,'全唐诗/poet.song.198000.json','["事變相尋智亦新，爛泥堆起石嶙峋。", "斷無餘力謀蒸土，頗有傍觀哂寘薪。", "自古虛心容議者，即今枵腹役耕民。", "姑尤聊攝皆齊境，莫遣郊封有詛人。"]'),
('08ae5231-93dc-4b95-a9d2-12073df7a2f8','答楊𢌹','劉克莊','宋','宋诗','song-poetry','','[]','一生忠孝發於詩，不爲桃根與柳枝。',64,'全唐诗/poet.song.198000.json','["一生忠孝發於詩，不爲桃根與柳枝。", "棗本流傳容有僞，箋家穿鑿苦求奇。", "偶全要領慙輕典，虛嘔心肝悔少時。", "澤畔纍臣搔白首，孤吟不敢累親知。"]'),
('68a62cc4-a6b4-4c33-9f4b-ba3e5e8e8e35','挽方岳倅','劉克莊','宋','宋诗','song-poetry','','[]','昨解巴陵紱，將尋洛社盟。',48,'全唐诗/poet.song.198000.json','["昨解巴陵紱，將尋洛社盟。", "璧埋真可惜，玉立尚如生。", "舊轍冰天遠，新塋雪瀨清。", "惟應带來鶴，解作斷腸聲。"]'),
('fb8823cc-a3e4-4c27-a6c2-d83cc13a13f3','梅雨隳城自用前韻','劉克莊','宋','宋诗','song-poetry','','[]','疊石黏灰事尚新，忽因霑漬減嶙峋。',64,'全唐诗/poet.song.198000.json','["疊石黏灰事尚新，忽因霑漬減嶙峋。", "晉陽昔僅存三板，瓠子今誰助束薪。", "恃陋竊憂難禦寇，加工却恐倍勞民。", "狂生亦豈前知者，曾是邊城荷杵人。"]'),
('35f6b423-9e87-4b94-b8ba-f0daf3be4ba9','跋某人詩卷','劉克莊','宋','宋诗','song-poetry','','[]','元祐賦律古，熙寧經義新。',24,'全唐诗/poet.song.198000.json','["元祐賦律古，熙寧經義新。", "請君忙改藝，詩好誤終身。"]'),
('a9ea1055-344e-44ef-a4a5-698230d7e060','城壞復修又賦','劉克莊','宋','宋诗','song-poetry','','[]','補罅扶傾手段新，舉頭千丈又嶙峋。',64,'全唐诗/poet.song.198000.json','["補罅扶傾手段新，舉頭千丈又嶙峋。", "主謀何止堪尸祝，妄議真當抵鬼薪。", "見說傳更增邏卒，已聞犯夜少姦民。", "小偷不辦公輸械，遥望須驚彼有人。"]'),
('dee6a7c1-89e9-436c-abf3-773b77b6efec','留山間種藝十絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','鄙事關人智淺深，漆堪成器楮堪衾。',32,'全唐诗/poet.song.198000.json','["鄙事關人智淺深，漆堪成器楮堪衾。", "自憐到死猶迂闊，純種梅花作墓林。"]'),
('ffa1d0e2-f681-4132-a09b-8c23a13f3db6','留山間種藝十絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','羞與春華艷冶同，殷勤培溉待秋風。',32,'全唐诗/poet.song.198000.json','["羞與春華艷冶同，殷勤培溉待秋風。", "不須牽引淵明比，隨分籬邊要幾叢。"]'),
('18251351-5aca-448e-a05c-792c8ae9353f','留山間種藝十絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','一生著數落人先，白髮栽松故可憐。',32,'全唐诗/poet.song.198000.json','["一生著數落人先，白髮栽松故可憐。", "待得伏菟堪采掘，此翁久矣作飛僊。"]'),
('e5a8c196-860b-4bee-888b-900e47b84572','留山間種藝十絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','蕭艾敷榮各有時，深藏芳潔欲奚爲。',32,'全唐诗/poet.song.198000.json','["蕭艾敷榮各有時，深藏芳潔欲奚爲。", "世間鼻孔無憑據，且伴幽窗讀楚辭。"]'),
('b062706c-bffb-4da6-a111-8f90ffe46550','留山間種藝十絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','歲歲春風花覆牆，摘來紅實亦甘香。',32,'全唐诗/poet.song.198000.json','["歲歲春風花覆牆，摘來紅實亦甘香。", "當時若種瑶池本，却恐河清未得嘗。"]'),
('88b6a1b7-f442-4ee5-9f6c-28a6e89b924a','留山間種藝十絕  其六','劉克莊','宋','宋诗','song-poetry','','[]','讒言自昔架空虛，薏苡非珠偶似珠。',32,'全唐诗/poet.song.198000.json','["讒言自昔架空虛，薏苡非珠偶似珠。", "半夜庭中金屑滿，老夫明日費分疎。"]'),
('e9ae33fd-5b81-4102-a713-7c2db9c249ea','留山間種藝十絕  其七','劉克莊','宋','宋诗','song-poetry','','[]','兩樹亭亭蘚砌傍，未論包貢奉君王。',32,'全唐诗/poet.song.198000.json','["兩樹亭亭蘚砌傍，未論包貢奉君王。", "世無班馬堪薰炙，且嗅幽花亦自香。"]'),
('4adb1267-4e20-413b-bede-1e80005f783d','留山間種藝十絕  其八','劉克莊','宋','宋诗','song-poetry','','[]','春風滿面喜津津，縱有嗔拳不忍嗔。',32,'全唐诗/poet.song.198000.json','["春風滿面喜津津，縱有嗔拳不忍嗔。", "尚恐傍觀安注脚，笑他何事與何人。"]'),
('f97fd4f7-0b44-48c0-8dc1-62c113cd97d2','留山間種藝十絕  其九','劉克莊','宋','宋诗','song-poetry','','[]','一卉能令一室香，炎天尤覺玉肌凉。',32,'全唐诗/poet.song.198000.json','["一卉能令一室香，炎天尤覺玉肌凉。", "野人不敢煩天女，自折瓊枝置枕傍。"]'),
('65f10f67-6835-4635-bc55-3693003f8fa0','留山間種藝十絕  其一○','劉克莊','宋','宋诗','song-poetry','','[]','攪醉妨眠挾雨聲，碧叢宜看不宜聽。',32,'全唐诗/poet.song.198000.json','["攪醉妨眠挾雨聲，碧叢宜看不宜聽。", "而今一任蕭蕭滴，華髮鰥翁徹夜醒。"]'),
('80a3a699-cb11-4933-87f7-5d22b09f8b81','寄題邵武死事胡將祠堂','劉克莊','宋','宋诗','song-poetry','','[]','士各全軀命，惟侯視死輕。',48,'全唐诗/poet.song.198000.json','["士各全軀命，惟侯視死輕。", "張巡鬚盡怒，先軫面如生。", "短刃猶梟寇，空弮尚背城。", "新祠簫鼓盛，人敬比神明。"]'),
('17691be7-feea-463e-a8ff-cbbad3c90b22','寄題沙縣死事祝將祠堂','劉克莊','宋','宋诗','song-poetry','','[]','淮右多良將，吾猶識祝侯。',48,'全唐诗/poet.song.198000.json','["淮右多良將，吾猶識祝侯。", "虎生能肉食，豹死有皮留。", "鐵漢爲揮涕，冰翁與雪讎。", "標名忠義傳，榮甚復何求。"]'),
('3b233565-84c3-40cd-9d9c-15847821dc23','挽王簡卿侍郎三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','先帝初更化，公曾以諫聞。',48,'全唐诗/poet.song.198000.json','["先帝初更化，公曾以諫聞。", "身雖遷柱史，袖尚有彈文。", "晚境圖成佛，它山預作墳。", "那知非變幻，止在石橋雲。"]'),
('5f7f538a-b9cb-4e71-b48e-b32ae5de06d1','挽王簡卿侍郎三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','末著尤奇特，杯行忽坐亡。',48,'全唐诗/poet.song.198000.json','["末著尤奇特，杯行忽坐亡。", "無香分侍女，有硯遺諸郎。", "長樂旌旗改，平泉竹石荒。", "公今呼不應，浮議果何傷。"]'),
('414a5419-123a-4361-ba25-d2a94af5f96b','挽王簡卿侍郎三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','已矣孤知己，顔蒼鬢髮稀。',48,'全唐诗/poet.song.198000.json','["已矣孤知己，顔蒼鬢髮稀。", "雖曾參話柄，終未契禪機。", "尚欲扁舟訪，俄傳隻履歸。", "無因拜公墓，稽首懺前非。"]'),
('67bd4297-5a03-40da-b486-8ef898b0e345','題高九萬菊磵','劉克莊','宋','宋诗','song-poetry','','[]','胡公飲菊潭，八十冠貂蟬。',84,'全唐诗/poet.song.198000.json','["胡公飲菊潭，八十冠貂蟬。", "高叟飲菊磵，六十雪滿顛。", "胡公死無名，高叟生無權。", "權隨糞土盡，名與穹壤傳。", "劉生勸高叟，世事不兩全。", "饑且拾落英，渴且𣂏寒泉。", "快吟三千篇，多活五百年。"]'),
('c4cf1189-7413-4854-85e7-d5d74637033b','挽陳師復寺丞二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','已奏囊封墨尚新，又携袖疏榻前陳。',64,'全唐诗/poet.song.198000.json','["已奏囊封墨尚新，又携袖疏榻前陳。", "小臣憂國言無隠，先帝如天笑不嗔。", "闕下舉幡空太學，路傍卧轍幾遺民。", "愚儒未解天公意，偏壽它人夭此人。"]'),
('b2f07d13-c650-4a2f-a88e-934331317a73','挽陳師復寺丞二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','歲晚滄洲築草堂，却將逢掖換軒裳。',64,'全唐诗/poet.song.198000.json','["歲晚滄洲築草堂，却將逢掖換軒裳。", "市朝共歎鳳高翥，世俗或疑麟不祥。", "童子舉扶猶忼慨，門人要絰各淒涼。", "衰殘無復相鎸切，遺墨常留几案傍。"]'),
('ac3d7ef2-2cb8-4d23-8bcc-dd62f39e1fa4','別高九萬','劉克莊','宋','宋诗','song-poetry','','[]','花翁徒步悲詩境，菊磵舂糧哭復齋。',64,'全唐诗/poet.song.198000.json','["花翁徒步悲詩境，菊磵舂糧哭復齋。", "衆客食魚彈鋏去，幾人白馬素車來。", "尋思舊事成三歎，斷送諸賢入八哀。", "信矣兩生俱烈士，有金當爲築高臺。"]'),
('e6417735-447e-40db-ba8a-32052d166013','贈建陽醫士楊椿老二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','當年琴調絕平平，妄意先賢宰武城。',32,'全唐诗/poet.song.198000.json','["當年琴調絕平平，妄意先賢宰武城。", "邑有澹臺猶欠識，始知令尹未聰明。"]'),
('7b9d0c68-b61e-4aa6-8882-01156bea906a','贈建陽醫士楊椿老二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','晚愛聃書義味長，無身始與患相忘。',32,'全唐诗/poet.song.198000.json','["晚愛聃書義味長，無身始與患相忘。", "殘年頗覺饑難忍，未敢貪君不死方。"]'),
('d47b2e02-9c8b-4925-99f6-e554223c6bac','挽潘柄','劉克莊','宋','宋诗','song-poetry','','[]','復齋之客潘夫子，生死相從未忍分。',64,'全唐诗/poet.song.198000.json','["復齋之客潘夫子，生死相從未忍分。", "薛守頗曾參道潔，志完何可欠承君。", "魯生邀飲猶同去，龐嫂來呼已不聞。", "菆舍一巵真永訣，老無脚力拜翁墳。"]'),
('f0c01c7b-d33e-4dda-8bf6-d5feb472e853','贈輝書記二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','野老柴門不慣開，有僧飛錫自天台。',32,'全唐诗/poet.song.198000.json','["野老柴門不慣開，有僧飛錫自天台。", "前身莫是寒山子，携得清詩滿袖來。"]'),
('8a214f53-7953-4625-9109-8a370ef83e50','贈輝書記二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','棒喝機鋒捷似飛，推敲事業費尋思。',32,'全唐诗/poet.song.198000.json','["棒喝機鋒捷似飛，推敲事業費尋思。", "師歸定被叢林笑，腹裏無禪却有詩。"]'),
('4b8ad4ad-52b5-41ba-83a2-983dfbc059e5','答黄鏞','劉克莊','宋','宋诗','song-poetry','','[]','少年妄意假韶鳴，憂患欺人兩鬢星。',64,'全唐诗/poet.song.198000.json','["少年妄意假韶鳴，憂患欺人兩鬢星。", "此去真當盟社友，向來不合誑山靈。", "百年如夜何由旦，萬古惟天只麽青。", "若到桐城逢舊友，爲言多醉少曾醒。"]'),
('f48bbef9-d9be-4178-9362-6dfc00aa028f','答陳珽主簿','劉克莊','宋','宋诗','song-poetry','','[]','主簿佳公子，何曾染綺紈。',48,'全唐诗/poet.song.198000.json','["主簿佳公子，何曾染綺紈。", "果能磨鐵硯，真可歃銅盤。", "君壯雷驚蟄，吾衰月闕團。", "家貧無寶貝，珍貺欲酬難。"]'),
('06466e08-c9ef-483e-8d7c-c56877148967','寄題南康胡氏春風堂','劉克莊','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','芋魁菜甲必同食，石田茅屋不忍析。',160,'全唐诗/poet.song.198000.json','["芋魁菜甲必同食，石田茅屋不忍析。", "有時對床聽風雨，有時共燈窺簡冊。", "大兄獨抱古人道，群季各修弟子職。", "一門和氣常如春，紫荆花開庭草碧。", "宛然生在舞雩時，又若坐於明道側。", "吾嘗三復棠棣詩，周公千載有慙色。", "共梨分棗能幾何，摘瓜煮豆堪太息。", "區區錐刀未足讓，伯夷遜國采薇喫。", "君能聚族真卓行，余亦爲兄愧涼德。", "莫年有意觀廬山，因作春風堂上客。"]'),
('2f519edc-a6fe-4c1d-a7d4-ee08f47bef66','送孫明府','劉克莊','宋','宋诗','song-poetry','','[]','三年於赤子，摩拊極殷勤。',48,'全唐诗/poet.song.198000.json','["三年於赤子，摩拊極殷勤。", "令尹留方寸，吾民受一分。", "宛如小滕國，突過大馮君。", "四境風謠美，諸公必采聞。"]'),
('9ee75e63-8c62-469b-9f64-d6ef94db5ded','答陳璘司戶','劉克莊','宋','宋诗','song-poetry','','[]','丞相詩高妙，諸孫亦復奇。',48,'全唐诗/poet.song.198000.json','["丞相詩高妙，諸孫亦復奇。", "惠連康樂弟，子美審言兒。", "三舍猶當避，偏師未易支。", "老來怯酬唱，欲速反成遲。"]'),
('864eaa7e-876c-4861-a418-2b1aaac3ea3a','辛卯滿散天基節即事六首  其一','劉克莊','宋','宋诗','song-poetry','','[]','老作黄冠返舊山，尚支驛料破衙官。',32,'全唐诗/poet.song.198000.json','["老作黄冠返舊山，尚支驛料破衙官。", "孤臣毫髮皆君賜，獨坐風廊不覺寒。"]'),
('7eec7527-67d7-45ce-a2c7-9cdd48c50e60','辛卯滿散天基節即事六首  其二','劉克莊','宋','宋诗','song-poetry','','[]','門廡無人殿未開，白頭散吏久徘徊。',32,'全唐诗/poet.song.198000.json','["門廡無人殿未開，白頭散吏久徘徊。", "年年歲歲千秋節，長占群官第一來。"]'),
('96589df8-7867-43e3-b04d-3b14e75ee5d9','辛卯滿散天基節即事六首  其三','劉克莊','宋','宋诗','song-poetry','','[]','聞說都人競出嬉，御街簫鼓倍年時。',32,'全唐诗/poet.song.198000.json','["聞說都人競出嬉，御街簫鼓倍年時。", "相公入奏天顔喜，半夜楊州送捷旗。"]'),
('60870fff-d7d6-4b2f-9036-b90f9b2b368f','辛卯滿散天基節即事六首  其四','劉克莊','宋','宋诗','song-poetry','','[]','約己隆親禮不同，鈞天無讌錫臣工。',32,'全唐诗/poet.song.198000.json','["約己隆親禮不同，鈞天無讌錫臣工。", "太皇勳德侔高帝，陛下謙恭似孝宗。"]'),
('4160a703-86a5-45b3-be2b-819524086654','辛卯滿散天基節即事六首  其五','劉克莊','宋','宋诗','song-poetry','','[]','野衲云云祝聖躬，亦拈拂子演宗風。',32,'全唐诗/poet.song.198000.json','["野衲云云祝聖躬，亦拈拂子演宗風。", "恨渠僻陋無聞見，不識光公與杲公。"]'),
('f97051bf-fb62-46f5-9bd2-9bacc22d2601','辛卯滿散天基節即事六首  其六','劉克莊','宋','宋诗','song-poetry','','[]','小臣無狀挂丹書，還著青袍兩載餘。',32,'全唐诗/poet.song.198000.json','["小臣無狀挂丹書，還著青袍兩載餘。", "物色依然如碧鸛，階銜久矣削緋魚。"]'),
('cf98644d-52d2-4275-83c7-e8c9d66eb25b','挽王華甫提刑二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','丱角從諸老，麻衣客五侯。',48,'全唐诗/poet.song.198000.json','["丱角從諸老，麻衣客五侯。", "風雲疑反手，江海不迴頭。", "寂寂生堪笑，皇皇死未酬。", "空餘老知識，閉戶著窮愁。"]'),
('113e8510-ad05-4361-84bd-53741fd0174f','挽王華甫提刑二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','何必求佳傳，家庭論自公。',48,'全唐诗/poet.song.198000.json','["何必求佳傳，家庭論自公。", "潁濱碑玉局，曲阜狀南豐。", "轡遠方追電，箏調每值風。", "深知有遺恨，不見捷旗紅。"]'),
('de975642-795c-4209-8102-34ecfa13fc20','還黄鏞詩卷','劉克莊','宋','宋诗','song-poetry','','[]','曾伴靈芝湖上吟，當年一悟至如今。',64,'全唐诗/poet.song.198000.json','["曾伴靈芝湖上吟，當年一悟至如今。", "源流不亂知歸趣，篇什無多見苦心。", "貫虱功夫須切近，膾鯨力量要雄深。", "暮年誰可談茲事，盎有村醪且自斟。"]'),
('15f07dd4-051e-4f27-9162-7d183a06f964','徐懋功餉酒用其韻','劉克莊','宋','宋诗','song-poetry','','[]','少時酒伴盡豪雄，歲晚瓶罍一併空。',64,'全唐诗/poet.song.198000.json','["少時酒伴盡豪雄，歲晚瓶罍一併空。", "方歎獨醒吟澤畔，忽勤分餉到籬東。", "鯤鯨有量真溟涬，螟蠃無知妄異同。", "老矣此身何處著，便應埋向醉鄉中。"]'),
('ceeedb7f-d7d9-40ac-84e3-a5897cd12139','答陳琯修職','劉克莊','宋','宋诗','song-poetry','','[]','陳氏源流遠，吾猶及紀羣。',48,'全唐诗/poet.song.198000.json','["陳氏源流遠，吾猶及紀羣。", "昔惟知伯氏，今又識郎君。", "後學尊師友，先賢賤藝文。", "滄洲書冊在，努力緝前聞。"]'),
('26b93105-e088-4b30-945f-0e97f59cc3e1','挽陳孺人','劉克莊','宋','宋诗','song-poetry','','[]','昨吊空閨涕未收，忍聞紼翣向斯丘。',64,'全唐诗/poet.song.198000.json','["昨吊空閨涕未收，忍聞紼翣向斯丘。", "不爲尚子了家事，似與龐公圓話頭。", "天下斷無膠可續，人間最有劍難求。", "潘郎文筆尤宜誄，想見新碑字字愁。"]'),
('976f0be9-f6f2-4d6e-abfe-76adfab77e66','壬辰春上冢五首 城南','劉克莊','宋','宋诗','song-poetry','','[]','一閉幽堂十九年，萬松手種已參天。',64,'全唐诗/poet.song.198000.json','["一閉幽堂十九年，萬松手種已參天。", "懶隨人乞郭東祭，自與母耕綿上田。", "試問拂雲施鶴表，何如藉地薦豚肩。", "此身只合安閭里，長爲先君掃墓阡。"]'),
('96679304-23bd-4cfd-94fc-8ca831c47e95','壬辰春上冢五首 西樓','劉克莊','宋','宋诗','song-poetry','','[]','溪草林花爭碧紅，傷心黄壤閟芳容。',64,'全唐诗/poet.song.198000.json','["溪草林花爭碧紅，傷心黄壤閟芳容。", "短松明月易陳迹，斷雨殘雲難覓蹤。", "伊昔老盆常共酌，即今敗絮倩誰縫。", "臼間一斗倉陳粟，薄暮歸來獨自舂。"]'),
('526a9631-ff0d-460a-8082-a90250669978','壬辰春上冢五首 郭西','劉克莊','宋','宋诗','song-poetry','','[]','自古佳城屬吉人，郭書王讖豈能神。',64,'全唐诗/poet.song.198000.json','["自古佳城屬吉人，郭書王讖豈能神。", "掃松稍喜衣冠衆，薦芰何妨俎豆貧。", "委巷起家基世德，分山葬友等天倫。", "側傍即是黄香冢，冥漠之中尚卜鄰。"]'),
('df97a691-896d-4e91-88f4-da7ddea6011a','壬辰春上冢五首 中𡼢','劉克莊','宋','宋诗','song-poetry','','[]','憶昨隆乾致太平，諸賢聳聽鳳先鳴。',64,'全唐诗/poet.song.198000.json','["憶昨隆乾致太平，諸賢聳聽鳳先鳴。", "奏篇不愧登瀛選，拂袖難留出晝行。", "當日伯夷兄弟瘦，至今楊震子孫清。", "定知千載蟇陵路，尚有行人酹董生。"]'),
('d1e33b99-dd04-4e01-928e-732cfc39fa41','壬辰春上冢五首 壽溪','劉克莊','宋','宋诗','song-poetry','','[]','水如綬带山如抱，畫手難摹一段奇。',64,'全唐诗/poet.song.198000.json','["水如綬带山如抱，畫手難摹一段奇。", "松下可澆三奠去，墓傍安用萬家爲。", "虹來昂首寧非瑞，蛟徙無蹤若有知。", "丱角釣游今白髮，重尋陳迹不勝悲。"]'),
('b485d74e-a699-41f4-b2ba-f16b1b9cc2d8','訪李鋼草堂不遇','劉克莊','宋','宋诗','song-poetry','','[]','細路縈紆入野田，遥瞻竹樹已欣然。',64,'全唐诗/poet.song.198000.json','["細路縈紆入野田，遥瞻竹樹已欣然。", "青苔地滑跌盧老，蒼耳林深迷謫仙。", "不羨玉堂在天上，徑須茅屋占雲邊。", "極知謝客非爲亢，貪看林花聽澗泉。"]'),
('6f4dcd95-3376-4dc3-a226-166ca46b5b89','題陳遂卿隠居','劉克莊','宋','宋诗','song-poetry','','[]','蚤日稱雄翰墨林，暮年里巷且浮沉。',64,'全唐诗/poet.song.198000.json','["蚤日稱雄翰墨林，暮年里巷且浮沉。", "諸公自負遺賢媿，此士元無謗國心。", "子佩子衿輸少俊，某丘某水揀幽深。", "明時莫作逃堯計，忽有弓旌底處尋。"]'),
('4aa08c91-c2b5-4c1c-9431-7df9df95bdad','綿亭林逸人扁所居室曰藏暉求詩','劉克莊','宋','宋诗','song-poetry','','[]','先生讀易注參同，築室雲山第幾重。',64,'全唐诗/poet.song.198000.json','["先生讀易注參同，築室雲山第幾重。", "昔遇壺丘疑見怪，今於老子信猶龍。", "方靈有物司丹竈，符驗無妖血劍鋒。", "只恐欲藏藏未得，世人往往或知蹤。"]'),
('b6c87fc2-f974-4265-97c6-fe09133f86d6','題白渡方氏聽蛙亭','劉克莊','宋','宋诗','song-poetry','','[]','塘水拍隄科斗生，想君亭子俯幽清。',64,'全唐诗/poet.song.198000.json','["塘水拍隄科斗生，想君亭子俯幽清。", "黄梅雨足野田潤，牡麴煙收村墅晴。", "莫信人嫌無理閙，頗疑渠有不平鳴。", "畫堂方喜聽琴阮，誰愛天然律呂聲。"]'),
('e1dcc1f2-052f-462d-867d-f2ad6dc0403f','贈鍾主簿父子','劉克莊','宋','宋诗','song-poetry','','[]','旗鈴接跡向西馳，丹桂靈椿並一時。',64,'全唐诗/poet.song.198000.json','["旗鈴接跡向西馳，丹桂靈椿並一時。", "競說郎君能跨竈，頓令老子欲笞兒。", "妙年不患錐無穎，前輩曾言木就規。", "相國晏公元楚産，何須千里遠求師。"]'),
('6c3fc805-96f0-46f2-af6f-6596746daec8','寄趙簡叔知宗','劉克莊','宋','宋诗','song-poetry','','[]','造物方將貴此翁，煌煌三印屈盤紅。',64,'全唐诗/poet.song.198000.json','["造物方將貴此翁，煌煌三印屈盤紅。", "牋天不受珠犀涴，表海新兼鈇鉞雄。", "詩滿名山留妙墨，舶歸外國說清風。", "何當把臂登雲榭，共看鯨波浸碧空。"]'),
('43616148-ac6d-4d1c-a9d3-7d6aeb65083f','贈豫知子','劉克莊','宋','宋诗','song-poetry','','[]','隔膜能知人肺肝，瞭如燭照與龜鑽。',64,'全唐诗/poet.song.198000.json','["隔膜能知人肺肝，瞭如燭照與龜鑽。", "敏於一行推棋子，妙似堯夫測牡丹。", "道是鬼來疑太黠，驀然仙去覓應難。", "身今槁木寒灰樣，慙愧巫咸子細看。"]'),
('60bfc97d-9f99-433c-a07f-fb3cead78416','簡叔和詩再寄','劉克莊','宋','宋诗','song-poetry','','[]','棄置而今成禿翁，君恩量給太倉紅。',64,'全唐诗/poet.song.198000.json','["棄置而今成禿翁，君恩量給太倉紅。", "著鞭縱落諸公後，揮麈猶堪一世雄。", "花月三千篇絕唱，海天九萬里剛風。", "胸中本自無冰炭，况讀君詩益掃空。"]'),
('bfc088e1-df9f-4ad0-aca8-08b9ca27aa2c','寄章貢姚別駕','劉克莊','宋','宋诗','song-poetry','','[]','贛江當日血成川，誰肯身馳不測淵。',64,'全唐诗/poet.song.198000.json','["贛江當日血成川，誰肯身馳不測淵。", "尺檄約降諸峒靜，單車禽畔一城全。", "带刀俗染惟新化，橫槊詩刊第幾編。", "想與元龍談世事，亦憐疎拙老林泉。"]'),
('183ef670-05a6-453b-926b-bcdc1a89d6e9','三寄簡叔','劉克莊','宋','宋诗','song-poetry','','[]','屢有詩貽田舍翁，燈花常至夜深紅。',64,'全唐诗/poet.song.198000.json','["屢有詩貽田舍翁，燈花常至夜深紅。", "莫嫌雲榭文書冗，稍喜冰銜職任雄。", "健吏安知元結事，貪夫愧死伯夷風。", "得君厚祿吾何患，從此樽中酒不空。"]'),
('402f1eda-7ae6-4b62-bbb6-6c81ca39ae15','寄章貢姚使君','劉克莊','宋','宋诗','song-poetry','','[]','虔在江西尤鉅麗，極知君相選侯難。',64,'全唐诗/poet.song.198000.json','["虔在江西尤鉅麗，極知君相選侯難。", "昔多法從懷州紱，今少詩人上將壇。", "斂戍官兵申拆洗，放衙谿洞報平安。", "衰頹欲納轅門謁，却怕崆峒臘雪寒。"]'),
('1b7f5288-aa96-4716-a6b5-6d475ef48389','蔣邁說易','劉克莊','宋','宋诗','song-poetry','','[]','新圖別義初拈出，四座皆驚昔未聞。',64,'全唐诗/poet.song.198000.json','["新圖別義初拈出，四座皆驚昔未聞。", "定是胸中通象數，或於夢裏見羲文。", "向來夫子編三絕，近世名儒說七分。", "自笑腐生尊古注，可能挾冊便從君。"]'),
('e7fbf1b6-924a-4e76-bfc0-a1a4c5608fb5','讀金鑾密記','劉克莊','宋','宋诗','song-poetry','','[]','仗下千官走似麕，倉皇誰扈屬車塵。',64,'全唐诗/poet.song.198000.json','["仗下千官走似麕，倉皇誰扈屬車塵。", "禁中陸九艱危共，殿上朱三苦死嗔。", "當日橫身抗岐汴，暮年避地客甌閩。", "小窗細讀金鑾記，始信香奩屬別人。"]'),
('c3a7b5f8-3bb9-4573-b12b-6cf769b4e672','哭鄭君瑞長官二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','自解銅章後，終身耻折腰。',48,'全唐诗/poet.song.198000.json','["自解銅章後，終身耻折腰。", "偶然安舊隠，非不戀清朝。", "薪水纔能給，弓旌未易招。", "墳山梅似雪，猶足配清標。"]'),
('9bb1056e-9a37-4783-a80a-f1338671c81f','哭鄭君瑞長官二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','史著陶潜卒，何妨爵秩卑。',48,'全唐诗/poet.song.198000.json','["史著陶潜卒，何妨爵秩卑。", "竟無乞米帖，止有采薇詩。", "舊友誰爲誄，新阡尚欠碑。", "中年哭同志，孤立可勝悲。"]'),
('0f54472d-7987-4f43-8b7c-0b0ff27db55c','獲硯','劉克莊','宋','宋诗','song-poetry','','[]','二硯溫如玉琢成，信知天地有精英。',64,'全唐诗/poet.song.198000.json','["二硯溫如玉琢成，信知天地有精英。", "馬肝紫潤尤宜沐，鵒眼青圓宛似生。", "未愛潘郎呼作友，便教米老拜爲兄。", "今年几案多奇獲，應是窮儒命漸亨。"]'),
('accb7b56-f898-40a9-bb68-c6ec8b55bfee','再獲一硯自和','劉克莊','宋','宋诗','song-poetry','','[]','三硯聯翩買券成，絕勝玉杵聘雲英。',64,'全唐诗/poet.song.198000.json','["三硯聯翩買券成，絕勝玉杵聘雲英。", "拊摩無粟向肌起，塗抹有花從筆生。", "韞匵每愁逢暴客，傾囊或笑費方兄。", "古來事業由勤苦，不信磨穿道不亨。"]'),
('7d867946-0676-42ab-ac2c-1e0c6141670a','蔡偉叔講通書','劉克莊','宋','宋诗','song-poetry','','[]','蔣君易學高無助，蔡子重來講杏壇。',64,'全唐诗/poet.song.198000.json','["蔣君易學高無助，蔡子重來講杏壇。", "絳帳先生移席聽，青衿學士堵牆觀。", "舉揚霽月光風易，箋注先天太極難。", "穩坐虎皮揮麈尾，豈知春雨客氈寒。"]'),
('93fc1975-f4d2-41c5-9810-57bcb02e2019','遺編','劉克莊','宋','宋诗','song-poetry','','[]','短髮蕭蕭老日侵，遺編未敢廢研尋。',64,'全唐诗/poet.song.198000.json','["短髮蕭蕭老日侵，遺編未敢廢研尋。", "薰蕕理慾迷通義，衮斧忠邪害恕心。", "篤信聖賢常事左，稍知治亂每憂深。", "人生有腹當盛酒，誰遣吾儕著古今。"]'),
('8164c0a3-617e-4154-8e8f-1cddcbe3acee','一念','劉克莊','宋','宋诗','song-poetry','','[]','一念纔萌帝已臨，豈容纖芥自欺心。',64,'全唐诗/poet.song.198000.json','["一念纔萌帝已臨，豈容纖芥自欺心。", "夜猶養氣操存熟，晨偶科頭警懼深。", "跌宕少曾希管葛，歛藏晚欲學柴參。", "小窗稍覺春宵冷，自設篝鑪置楮衾。"]'),
('9c653f8a-e22e-4bd0-9765-dc8c74e22e4e','貧居自警三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','昨者匆匆擲印歸，六年岑寂閉柴扉。',64,'全唐诗/poet.song.198000.json','["昨者匆匆擲印歸，六年岑寂閉柴扉。", "歲荒奴僅拾殘穗，日晏婢方羹苦薇。", "寧渴莫賒鄰近酒，儘寒不著借來衣。", "中年但祝身强健，要卧松風坐釣磯。"]'),
('ed388fcb-0ffc-4aa6-b254-84d4665b5507','貧居自警三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','赤粟黄虀味最深，此生不恨老雲林。',64,'全唐诗/poet.song.198000.json','["赤粟黄虀味最深，此生不恨老雲林。", "鬼神每瞰高明室，天地皆知暮夜金。", "夸士燃臍猶殉貨，先賢覆首或無衾。", "一瓢千駟同歸盡，莫爲浮雲錯動心。"]'),
('a0d5cfc6-d473-48ec-812d-9949e83f83d0','貧居自警三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','客過吾廬語至晡，旋營鹽酪刈薪芻。',64,'全唐诗/poet.song.198000.json','["客過吾廬語至晡，旋營鹽酪刈薪芻。", "酒兼麟脯不時有，飯與魚羹何處無。", "力穡勿忘家世儉，堆金能使子孫愚。", "俗兒未識貧中樂，妄議書生骨相臞。"]'),
('2ea802f5-f9d1-400c-9f72-43615755e8db','寒食清明二首  其一','劉克莊','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u5bd2\u98df\u8282", "\u98ce\u4fd7"]','寂寂柴門村落裏，也教插柳記年華。',64,'全唐诗/poet.song.198000.json','["寂寂柴門村落裏，也教插柳記年華。", "禁煙不到粵人國，上冢亦携龐老家。", "漢寢唐陵無麥飯，山蹊野徑有梨花。", "一尊徑藉青苔卧，莫管城頭奏暮笳。"]'),
('5e6507aa-909e-46c7-b06e-0954d0f4dfdd','寒食清明二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','過眼年光疾彈丸，桐華半拆燕初還。',64,'全唐诗/poet.song.198000.json','["過眼年光疾彈丸，桐華半拆燕初還。", "漢宮有燭朱門煖，墨突無煙白屋寒。", "寧復鬭雞陪戲社，頗思携鶴訪孤山。", "今年秫與金同價，偶得茅柴且盡歡。"]'),
('945d1564-4f60-4362-a90e-949c82b4d9d2','上巳','劉克莊','宋','宋诗','song-poetry','','[]','櫻笋登盤節物新，一筇踏遍九州春。',64,'全唐诗/poet.song.198000.json','["櫻笋登盤節物新，一筇踏遍九州春。", "似曾山陰訪脩竹，不記水邊觀麗人。", "豪飲自憐非少日，俊遊亦恐是前身。", "暮歸尚有清狂態，亂插山花滿角巾。"]'),
('9a6d3b7b-73ef-4f93-b9b0-bf480e1c388c','村墅','劉克莊','宋','宋诗','song-poetry','','[]','村墅溪亭處處嬉，新年海岱悉清夷。',64,'全唐诗/poet.song.198000.json','["村墅溪亭處處嬉，新年海岱悉清夷。", "盜平四野無驚柝，虜去三邊有捷旗。", "子美間關離亂際，堯夫生死太平時。", "從今一洗窮愁語，多賦看花飲酒詩。"]'),
('7a0e5897-afeb-49cd-875c-d29fcd5e0b2e','進德','劉克莊','宋','宋诗','song-poetry','','[]','進德功夫有淺深，一毫間斷即差參。',64,'全唐诗/poet.song.198000.json','["進德功夫有淺深，一毫間斷即差參。", "醉無謬誤明持敬，怒亦中和見養心。", "爲善豈須朋友責，積勤常若父師臨。", "向來歲月悠悠過，垂老方知痛自箴。"]'),
('102cc22a-a3f2-4238-9055-ef8e33ca5253','答梁文杓','劉克莊','宋','宋诗','song-poetry','','[]','二梁大學同袍舊，晚識郎君亦雋才。',64,'全唐诗/poet.song.198000.json','["二梁大學同袍舊，晚識郎君亦雋才。", "柳永詞堪腔裏唱，劉叉詩自膽中來。", "老夫一榻何曾下，吾子扁舟作麽迴。", "見說桐城方調卒，未應能築禮賢臺。"]'),
('51f47d15-d45d-4891-8790-c444360a6851','哭章泉二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','自有簞瓢樂，那須璧帛迎。',48,'全唐诗/poet.song.198000.json','["自有簞瓢樂，那須璧帛迎。", "後凋仁者壽，獨往聖之清。", "古不稱千駟，今猶重兩生。", "吾衰久無淚，一慟爲耆英。"]'),
('ac047e81-cd9f-49b7-aec1-c53e535e10b1','哭章泉二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','小扉通水竹，幽絕少比鄰。',48,'全唐诗/poet.song.198000.json','["小扉通水竹，幽絕少比鄰。", "家似巢栖者，詩非火食人。", "於今無宿士，若昔有先民。", "彊作徵君誄，居然語未親。"]'),
('c39263eb-176b-45c1-bb12-d88ca85f6135','贈馬相士二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','嫗貌何妨至輔臣，猴形亦有上麒麟。',32,'全唐诗/poet.song.198000.json','["嫗貌何妨至輔臣，猴形亦有上麒麟。", "伏波眉目空如畫，不是雲臺劍佩人。"]'),
('3a67fedd-5767-4193-bd8b-d7cdf1decd58','贈馬相士二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','荀卿粗了心形者，蒯徹安知背面哉。',32,'全唐诗/poet.song.198000.json','["荀卿粗了心形者，蒯徹安知背面哉。", "別有精微書不載，待君見了季咸來。"]'),
('d796d9f6-e95f-48e9-8280-ecf9ff0c4726','余爲建陽令遣小吏王堪爲西山翁之役翁留之仙遊山房招鶴亭之上令抄道書久之若有所悟棄家不歸後六七年訪余田間敝裘跣足真爲道人矣自言欲謁翁於桐城作五詩送之  其一','劉克莊','宋','宋诗','song-poetry','','[]','向來刀筆充書佐，歲晚衣巾學道流。',32,'全唐诗/poet.song.198000.json','["向來刀筆充書佐，歲晚衣巾學道流。", "畢竟賢於人一著，醉中夢裏忽迴頭。"]'),
('b84b962a-5961-4178-bf97-4f475108a529','余爲建陽令遣小吏王堪爲西山翁之役翁留之仙遊山房招鶴亭之上令抄道書久之若有所悟棄家不歸後六七年訪余田間敝裘跣足真爲道人矣自言欲謁翁於桐城作五詩送之  其二','劉克莊','宋','宋诗','song-poetry','','[]','拂袖歸來久閉關，道人剝啄訪平安。',32,'全唐诗/poet.song.198000.json','["拂袖歸來久閉關，道人剝啄訪平安。", "要知對面劉高尚，即是翻身靖長官。"]'),
('9b011c5d-8368-4487-aef9-1b6358528ef5','余爲建陽令遣小吏王堪爲西山翁之役翁留之仙遊山房招鶴亭之上令抄道書久之若有所悟棄家不歸後六七年訪余田間敝裘跣足真爲道人矣自言欲謁翁於桐城作五詩送之  其三','劉克莊','宋','宋诗','song-poetry','','[]','去去尋師莫遠尋，蓬萊何處海深深。',32,'全唐诗/poet.song.198000.json','["去去尋師莫遠尋，蓬萊何處海深深。", "山房幸有栖身地，且讀西山夜氣箴。"]'),
('f6e76c03-db31-45b8-8c15-1b32a7633173','余爲建陽令遣小吏王堪爲西山翁之役翁留之仙遊山房招鶴亭之上令抄道書久之若有所悟棄家不歸後六七年訪余田間敝裘跣足真爲道人矣自言欲謁翁於桐城作五詩送之  其四','劉克莊','宋','宋诗','song-poetry','','[]','聞說周僊有後身，出山不爲兩朱輪。',32,'全唐诗/poet.song.198000.json','["聞說周僊有後身，出山不爲兩朱輪。", "白雲丹竈俱無恙，憑汝殷勤謝主人。"]'),
('96c47920-048b-4974-969e-e9951e44020e','余爲建陽令遣小吏王堪爲西山翁之役翁留之仙遊山房招鶴亭之上令抄道書久之若有所悟棄家不歸後六七年訪余田間敝裘跣足真爲道人矣自言欲謁翁於桐城作五詩送之  其五','劉克莊','宋','宋诗','song-poetry','','[]','或盤碧漢唳清宵，幾載山中伴寂寥。',32,'全唐诗/poet.song.198000.json','["或盤碧漢唳清宵，幾載山中伴寂寥。", "今日鶴來翁已出，他年却恐費翁招。"]'),
('672f4fdb-4d71-49a9-bfa7-e88518838a8d','和南塘食荔歎','劉克莊','宋','宋诗','song-poetry','','[]','君欲和詩無匆匆，唱首天下文章公。',240,'全唐诗/poet.song.198000.json','["君欲和詩無匆匆，唱首天下文章公。", "今年荔子况倍熟，亭亭錦蓋高張空。", "猿偷鴉啄牧童采，林間殘顆猶殷紅。", "在昔唐家充歲貢，吟諷何止杜陵翁。", "南窮交州西蜀土，快馬馱送如飛龍。", "絳裳冰肌初照眼，玉環一笑恩光濃。", "惟閩以遠幸免涴，一顆不到溫泉宮。", "自從陳紫無真本，皺玉晚出尤稱雄。", "邇來雞舌擅瑰瑋，贊香譽味萬喙同。", "麟臺仙人親題品，天爲此果開遭逢。", "乃知微物似有數，聲價亦與時汙隆。", "列聖儉德被華戎，微如淮白不敢供。", "奈何置驛奉私室，安得木鐸觀民風。", "山蹊谷塹日力窮，血肩踠足馳筠籠。", "請公移此食荔歎，置在薰風殿閣中。"]'),
('95bd75aa-f377-45ac-8582-2dcdfe21ea0d','送真西山再鎮溫陵','劉克莊','宋','宋诗','song-poetry','','[]','父老香花夾路催，朱幡那忍更徘徊。',64,'全唐诗/poet.song.198000.json','["父老香花夾路催，朱幡那忍更徘徊。", "弓張至此尤宜弛，珠去安知不復迴。", "海上有艘堪致粟，洛中無篚勝生財。", "泉人畢竟修何福，消得西山兩度來。"]'),
('ec52ea58-cc04-412f-b742-a92642afbc25','水仙花','劉克莊','宋','宋诗','song-poetry','','[]','歲華摇落物蕭然，一種清芬絕可憐。',64,'全唐诗/poet.song.198000.json','["歲華摇落物蕭然，一種清芬絕可憐。", "不許淤泥侵皓素，全憑風露發幽妍。", "騷魂灑落沉湘客，玉色依稀捉月僊。", "却笑涪翁太脂粉，誤將高雅匹嬋娟。"]'),
('1a8ae700-fb03-4131-98b9-9fafbf89ac25','葵花二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','植物雖微性有常，人心翻覆至難量。',32,'全唐诗/poet.song.198000.json','["植物雖微性有常，人心翻覆至難量。", "李陵衛律陰山死，不似葵花識太陽。"]'),
('a298c0e7-21e8-400a-b0d9-6f88016e4f4a','葵花二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','下了江南奏凱迴，曹公鞅鞅未忘懷。',32,'全唐诗/poet.song.198000.json','["下了江南奏凱迴，曹公鞅鞅未忘懷。", "爭知野老門庭冷，旌節無心忽自來。"]'),
('9a96eaa7-17c8-40ac-a699-96419f411a08','題鄭寧文卷','劉克莊','宋','宋诗','song-poetry','','[]','昔侍西山講習時，頗於函丈得精微。',64,'全唐诗/poet.song.198000.json','["昔侍西山講習時，頗於函丈得精微。", "書如逐客猶遭絀，辭取橫汾亦恐非。", "箏笛豈能諧雅樂，綺紈元未識深衣。", "嗟余老矣君方少，勤向師門扣指歸。"]'),
('8d049eed-82e1-4e52-9df4-3a5c76a49994','悼阿駒七首  其一','劉克莊','宋','宋诗','song-poetry','','[]','吾老方期汝亢宗，愛憐不與衆雛同。',32,'全唐诗/poet.song.198000.json','["吾老方期汝亢宗，愛憐不與衆雛同。", "豈知希世千金産，止作空花賺廼翁。"]'),
('1e1d354c-40d7-4542-a039-c64c4abf6878','悼阿駒七首  其二','劉克莊','宋','宋诗','song-poetry','','[]','長兄開卷每隨聲，大母繙經亦諦聽。',32,'全唐诗/poet.song.198000.json','["長兄開卷每隨聲，大母繙經亦諦聽。", "眉目分明無夭法，恐緣了了與惺惺。"]'),
('72a585b3-363e-427f-b5ed-e540b886022f','悼阿駒七首  其三','劉克莊','宋','宋诗','song-poetry','','[]','北轍南轅有返期，吾兒掣手去何之。',32,'全唐诗/poet.song.198000.json','["北轍南轅有返期，吾兒掣手去何之。", "夢中玉雪來懷抱，愁絕鄰鐘喚醒時。"]'),
('803f9f3d-edfe-4a6a-ade0-0c9d69d27b76','悼阿駒七首  其四','劉克莊','宋','宋诗','song-poetry','','[]','隔日猶能喚女兄，兒於孝友殆天成。',32,'全唐诗/poet.song.198000.json','["隔日猶能喚女兄，兒於孝友殆天成。", "直須見汝蓮花上，纔得胸中一點平。"]'),
('1aaf1aa3-7178-48a9-b01a-605453d5efa7','悼阿駒七首  其五','劉克莊','宋','宋诗','song-poetry','','[]','富貴威權得自由，收融二子殺楊脩。',32,'全唐诗/poet.song.198000.json','["富貴威權得自由，收融二子殺楊脩。", "閑人於物無恩怨，那得倉舒只麽休。"]'),
('75303f68-3587-4c7a-9120-431304f3dbb3','悼阿駒七首  其六','劉克莊','宋','宋诗','song-poetry','','[]','眼有玄花因悼亡，觀書對客兩茫洋。',32,'全唐诗/poet.song.198000.json','["眼有玄花因悼亡，觀書對客兩茫洋。", "情知淚是衰翁血，更爲童烏滴數行。"]'),
('c3e13350-50b6-46b5-9734-e8c45a1896bb','悼阿駒七首  其七','劉克莊','宋','宋诗','song-poetry','','[]','人生憂患本無涯，强取瞿聃語自排。',32,'全唐诗/poet.song.198000.json','["人生憂患本無涯，强取瞿聃語自排。", "吾母白頭尤念我，吞聲不敢惱慈懷。"]'),
('e0e9f682-aa7c-4011-b792-d18cefaada92','鄭寧示邊報走筆戲贈','劉克莊','宋','宋诗','song-poetry','','[]','曾客嫖姚與伏波，慣騎生馬擁琱戈。',64,'全唐诗/poet.song.198000.json','["曾客嫖姚與伏波，慣騎生馬擁琱戈。", "金臺有命終須築，鐵硯無功亦且磨。", "見說帛書來汝洛，又傳氈帳迫淮河。", "只今西北多機會，吾子南歸意若何。"]'),
('142916ff-b940-4eb3-be11-380c98fe53b2','挽劉學諭','劉克莊','宋','宋诗','song-poetry','','[]','少游鄉校至華顛，常以虀鹽養浩然。',64,'全唐诗/poet.song.198000.json','["少游鄉校至華顛，常以虀鹽養浩然。", "科舉法行無譽士，丘園禮廢有遺賢。", "劉賁下第人稱屈，李漢編文後必傳。", "聞道諸郎皆秀孝，拂雲華表看它年。"]'),
('772088a6-fa1c-43b4-8150-320aee7d1ed9','送陳戶曹之官襄陽二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','丞相曾參督府謀，郎君今復贊邊籌。',64,'全唐诗/poet.song.198000.json','["丞相曾參督府謀，郎君今復贊邊籌。", "彼哉金谷飲長夜，去矣玉關防盛秋。", "尺度豈能拘快士，功名斷不在中州。", "習池水滿堤花艷，安得相陪賦遠遊。"]'),
('749fe528-50d3-41e0-bb3b-0278c430c8a7','送陳戶曹之官襄陽二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','幕府秋風事日生，參軍匹馬去兼程。',64,'全唐诗/poet.song.198000.json','["幕府秋風事日生，參軍匹馬去兼程。", "起爲楚舞何其壯，吟退胡兵在此行。", "且喜峴山碑有跋，不愁江表傳無名。", "老儒那復封侯夢，止願躬耕看太平。"]'),
('8a085a61-cfc0-42c3-a4b6-1d478c2bdc61','旴士張季携所注三略訪西山先生既跋其書余復題二絕於卷尾  其一','劉克莊','宋','宋诗','song-poetry','','[]','張生快士非拘儒，袖出一編相斫書。',32,'全唐诗/poet.song.198000.json','["張生快士非拘儒，袖出一編相斫書。", "撲虱拍蚊吾不忍，斷蛇刺虎子何麤。"]'),
('725e32d2-8fc4-4b9b-b075-00edd8144dd4','旴士張季携所注三略訪西山先生既跋其書余復題二絕於卷尾  其二','劉克莊','宋','宋诗','song-poetry','','[]','千里從師細講評，橫渠昔亦謁高平。',32,'全唐诗/poet.song.198000.json','["千里從師細講評，橫渠昔亦謁高平。", "自從受得中庸了，止說西銘不說兵。"]'),
('f14bba58-6a49-4094-ad8d-f09e7a09601f','送湯伯紀歸番昜','劉克莊','宋','宋诗','song-poetry','','[]','華宗所産必人英，久見諸賢說父兄。',64,'全唐诗/poet.song.198000.json','["華宗所産必人英，久見諸賢說父兄。", "荀氏晚添文若出，楊家又有敬之生。", "進堪負荷斯文責，退亦流傳後世名。", "身老荒村無可恨，獨於佳友尚關情。"]'),
('1de4f3ae-f705-4958-b26e-cf62b9c19ebb','病後訪梅九絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','夢得因桃數左遷，長源爲柳忤當權。',32,'全唐诗/poet.song.198000.json','["夢得因桃數左遷，長源爲柳忤當權。", "幸然不識桃并柳，却被梅花累十年。"]'),
('7bb959b7-b656-43c7-9264-8f388cba4775','病後訪梅九絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','先生歲晚被人疑，梅畔渾無一字詩。',32,'全唐诗/poet.song.198000.json','["先生歲晚被人疑，梅畔渾無一字詩。", "明月清風愁併案，野花啼鳥怕隨司。"]'),
('39b28826-8456-4c76-ba20-03aeb4774e6f','病後訪梅九絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','區區毛鄭號精專，未必風人意果然。',32,'全唐诗/poet.song.198000.json','["區區毛鄭號精專，未必風人意果然。", "犬彘不吞舒亶唾，豈堪與世作詩箋。"]'),
('e388b1f1-eb94-4ae0-9644-fb178e034ae4','病後訪梅九絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','和靖林間欬嗽時，一邊覓句一邊饑。',32,'全唐诗/poet.song.198000.json','["和靖林間欬嗽時，一邊覓句一邊饑。", "而今始會天公意，不惜功名只惜詩。"]'),
('0ee02ddc-e574-4f27-93ae-cba5825cd669','病後訪梅九絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','老子無糧可禦冬，强鳴饑吻和寒蛩。',32,'全唐诗/poet.song.198000.json','["老子無糧可禦冬，强鳴饑吻和寒蛩。", "舍南舍北花如雪，止嚥清香飽殺儂。"]'),
('5f43782b-f915-4f4b-8918-c0ee06fb9494','病後訪梅九絕  其六','劉克莊','宋','宋诗','song-poetry','','[]','與梅交絕幾星霜，瞥見南枝喜欲狂。',32,'全唐诗/poet.song.198000.json','["與梅交絕幾星霜，瞥見南枝喜欲狂。", "便欲佩壺携鐵笛，爲花痛飲百千場。"]'),
('8f890a16-8256-49b2-98d1-dbf3f557281f','病後訪梅九絕  其七','劉克莊','宋','宋诗','song-poetry','','[]','一聯半首致魁台，前有沂公後簡齋。',32,'全唐诗/poet.song.198000.json','["一聯半首致魁台，前有沂公後簡齋。", "自是君詩無警策，梅花窮殺幾人來。"]'),
('c046f210-3181-49e3-b032-e233bfadbe77','病後訪梅九絕  其八','劉克莊','宋','宋诗','song-poetry','','[]','春信分明到草廬，呼兒沽酒買溪魚。',32,'全唐诗/poet.song.198000.json','["春信分明到草廬，呼兒沽酒買溪魚。", "從前弄月嘲風罪，即日金雞已赦除。"]'),
('fabbbd92-c0ac-42ae-a640-73cba4692c61','病後訪梅九絕  其九','劉克莊','宋','宋诗','song-poetry','','[]','菊得陶翁名愈重，蓮因周子品尤尊。',32,'全唐诗/poet.song.198000.json','["菊得陶翁名愈重，蓮因周子品尤尊。", "後來誰判梅公案，斷自孤山迄後村。"]'),
('5963d225-dc30-4103-9c33-3b57327006c6','陪西山遊鼓山一首','劉克莊','宋','宋诗','song-poetry','','[]','先生廊廟姿，非直藩翰才。',144,'全唐诗/poet.song.198000.json','["先生廊廟姿，非直藩翰才。", "南州彩旗留，北闕丹詔催。", "重臣方暑行，停驂小裴回。", "客中載枚鄒，物外尋宗雷。", "遂窮天海觀，一豁風雲懷。", "眷言此靈山，自判宇宙來。", "登臨幾朱輪，滅沒隨飛埃。", "堂堂蔡與趙，繼者其誰哉。", "共惟勳業侔，况乃名節偕。", "伊余忝載筆，適值祖帳開。", "雖陪叔子游，獨抱湛輩哀。", "餞詩堪覆瓿，不敢鎸蒼崖。"]'),
('ea52ad54-8d2a-4499-b08e-d81fd68ee46f','鼓山用餘干趙相韻','劉克莊','宋','宋诗','song-poetry','','[]','城郭區區一聚埃，江山如此信佳哉。',64,'全唐诗/poet.song.198000.json','["城郭區區一聚埃，江山如此信佳哉。", "挾龍相國騎箕去，招鶴仙人弭節來。", "試問炊粱成短夢，何如煨芋撥殘灰。", "危亭更著文公扁，日落山空未忍回。"]'),
('72e539d1-59fa-4263-b810-8c5f3f7678c3','題真仁夫畫卷','劉克莊','宋','宋诗','song-poetry','','[]','草木黄落，水雲莽蒼。',70,'全唐诗/poet.song.198000.json','["草木黄落，水雲莽蒼。", "孤舟卸帆，凍鴈失行。", "昔余遠遊，沿灕泝湘。", "堠長店疎，僕痡馬僵。", "行李蕭然，有詩滿囊。", "今其老矣，寧志四方。", "撫卷追思，歷歷不忘。"]'),
('f311cdb3-0789-44d0-b6ca-f9b24e24c344','題龍眠十八尊者','劉克莊','宋','宋诗','song-poetry','','[]','嘗聞天台境，肉身往無從。',264,'全唐诗/poet.song.198000.json','["嘗聞天台境，肉身往無從。", "仁夫示此圖，恍惚游其中。", "應真一一若舊識，或踞怪石臨飛淙。", "山鬼投牒何敬恭，天女問法尤丰茸。", "盆魚鬐鬛等針粟，放去夭矯拏空濛。", "山深無人地祇出，被服導從侔王公。", "前驅鷙獸後夔魍，徐行殿以一瘦筇。", "巉巉蒼壁謖謖松，下有老宿眉雪濃。", "石橋滅沒雲氣斷，似是鬼國非天宮。", "層冰融結挾怒瀑，毒虺噴薄含腥風。", "至人於此方入定，壞衲羃首枯株同。", "等閑一坐六十劫，汝技有盡吾無窮。", "書生往往談性命，怵以禍福猶兒童。", "倒持手版口勸進，對此寧不面發紅。", "我知龍眠筆外意，要與濁世鍼盲聾。", "退之云釋善變幻，愷之謂畫能神通。", "幻耶神耶兩莫詰，與子持叩西山翁。"]'),
('ecae36f2-c629-4756-afd5-0f2536498881','米元章有帖云老弟山林集多於眉陽集然不襲古人一句子瞻南還與之說茫然歎久之似歎渠偷也戲跋二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','大令云亡筆不傳，世無行草已千年。',32,'全唐诗/poet.song.198000.json','["大令云亡筆不傳，世無行草已千年。", "偶然遺下鵝群帖，生出楊風與米顛。"]'),
('8b3fba74-6a0b-4d6a-9a01-ecef58f2daea','米元章有帖云老弟山林集多於眉陽集然不襲古人一句子瞻南還與之說茫然歎久之似歎渠偷也戲跋二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','二集一傳一不傳，可能寶晉勝坡仙。',32,'全唐诗/poet.song.198000.json','["二集一傳一不傳，可能寶晉勝坡仙。", "蘇郎不醉常如醉，米老真顛却辨顛。"]'),
('490808af-0645-4f8a-9ad1-c0d6e77894fa','跋周忘機畫一首','劉克莊','宋','宋诗','song-poetry','','[]','周郎詞藝妙天下，似是詩家非畫家。',32,'全唐诗/poet.song.198000.json','["周郎詞藝妙天下，似是詩家非畫家。", "寧與嵇公寫琴操，不爲盛尹作梅花。"]'),
('2dd344c7-372e-4a6c-9791-609d82e562d9','題林戶曹寒齋','劉克莊','宋','宋诗','song-poetry','','[]','舉世爭馳勢利場，君於冷處看人忙。',64,'全唐诗/poet.song.198000.json','["舉世爭馳勢利場，君於冷處看人忙。", "不營摩詰散花室，只設蘇州聽雨床。", "種果園林無虎守，勘書窗几有螢光。", "直須喚起西塘老，來向齋中伴石塘。"]'),
('4de2547e-a53a-4f09-b128-151c5d358259','呈黄建州','劉克莊','宋','宋诗','song-poetry','','[]','當年虎穴挺身臨，匹馬平欺萬綠林。',64,'全唐诗/poet.song.198000.json','["當年虎穴挺身臨，匹馬平欺萬綠林。", "余欲關弓常掩涕，汝能賣劍即回心。", "歌廉民已嗟來暮，微管吾安得至今。", "欲謁鈴齋參嫡派，管蠡何敢測高深。"]'),
('7c89230f-0d0b-43bc-8277-92167a1eaabe','過建陽二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','溪上重來兩鬢絲，豈知拙政久猶思。',64,'全唐诗/poet.song.198000.json','["溪上重來兩鬢絲，豈知拙政久猶思。", "旄倪欲見葉公面，香火共存朱邑祠。", "爭勸令君持酒琖，不容老子閉車帷。", "誰言俗薄今非古，我與斯民各秉彜。"]'),
('7a601272-772e-4f6e-a6ee-27072438a36f','過建陽二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','白布裙襦雪滿顛，携扶傴僂拜車前。',64,'全唐诗/poet.song.198000.json','["白布裙襦雪滿顛，携扶傴僂拜車前。", "皆言庾氏相因粟，猶是君侯不飲泉。", "自昔活民須有備，即今去客愧無權。", "愚公老矣癡如故，長把心燈望後賢。"]'),
('9b835527-4a1d-4c3e-9dbe-8b9f2f68eb52','過章戴二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','魯叟新阡何處尋，橋邊感舊獨沉吟。',64,'全唐诗/poet.song.198000.json','["魯叟新阡何處尋，橋邊感舊獨沉吟。", "一生欲唾姦諛面，千古難磨道義心。", "溪昔放魚晴鱍鱍，門今羅爵冷涔涔。", "發潜頼有西山筆，何日碑成勒碧岑。"]'),
('1a1805fb-b88b-43d3-b906-068bdd9adb62','過章戴二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','曾向明時雪李邕，又聞名在聘賢中。',64,'全唐诗/poet.song.198000.json','["曾向明時雪李邕，又聞名在聘賢中。", "憶言鴟吻施茅屋，忍見龜趺立柏宮。", "杯酒昔常陪賀老，隻雞終待哭喬公。", "情知客淚先難制，鄰笛那堪咽晚風。"]'),
('1e97439e-55ef-4a5a-bf59-24460c00306c','答李泉州元善','劉克莊','宋','宋诗','song-poetry','','[]','平生陳無己，白首欠吟債。',108,'全唐诗/poet.song.198000.json','["平生陳無己，白首欠吟債。", "未嘗交馬呂，况肯見章蔡。", "附熱生可鄙，中寒死亦快。", "吾方尚此友，巾車與同載。", "前瞻有膺滂，却顧有融泰。", "要當堅一壁，詎可立兩界。", "恕乎行誼虧，希也名節壞。", "史君惠良箴，下走敢不拜。", "懷哉道義交，異彼姑息愛。"]'),
('04f836bb-83e7-4dcb-bf64-7592398359d1','送趙信州二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','君於朝列號名流，信在江東亦望州。',64,'全唐诗/poet.song.198000.json','["君於朝列號名流，信在江東亦望州。", "保抱彼民思父母，齎咨吾輩惜交游。", "香凝應物吟詩榻，虹貫元章載畫舟。", "澗上泉邊今寂寞，豈無遺藁待搜求。"]'),
('c2425778-db17-474e-8486-438b12b0a752','送趙信州二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','貧者惟言可贈行，臨分握手盡交情。',64,'全唐诗/poet.song.198000.json','["貧者惟言可贈行，臨分握手盡交情。", "馬於轡力窮時駭，鷗向機心動處驚。", "齊士豈無堪客禮，蔡人便遣作牙兵。", "遥知陌上羅敷女，競看雙旌出勸耕。"]'),
('594039a4-c05c-449f-8454-2dc7eb4b2c05','題趙子固詩卷','劉克莊','宋','宋诗','song-poetry','','[]','紫芝仲白俱仙去，晚秀惟君擅士林。',64,'全唐诗/poet.song.198000.json','["紫芝仲白俱仙去，晚秀惟君擅士林。", "字肖率更親手作，詩疑賈島後身吟。", "九成合奏音方備，三染爲纁色始深。", "老去尤於朋友篤，未忘几研琢磨心。"]'),
('64cfe8b6-083d-4341-9cc1-55b4f0f45cfc','題湯伯紀程文','劉克莊','宋','宋诗','song-poetry','','[]','詔書選後宮，衆女競媒致。',84,'全唐诗/poet.song.198000.json','["詔書選後宮，衆女競媒致。", "拂鏡濃畫眉，臨風高綰髻。", "朝猶東鄰居，夕已金屋貴。", "彼姝絕代姿，綽約乘雲氣。", "箴史合古趣，佩服與今異。", "宜哉寤寐求，惜也憔悴棄。", "君門深復深，歲遣花鳥使。"]'),
('eced1c2a-4cd9-421c-b6b8-33db5f9bf85a','和高九萬雪詩','劉克莊','宋','宋诗','song-poetry','','[]','添盡綿衣體未和，小窗奈此苦寒何。',64,'全唐诗/poet.song.198000.json','["添盡綿衣體未和，小窗奈此苦寒何。", "極知上竺僊人喜，不道長安貧士多。", "窮巷都無晨噪鵲，邊城應有夜驚鵝。", "君才堪續梁臺賦，早晚樓船濟汴河。"]'),
('7c95c0e6-59d4-4a34-8399-9ea44aa0af5c','答曾無疑校勘','劉克莊','宋','宋诗','song-poetry','','[]','詩到黄初字永和，半生西望遡明河。',64,'全唐诗/poet.song.198000.json','["詩到黄初字永和，半生西望遡明河。", "已招學士來儒館，更欠山人拜諫坡。", "四庫舊書存有幾，五朝遺老苦無多。", "傳聞將講臨雍禮，小駐驪駒白玉珂。"]'),
('8cf7fed2-6c26-41df-a175-a8034adfd699','題袁祕書文藁','劉克莊','宋','宋诗','song-poetry','','[]','場屋聲名淳紹初，同時一輩曉星疎。',64,'全唐诗/poet.song.198000.json','["場屋聲名淳紹初，同時一輩曉星疎。", "舉人尚記前鄉貢，天子亦呼行祕書。", "出蜀詩堪編杜集，涉湘文可補騷餘。", "中朝典冊須鴻筆，何必然藜照蠹魚。"]'),
('5d475398-a421-451f-a6de-e0f7d9c201f3','題廬陵羅生詩卷','劉克莊','宋','宋诗','song-poetry','','[]','門巷蕭然人迹少，華裾客子袖文過。',64,'全唐诗/poet.song.198000.json','["門巷蕭然人迹少，華裾客子袖文過。", "織千機錦非常巧，熏一銖香已覺多。", "持贈白雲情厚矣，暗投明月愧如何。", "桃花水煖鱸堪鱠，恨不相携買短蓑。"]'),
('d4b1b6a0-c78d-4247-9e13-73be72243ea9','陳夫人哀詩','劉克莊','宋','宋诗','song-poetry','','[]','龍川天下士，女子節尤奇。',48,'全唐诗/poet.song.198000.json','["龍川天下士，女子節尤奇。", "孟母遷鄰訓，共姜誓己詩。", "生無封國分，歿有表阡時。", "曾識雙珠樹，聊爲補些辭。"]'),
('284e3194-2498-426c-acba-2999a7839943','挽連夫人','劉克莊','宋','宋诗','song-poetry','','[]','渡江門戶已華簪，嫁得黔婁作藁砧。',64,'全唐诗/poet.song.198000.json','["渡江門戶已華簪，嫁得黔婁作藁砧。", "疇昔曾爲賓截髮，暮年親見子腰金。", "瀧阡新刻豐碑妙，防墓重封宿草深。", "憶與夏卿聯禁路，些辭題罷一酸心。"]'),
('c12f4206-f75d-4fa1-a5df-ab862e6f35e2','參預陳公挽詩二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','人歎摛毫妙，天知補衮忠。',48,'全唐诗/poet.song.198000.json','["人歎摛毫妙，天知補衮忠。", "力猶挽元氣，身已御長風。", "家譜侔洪氏，官稱似范公。", "獨憐蓴鯽奠，不得至苕中。"]'),
('8425396e-55b9-4b58-a2d9-a5543b776e27','參預陳公挽詩二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','聖主初調瑟，煩公數寄聲。',48,'全唐诗/poet.song.198000.json','["聖主初調瑟，煩公數寄聲。", "已來周大老，尚致魯諸生。", "末至餘尊盡，西歸隻履輕。", "中年知己淚，銷得幾回傾。"]'),
('a307df1c-c0fb-42ba-a6b4-930f3d058d54','又二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','世道方憑藉，云胡不憗遺。',48,'全唐诗/poet.song.198000.json','["世道方憑藉，云胡不憗遺。", "重如鎮喬嶽，寬可納須彌。", "鴟閣開無日，蟇陵窆有期。", "嗟余衰久矣，告第乏雄辭。"]'),
('1d82ca86-5bc1-48c7-a1ec-20938db8c5e9','又二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','不謂斯人夭，堂堂在目中。',48,'全唐诗/poet.song.198000.json','["不謂斯人夭，堂堂在目中。", "曾參黄面老，肯戀黑頭公。", "性理天淵徹，榮華露電空。", "獨餘章奏在，聖主記遺忠。"]'),
('d071559e-807f-467a-8612-3dd73289c0cb','送王實之','劉克莊','宋','宋诗','song-poetry','','[]','欲去還留每自憐，竟爲吾子著先鞭。',64,'全唐诗/poet.song.198000.json','["欲去還留每自憐，竟爲吾子著先鞭。", "孤忠盡見萬言疏，十口同登一葉船。", "屈法相全煩聖主，上書俱貶愧前賢。", "南歸定過西山下，細把行藏告墓阡。"]'),
('cb8a7c97-8f70-4df3-a16b-34e71ebff7ee','重餞趙信州分韻得寢字','劉克莊','宋','宋诗','song-poetry','','[]','近甸騷屑餘，當宁焦勞甚。',144,'全唐诗/poet.song.198000.json','["近甸騷屑餘，當宁焦勞甚。", "剖符寄非輕，弄印擇已審。", "盎然春風和，解此寒色凜。", "吾聞守四隣，豈必衛堂寢。", "惡馬易調伏，小鮮難烹飪。", "臘前況屢白，秋杪定一稔。", "我侯但凝香，彼州自奠枕。", "英英尚書郎，餞詩麗如錦。", "驪珠忽滿軸，繼者皆曹沈。", "顧予如病鶴，欲鳴聲復噤。", "寧論鬼揶揄，行以親來諗。", "南歸掣齋鈴，儻留故人飲。"]'),
('0ceb8718-6a10-4f95-bf91-bc6b37378d4e','鄭丞相生日口號十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','陌上塵飛敕使來，親傳天語賀元台。',32,'全唐诗/poet.song.198000.json','["陌上塵飛敕使來，親傳天語賀元台。", "門庭如水無珍獻，惟有黄華伴壽杯。"]'),
('7c484317-5e2a-46c4-85cc-e531cf8b5f8a','鄭丞相生日口號十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','王呂紛更尚治安，史韓椓杙始凋殘。',32,'全唐诗/poet.song.198000.json','["王呂紛更尚治安，史韓椓杙始凋殘。", "廼知元祐調絃易，却是端平變局難。"]'),
('3d29a598-dd56-4c27-bed4-ca010a95b0b8','鄭丞相生日口號十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','金塢銅山二紀中，可無玉雪洗貪風。',32,'全唐诗/poet.song.198000.json','["金塢銅山二紀中，可無玉雪洗貪風。", "從今中外多廉吏，家有錢神賦一通。"]'),
('e0549b48-acdc-40c6-99db-9332371e28ea','鄭丞相生日口號十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','小范登庸面稍腴，惟公不以位爲娛。',32,'全唐诗/poet.song.198000.json','["小范登庸面稍腴，惟公不以位爲娛。", "宅家亦自臨朝說，丞相都因國事臞。"]'),
('a65e6872-45a0-4e26-a25f-484a2b03847b','鄭丞相生日口號十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','舒黯淹留守相間，平津千載有慙顔。',32,'全唐诗/poet.song.198000.json','["舒黯淹留守相間，平津千載有慙顔。", "惜渠不見端平相，召了西山召鶴山。"]'),
('adc6e0a4-fe37-4f2b-bcc8-e7c8ac86d1a2','鄭丞相生日口號十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','忤旨嬰鱗不自安，明朝密啟與遷官。',32,'全唐诗/poet.song.198000.json','["忤旨嬰鱗不自安，明朝密啟與遷官。", "百僚舉笏私相語，相國胸中得許寬。"]'),
('8be4b14e-c084-4d36-a215-b39d62be37d2','鄭丞相生日口號十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','曠懷未許衆人窺，細行猶堪百世師。',32,'全唐诗/poet.song.198000.json','["曠懷未許衆人窺，細行猶堪百世師。", "廣厦千間無地起，靈臺一片有天知。"]'),
('03ca68dd-f3fc-4f70-a2cb-5478c61c7195','鄭丞相生日口號十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','轉了頭廳屢乞歸，已將傳舍視黄扉。',32,'全唐诗/poet.song.198000.json','["轉了頭廳屢乞歸，已將傳舍視黄扉。", "江湖不欠魚羹飯，直爲君恩未拂衣。"]'),
('069fa534-60cf-48da-b83d-2778ff2ead85','鄭丞相生日口號十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','篚苞不復入脩門，民力微蘇物漸蕃。',32,'全唐诗/poet.song.198000.json','["篚苞不復入脩門，民力微蘇物漸蕃。", "見說海邊停䱹局，介鱗亦被相君恩。"]'),
('0ce81211-8519-40c2-b4ff-c1e339411349','鄭丞相生日口號十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','不用占蓍更訊龜，功成尚有赤松期。',32,'全唐诗/poet.song.198000.json','["不用占蓍更訊龜，功成尚有赤松期。", "由來壽與仁相貫，季主君平未必知。"]'),
('6bd1d44c-aa46-4518-bece-77dc7f299c01','出宿環碧','劉克莊','宋','宋诗','song-poetry','','[]','逐客挑包水榭中，忽聞乾鵲噪東風。',32,'全唐诗/poet.song.198000.json','["逐客挑包水榭中，忽聞乾鵲噪東風。", "若非閩嶠安書至，即是襄州吉語通。"]'),
('250c0684-0331-46b6-9ae3-1dd1e9109a70','環碧寒甚移宿客邸','劉克莊','宋','宋诗','song-poetry','','[]','香歇朝衣懶更熏，夢殘宮漏遠難聞。',32,'全唐诗/poet.song.198000.json','["香歇朝衣懶更熏，夢殘宮漏遠難聞。", "漫郎不稱青綾被，退士惟堪白布裙。"]'),
('a4c372cc-1fa2-4465-83ea-14dfec93c764','桐廬舟中即事','劉克莊','宋','宋诗','song-poetry','','[]','車前彎帽同聲散，關外華簪一揖休。',32,'全唐诗/poet.song.198000.json','["車前彎帽同聲散，關外華簪一揖休。", "惟有浙江潮好事，肯隨逐客到嚴州。"]'),
('a52228a3-0111-4a89-aac1-808b4e934769','朱買臣廟','劉克莊','宋','宋诗','song-poetry','','[]','翁子平生最苦貧，晚將丹頸博朱輪。',32,'全唐诗/poet.song.198000.json','["翁子平生最苦貧，晚將丹頸博朱輪。", "老儒五十無章綬，歸去何妨且負薪。"]'),
('255bf95a-7c30-4cae-8dce-efec66313dbe','江山道中','劉克莊','宋','宋诗','song-poetry','','[]','純綿未覺中年暖，薄酒難禁二月寒。',32,'全唐诗/poet.song.198000.json','["純綿未覺中年暖，薄酒難禁二月寒。", "可惜一溪桃李樹，貪程不得過橋看。"]'),
('72176904-9c69-48f5-930f-a1f7f8c28797','徐偃王廟','劉克莊','宋','宋诗','song-poetry','','[]','仁暴由來各異施，秦徐至竟孰雄雌。',32,'全唐诗/poet.song.198000.json','["仁暴由來各異施，秦徐至竟孰雄雌。", "君看驪岫今無墓，得似柯山尚有祠。"]'),
('7a46b2df-6b20-4bfa-a517-a00af06dbfd2','漁梁','劉克莊','宋','宋诗','song-poetry','','[]','淺溪忽漲尋常水，朽樹猶開千百花。',32,'全唐诗/poet.song.198000.json','["淺溪忽漲尋常水，朽樹猶開千百花。", "有酒可沽魚可買，造門莫問是誰家。"]'),
('afa5c694-297e-4f04-896f-48e4339bfe73','馮唐廟','劉克莊','宋','宋诗','song-poetry','','[]','當饋而今渴將材，豈無梟俊尚沉埋。',32,'全唐诗/poet.song.198000.json','["當饋而今渴將材，豈無梟俊尚沉埋。", "不曾薦得雲中守，也道身從省戶來。"]'),
('42363c7f-dfc6-41a3-9caf-193096970ebf','新蓬二嶺','劉克莊','宋','宋诗','song-poetry','','[]','路入雲端一綫微，行人竊笑僕交譏。',32,'全唐诗/poet.song.198000.json','["路入雲端一綫微，行人竊笑僕交譏。", "空囊非有連城璧，作麽携從間道歸。"]'),
('96cbdfd8-6eec-4828-b725-787c64f408ef','春陰','劉克莊','宋','宋诗','song-poetry','','[]','春陰欺得病夫身，偶值晴天一欠伸。',32,'全唐诗/poet.song.198000.json','["春陰欺得病夫身，偶值晴天一欠伸。", "客舍無誰相管領，半簷紅日苦留人。"]'),
('9c2f39cf-97f6-4d03-8034-2788f1565c75','宿小寺觀主僧陞座','劉克莊','宋','宋诗','song-poetry','','[]','靜處尤宜策睡勳，徑投禪榻炷鑪熏。',64,'全唐诗/poet.song.198000.json','["靜處尤宜策睡勳，徑投禪榻炷鑪熏。", "恰爲胡蝶春游美，忽吼華鯨曙色分。", "僧袒右肩方說法，我聾左耳若無聞。", "平生不作桑間戀，草草挑包下白雲。"]'),
('8d234e72-0b54-4b9b-a017-f772b024a179','田舍即事十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','去年贏粟尚儲瓶，又見新秧蘸水青。',32,'全唐诗/poet.song.198000.json','["去年贏粟尚儲瓶，又見新秧蘸水青。", "野老逢人說慙愧，長官清白社公靈。"]'),
('eee34628-f3b7-422c-afac-b0177e211b93','田舍即事十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','村落爭看烏角巾，略談北事向南人。',32,'全唐诗/poet.song.198000.json','["村落爭看烏角巾，略談北事向南人。", "百年只有中州樂，世世無爲塞下民。"]'),
('692b6b62-3e2d-4d8e-ab45-a4b3aee8bff3','田舍即事十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','古來觀社見春秋，茜袂銀釵盡出遊。',32,'全唐诗/poet.song.198000.json','["古來觀社見春秋，茜袂銀釵盡出遊。", "欲與魯人同獵較，可憐身世尚它州。"]'),
('8ca7edc1-b1a3-437d-8d3a-803782ca83e3','田舍即事十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','蹴踘鞵尖塵不涴，臂鷹袖窄樣新裁。',32,'全唐诗/poet.song.198000.json','["蹴踘鞵尖塵不涴，臂鷹袖窄樣新裁。", "社中年少相容否，也待鮮衣染鬢來。"]'),
('85ab8893-1a74-444e-8806-0453dc6e03d4','田舍即事十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','鄰壁嘲啾誦學而，老人睡少聽移時。',32,'全唐诗/poet.song.198000.json','["鄰壁嘲啾誦學而，老人睡少聽移時。", "它年謹勿如張禹，帝問床前謬不知。"]'),
('4ab5c505-1d35-42f0-bcaf-2c60712ba132','田舍即事十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','田舍諸雛各雅馴，男兒盍有藝資身。',32,'全唐诗/poet.song.198000.json','["田舍諸雛各雅馴，男兒盍有藝資身。", "古來醫卜多名世，莫學文章點涴人。"]'),
('e14bdd05-0077-4715-9a5e-8c9ee6409ebc','田舍即事十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','條桑女子兩鬟垂，車馬過門未省窺。',32,'全唐诗/poet.song.198000.json','["條桑女子兩鬟垂，車馬過門未省窺。", "生長柴門蓬戶裏，安知世有二南詩。"]'),
('1e5ff018-c903-4c68-8e25-c9c264b07c73','田舍即事十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','草草衣裝挈自隨，壻貧畢竟與齊眉。',32,'全唐诗/poet.song.198000.json','["草草衣裝挈自隨，壻貧畢竟與齊眉。", "絕勝京洛傾城色，鏁向侯門作侍兒。"]'),
('daed61f1-7f1d-4c6c-9396-c66105af2a49','田舍即事十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','兒女相携看市優，縱談楚漢割鴻溝。',32,'全唐诗/poet.song.198000.json','["兒女相携看市優，縱談楚漢割鴻溝。", "山河不暇爲渠惜，聽到虞姬直是愁。"]'),
('fe2a5f3d-50e9-4991-95f6-3cfb98f243d6','田舍即事十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','溪上漁郎占斷春，一川碧浪映紅雲。',32,'全唐诗/poet.song.198000.json','["溪上漁郎占斷春，一川碧浪映紅雲。", "問渠定是神仙否，艣去如飛語不聞。"]'),
('9dad6139-dbbd-4930-b570-64054c3ade92','寄題趙廣文南墅','劉克莊','宋','宋诗','song-poetry','','[]','博士才名賀白流，詎應蚤計到菟裘。',64,'全唐诗/poet.song.198000.json','["博士才名賀白流，詎應蚤計到菟裘。", "宮中未索清平調，海上聊爲汗漫遊。", "隠几飽看山變態，開軒惟對竹清脩。", "買鄰有志嗟無力，肯與羊曇共賭不。"]'),
('5fa6b83a-e33b-4512-9915-ef40ae62d379','寄和湯仲能','劉克莊','宋','宋诗','song-poetry','','[]','憶昨桃包返故鄉，意君束带侍明光。',64,'全唐诗/poet.song.198000.json','["憶昨桃包返故鄉，意君束带侍明光。", "一書似坐窮爲祟，百計無如去最長。", "蟻穴夢殘何足記，蟇陵願在莫須償。", "即今臺閣多收召，定有名公雪孝章。"]'),
('39f7f73a-d9dc-4ae0-8810-0d1cd3184ec3','送湯季庸監嶽','劉克莊','宋','宋诗','song-poetry','','[]','季子真奇士，聲名亞長君。',48,'全唐诗/poet.song.198000.json','["季子真奇士，聲名亞長君。", "尚難友裘牧，何敢吏朱雲。", "江國無生業，沙場有異聞。", "臨岐各珍重，世故屬紛紜。"]'),
('e4398af1-03e6-4185-9658-b73689f5b424','送徐鼎夫用廬陵通守博士戴文韻','劉克莊','宋','宋诗','song-poetry','','[]','一春風雨郡齋寒，荒了麻姑老子壇。',64,'全唐诗/poet.song.198000.json','["一春風雨郡齋寒，荒了麻姑老子壇。", "吏抱文書排闥至，客携詩卷退衙看。", "愁來鏡裏絲難染，老去胸中錦已殘。", "若棹扁舟見安道，爲言歲晚習申韓。"]'),
('8ce894df-0940-4840-a040-bf810ad37320','次韻王元度二詩  其一','劉克莊','宋','宋诗','song-poetry','','[]','留落而今兩鬢秋，暮年出處愧前修。',64,'全唐诗/poet.song.198000.json','["留落而今兩鬢秋，暮年出處愧前修。", "敢云余補韓公處，極喜君來謝客州。", "奇甚寶鐔騰紫氣，清於玉瓚薦黄流。", "後生不作先賢遠，便合相推出一頭。"]'),
('a0f0e0ed-1d87-4b0a-9953-899ecd9b1f14','次韻王元度二詩  其二','劉克莊','宋','宋诗','song-poetry','','[]','向來綺語禍機深，幾效靈均欲自沉。',64,'全唐诗/poet.song.198000.json','["向來綺語禍機深，幾效靈均欲自沉。", "周廟人曾銘在背，管城子已禿無心。", "今誰伯樂能酬價，後有鍾期必賞音。", "老矣尚須君警策，昔人一字答千金。"]'),
('1fb982cf-89bd-4d59-9297-53168188540a','送趙叔愚赴潯州理掾','劉克莊','宋','宋诗','song-poetry','','[]','未奉三雍對，聊爲五筦行。',48,'全唐诗/poet.song.198000.json','["未奉三雍對，聊爲五筦行。", "鄉書踰嶺少，詩思入湘清。", "遠宦身差穩，中州事日生。", "向來幾離別，此別最關情。"]'),
('e72038ed-0c7e-4839-a3c7-7f2b5f5c0d28','離郡五絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','自傷臨郡淺，有愧在民深。',24,'全唐诗/poet.song.198000.json','["自傷臨郡淺，有愧在民深。", "稽首文公廟，由唐直至今。"]'),
('59c30ef8-c29f-4525-8ffb-2558f61ee57d','離郡五絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','既收其印綬，猶送以車船。',24,'全唐诗/poet.song.198000.json','["既收其印綬，猶送以車船。", "回首柱下史，江邊更可憐。"]'),
('a9739117-1120-4a20-ba17-fd19ae30fb18','離郡五絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','昨日專城守，今朝失國人。',24,'全唐诗/poet.song.198000.json','["昨日專城守，今朝失國人。", "乾坤如許大，無地著孤臣。"]'),
('7696a6a2-5db3-40ef-a0f1-c4d8d8990174','離郡五絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','赫赫戎衣定，區區扣馬非。',24,'全唐诗/poet.song.198000.json','["赫赫戎衣定，區區扣馬非。", "如何孤竹子，嫌粟不嫌薇。"]'),
('aeb243b8-6592-46f1-8bce-c8c2abca9afa','離郡五絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','丘筆鄭克段，軻言象愛兄。',24,'全唐诗/poet.song.198000.json','["丘筆鄭克段，軻言象愛兄。", "回天力不足，削地罰猶輕。"]'),
('b63066c0-c273-42b6-875c-5165469de15e','寄徐直翁侍郎二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','銳惰皆由氣所爲，浩然不屈是男兒。',64,'全唐诗/poet.song.198000.json','["銳惰皆由氣所爲，浩然不屈是男兒。", "未知重入脩門後，何似初攀折檻時。", "已有客貽絕交論，豈無人取送行詩。", "勿令一種求疵者，妄議君侯鳳德衰。"]'),
('d1f98227-fcc6-4c74-aec8-d1a69456c02f','寄徐直翁侍郎二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','憶昨紛紛衆喙鳴，怪君噤齘久無聲。',64,'全唐诗/poet.song.198000.json','["憶昨紛紛衆喙鳴，怪君噤齘久無聲。", "得非家客留廷尉，或是閨人沮仲卿。", "白璧微瑕終古在，黄金橫带霎時榮。", "從來公議無情甚，莫遣蒙齋獨擅名。"]'),
('e50fc39d-aed6-4854-aa50-d7a7fc2dd560','和仲弟十絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','懶窺戶外問晴陰，靜向窗前閲古今。',32,'全唐诗/poet.song.198000.json','["懶窺戶外問晴陰，靜向窗前閲古今。", "江國事稀聊袖手，鈞天夢斷久灰心。"]'),
('b6bb574e-4412-4140-8154-6d188a526c34','和仲弟十絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','慈母清齋奉竺乾，平生功行默通天。',32,'全唐诗/poet.song.198000.json','["慈母清齋奉竺乾，平生功行默通天。", "遥知靜坐修禪觀，永晝爐中一穗煙。"]'),
('4557d21c-7c9d-4742-9345-3df034f83fdc','和仲弟十絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','即今江表尚恬熙，忘却前迴飲馬時。',32,'全唐诗/poet.song.198000.json','["即今江表尚恬熙，忘却前迴飲馬時。", "淝水豈無風鶴助，平涼莫受犬羊欺。"]'),
('cf83b992-ab52-4b65-bc26-34ce0a6b8ea5','和仲弟十絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','樓頭吹徹幾寒梅，推枕穿衣曉帳開。',32,'全唐诗/poet.song.198000.json','["樓頭吹徹幾寒梅，推枕穿衣曉帳開。", "蟻鬭蝸爭求予决，老夫身世自難裁。"]'),
('80cf0f33-3f49-459a-86ee-7df828c55d06','和仲弟十絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','一春簷溜不曾停，滴破空階蘚暈青。',32,'全唐诗/poet.song.198000.json','["一春簷溜不曾停，滴破空階蘚暈青。", "便是兒時對床雨，絕憐老大不同聽。"]'),
('609bfe53-6dae-461e-a991-1d07c3f65cea','和仲弟十絕  其六','劉克莊','宋','宋诗','song-poetry','','[]','行遍高臺到曲池，閑將白髮照清漪。',32,'全唐诗/poet.song.198000.json','["行遍高臺到曲池，閑將白髮照清漪。", "未應官舍無幽事，亦有臨流嘯詠時。"]'),
('1a7205ec-f381-4830-b349-d5f00d97ec28','和仲弟十絕  其七','劉克莊','宋','宋诗','song-poetry','','[]','少工文字老安施，不但才慳力已疲。',32,'全唐诗/poet.song.198000.json','["少工文字老安施，不但才慳力已疲。", "無復滴泉來上綆，惠連入夢偶成詩。"]'),
('860ba4e4-b052-4a53-90fa-ad89b1ba8d8b','和仲弟十絕  其八','劉克莊','宋','宋诗','song-poetry','','[]','弟兄雖幸忝朱輪，各是人間五十人。',32,'全唐诗/poet.song.198000.json','["弟兄雖幸忝朱輪，各是人間五十人。", "只合共娛千歲母，可能少補二州民。"]'),
('33da26f8-e5f8-42ec-830d-485096658909','和仲弟十絕  其九','劉克莊','宋','宋诗','song-poetry','','[]','鴈回杳杳渾無報，鵲語啾啾似有憑。',32,'全唐诗/poet.song.198000.json','["鴈回杳杳渾無報，鵲語啾啾似有憑。", "忽得遠書看百過，眼昏自起剔殘燈。"]'),
('2d2ee3a7-0a36-4271-8621-d9dc4e9de06f','和仲弟十絕  其一○','劉克莊','宋','宋诗','song-poetry','','[]','千古堂堂一孔明，尚咨幼宰訪州平。',32,'全唐诗/poet.song.198000.json','["千古堂堂一孔明，尚咨幼宰訪州平。", "諸君應悉惓惓意，老子寧希赫赫聲。"]'),
('6fdb880c-11e2-4ca6-8d66-70067f75a3bb','丁酉重九日宿順昌步雲閣絕句七首呈味道明府  其一','劉克莊','宋','宋诗','song-poetry','','[]','傍邑曾爲劫火塵，獨茲猶是太平民。',32,'全唐诗/poet.song.198000.json','["傍邑曾爲劫火塵，獨茲猶是太平民。", "兒時所歷今三紀，便喚溪山作故人。"]'),
('720b73ba-5b87-4b01-8866-fdbe9f392789','丁酉重九日宿順昌步雲閣絕句七首呈味道明府  其二','劉克莊','宋','宋诗','song-poetry','','[]','老子癡頑耐遠遊，平生腹不貯閑愁。',32,'全唐诗/poet.song.198000.json','["老子癡頑耐遠遊，平生腹不貯閑愁。", "今年天賜登高地，身在雲峰最上頭。"]'),
('c46d7f3e-4938-4107-ade9-0ca327c0c0bb','丁酉重九日宿順昌步雲閣絕句七首呈味道明府  其三','劉克莊','宋','宋诗','song-poetry','','[]','小休綠樹濯清泉，垢盡身輕意欲仙。',32,'全唐诗/poet.song.198000.json','["小休綠樹濯清泉，垢盡身輕意欲仙。", "豈必魯儒知此樂，舞雩風止在溪邊。"]'),
('81642e24-e0f3-48a0-af59-4790cdde1297','丁酉重九日宿順昌步雲閣絕句七首呈味道明府  其四','劉克莊','宋','宋诗','song-poetry','','[]','九月南州菊未黄，芙蓉取次獻新粧。',32,'全唐诗/poet.song.198000.json','["九月南州菊未黄，芙蓉取次獻新粧。", "不妨折取繁紅插，四海皆知兩鬢霜。"]'),
('390e8420-134f-4a90-9671-eea524b93ef0','丁酉重九日宿順昌步雲閣絕句七首呈味道明府  其五','劉克莊','宋','宋诗','song-poetry','','[]','只了年年作逐臣，衣冠繿縷面埃塵。',32,'全唐诗/poet.song.198000.json','["只了年年作逐臣，衣冠繿縷面埃塵。", "偶逢令尹留連我，不畏狂生點涴人。"]'),
('9db52389-9037-4a8f-b1fa-fa67d84cb9a5','丁酉重九日宿順昌步雲閣絕句七首呈味道明府  其六','劉克莊','宋','宋诗','song-poetry','','[]','先倩清風掃水軒，更呼凉月倒金樽。',32,'全唐诗/poet.song.198000.json','["先倩清風掃水軒，更呼凉月倒金樽。", "定知明府歸侵夜，縣郭留燈未閉門。"]'),
('e13955ac-62b8-417a-a7bd-be33f15855eb','丁酉重九日宿順昌步雲閣絕句七首呈味道明府  其七','劉克莊','宋','宋诗','song-poetry','','[]','長君論事天爲動，季子居官水似清。',32,'全唐诗/poet.song.198000.json','["長君論事天爲動，季子居官水似清。", "雙眊不能鈔諫草，偏聾尚可聽琴聲。"]'),
('339ef16f-14f2-48f9-8a41-8c19296fca8e','友人李先輩丑父嘗以夷成詩二帙示余莫知爲何人所作心甚愛之過延平客有袖詩一章見訪始知夷成者蓋葉君之別號也鬚髮皓然矣詩與人皆可重因用其韻爲謝','劉克莊','宋','宋诗','song-poetry','','[]','筋力都非少壯時，不煩攬鏡覺吾衰。',64,'全唐诗/poet.song.198000.json','["筋力都非少壯時，不煩攬鏡覺吾衰。", "展禽出仕曾三已，表聖歸休有四宜。", "飽閲交情悲世道，差强人意頼君詩。", "此生到死慙三士，本自難招況易麾。"]'),
('25511ad0-f5e5-4390-99a2-bdf26d155a23','丁酉九月十四日黄源嶺客舍題黄瀛父近詩','劉克莊','宋','宋诗','song-poetry','','[]','不但行吟又卧披，掩編因有感於斯。',64,'全唐诗/poet.song.198000.json','["不但行吟又卧披，掩編因有感於斯。", "競爲蛙蚓號鳴態，烏覩龍鸞夭矯姿。", "損挹嫌人稱大好，琢磨容我指微疵。", "自慙學識非匡鼎，安敢陪君共說詩。"]'),
('ddb2562c-25d2-4255-ad94-390b269aab6a','次王元度韻','劉克莊','宋','宋诗','song-poetry','','[]','占盡靈烏顧盡雲，君恩寬大放歸閩。',64,'全唐诗/poet.song.198000.json','["占盡靈烏顧盡雲，君恩寬大放歸閩。", "一區二頃生緣薄，萬緒千條素髮新。", "鐵馬即今徵戰士，金雞何日赦纍臣。", "殷勤說向西飛鴈，多謝交游與吏民。"]'),
('22888578-3f38-4063-8d0b-970390bcfaed','送范守仲冶二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','二年田里內，民不識追胥。',48,'全唐诗/poet.song.198000.json','["二年田里內，民不識追胥。", "官府絕無事，使君惟讀書。", "儉於住家日，臞似下車初。", "太末方凋弊，公行不可徐。"]'),
('0d7bdebc-52ba-4b2d-8c97-5ed9180fd535','送范守仲冶二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','放逐諳時態，惟侯意味長。',48,'全唐诗/poet.song.198000.json','["放逐諳時態，惟侯意味長。", "醴爲狂客設，羹許老人嘗。", "南國留棠舍，西郊閉草堂。", "臨岐先作惡，未可倚剛腸。"]'),
('2bf11715-c328-4e5d-bb45-dc7ca53c02c6','挽趙漕簡叔二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','雖擁軺車貴，蕭然似布韋。',48,'全唐诗/poet.song.198000.json','["雖擁軺車貴，蕭然似布韋。", "家依僧舍住，俸買古琴歸。", "海內勝流盡，民間廉吏稀。", "空餘詩卷在，展玩一沾衣。"]'),
('9768fa6e-cf58-44c3-98a2-032821d10308','挽趙漕簡叔二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','恰訝書題少，俄驚訃問臨。',48,'全唐诗/poet.song.198000.json','["恰訝書題少，俄驚訃問臨。", "死方拋筆研，貧不涴珠琛。", "劫火難隳節，浮雲肯動心。", "悲哉廣陵散，舊譜有誰尋。"]'),
('2691a46d-8cc7-44da-a07d-96f2ad942570','曹路分贈詩次韻一首','劉克莊','宋','宋诗','song-poetry','','[]','古來詩律推曹氏，不數河梁與董逃。',64,'全唐诗/poet.song.198000.json','["古來詩律推曹氏，不數河梁與董逃。", "唐季三家松最勝，建安七子植尤高。", "短檠尚課兒精選，老筆真堪僕命騷。", "極欲留君橫槊賦，舟人苦報粵江濤。"]'),
('a5d36e75-d68c-495f-b523-4ba531d9170e','用曹帥侍郎韻贈曹路分','劉克莊','宋','宋诗','song-poetry','','[]','曹侯書滿腹，非以劍防身。',48,'全唐诗/poet.song.198000.json','["曹侯書滿腹，非以劍防身。", "馬上檄尤速，橐中詩不貧。", "虜情工變詐，時論主和親。", "旗鼓何時建，方知國有人。"]'),
('a8365026-ced6-4189-aadb-beeb1015ebe4','永嘉曹君贈詩次韻一首','劉克莊','宋','宋诗','song-poetry','','[]','開卷沉吟首屢搔，想提詩律比戎韜。',64,'全唐诗/poet.song.198000.json','["開卷沉吟首屢搔，想提詩律比戎韜。", "清於學士茶烹雪，壯似將軍弩射濤。", "再茜三纁由染漬，勺泉卷石可深高。", "蝸廬自笑無巵酒，不得澆君道路勞。"]'),
('0d8d6c1d-221c-490e-bdf3-8bd14c0e8fa7','余大父著作嘗以所得沈元用給事歙硯遺水南林府君後七十年林氏子大鼎以端研遺余答以小詩','劉克莊','宋','宋诗','song-poetry','','[]','隆乾手澤稀疎甚，數帖悽其在水南。',64,'全唐诗/poet.song.198000.json','["隆乾手澤稀疎甚，數帖悽其在水南。", "但看吾翁貽歙石，固應之子餉端巖。", "丁寧後裔藏爲好，羞愧先民寶不貪。", "自笑老猶耽筆硯，少年莫也肯同參。"]'),
('00af7c93-7bb8-451b-b44d-0652bb07b54f','挽鄭子敬都承二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','重入脩門兩鬢絲，延和累疏竭忠規。',64,'全唐诗/poet.song.198000.json','["重入脩門兩鬢絲，延和累疏竭忠規。", "立朝頗慕汲生戇，謀國不知晁氏危。", "老去故人能有幾，古來君子例無時。", "傳聞近事堪悲慨，說向重泉亦皺眉。"]'),
('d0c2e588-fa1a-406a-959a-0aceb61b0b01','挽鄭子敬都承二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','向來俱觸相君嗔，里社追隨二十春。',64,'全唐诗/poet.song.198000.json','["向來俱觸相君嗔，里社追隨二十春。", "尚記殘編燈下共，忽看華表路傍新。", "行車不忍過三步，臨穴應難贖百身。", "歲晚空山風雨橫，奠芻歸去倍傷神。"]'),
('fc65fa1e-d475-4859-9f86-130671693c49','次韻實之二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','孤臣去國四經春，迹遠安知罪尚新。',64,'全唐诗/poet.song.198000.json','["孤臣去國四經春，迹遠安知罪尚新。", "蚤亦曾譏秦氏者，晚爲與議濮園人。", "懶箋光範干時宰，且伴田家賽社神。", "醉倒不能愁世事，倩他煙柳替含顰。"]'),
('073a626b-404c-4e2c-a8da-51c957a61fea','次韻實之二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','向來歲月半投閑，莫歎朝朝苜蓿盤。',64,'全唐诗/poet.song.198000.json','["向來歲月半投閑，莫歎朝朝苜蓿盤。", "身後芬芳聊自誑，眼前腥腐飽曾餐。", "蟲雞一笑何須較，花鳥相疎恐被彈。", "清議自爲儒者設，未應覊束老黄冠。"]'),
('ed8862c6-a7df-4f0a-99db-fad78156ce62','再和二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','借屋城中又一春，桃符萬口說清新。',64,'全唐诗/poet.song.198000.json','["借屋城中又一春，桃符萬口說清新。", "向來曾上慶曆頌，老去甘爲元祐人。", "健論真堪驚諂子，固窮不肯媚錢神。", "吾評此士西塘比，後進紛紛謾效顰。"]'),
('6efd547b-2e6a-44e4-bb56-76e3e0a86099','再和二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','與君未得便安閑，邊警偏能惱澗槃。',64,'全唐诗/poet.song.198000.json','["與君未得便安閑，邊警偏能惱澗槃。", "草地棗紅猶索鬭，田家稻白可能餐。", "誰將鐵綆橫江鎖，莫靠琵琶出塞彈。", "處處衝梯樓上舞，不應諸老自巍冠。"]'),
('04070658-36c8-4eed-85ad-d2e2992ffb08','三和二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','主聖時清萬宇春，禽魚花草各懷新。',64,'全唐诗/poet.song.198000.json','["主聖時清萬宇春，禽魚花草各懷新。", "如何丹鳳樓中手，未作金雞竿下人。", "家有寧馨堪跨竈，囊無阿堵可通神。", "客談江北狼煙息，暫展雙眉不用顰。"]'),
('cbb479e9-a205-43fd-a6d7-264382f9c62c','三和二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','厨人無職主君閑，春日惟供菜滿槃。',64,'全唐诗/poet.song.198000.json','["厨人無職主君閑，春日惟供菜滿槃。", "山下鴟肥聊共飽，堂中羊美得常餐。", "徧嘗憂患肱三折，已過光陰指一彈。", "老去有巾宜漉酒，笑它楚客切雲冠。"]'),
('daaec5e7-53c3-4c1f-a2dd-ab484f9c488d','挽戴丞','劉克莊','宋','宋诗','song-poetry','','[]','戴氏多人物，君尤月旦推。',48,'全唐诗/poet.song.198000.json','["戴氏多人物，君尤月旦推。", "能傳后倉禮，亦擅叔倫詩。", "故里懸車蚤，名場解褐遲。", "它年端有恨，椿桂不同時。"]'),
('02f4f125-d3c9-459c-9f9d-930248539b9e','題永福黄生行卷','劉克莊','宋','宋诗','song-poetry','','[]','廢詩二十餘年矣，忽讀來詩眼暫明。',64,'全唐诗/poet.song.198000.json','["廢詩二十餘年矣，忽讀來詩眼暫明。", "處士梅曾如許瘦，化人酒莫過於清。", "蛩鳴競起爲唐體，牛耳誰堪主夏盟。", "事闊語長殊未竟，跨馿作麽問歸程。"]'),
('7c79060b-c4af-491d-81d1-d7ef2c44a7ae','送方清孫參學','劉克莊','宋','宋诗','song-poetry','','[]','僕負輕裝主倚轅，交游握手若爲言。',64,'全唐诗/poet.song.198000.json','["僕負輕裝主倚轅，交游握手若爲言。", "須求沂水風雩樂，勿愛沙河夜市繁。", "曩日士曾宗郭太，它時我欲傳何蕃。", "殷勤待折津亭柳，老怕春寒不出村。"]'),
('d5f1a2c6-f16b-4f8a-a1ce-e993bb3667d5','挽南塘趙尚書二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','起掌端平制，蕭蕭素髮新。',48,'全唐诗/poet.song.198000.json','["起掌端平制，蕭蕭素髮新。", "更生宗室老，太白謫僊人。", "貴矣狨施馬，悲哉筆絕麟。", "誰爲篆華表，題作宋詞臣。"]'),
('523b8875-69bb-4f51-ab62-c618248d6a09','挽南塘趙尚書二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','自從水心死，麈柄獨歸公。',48,'全唐诗/poet.song.198000.json','["自從水心死，麈柄獨歸公。", "於易疑程氏，惟詩取晦翁。", "二箴家有本，孤論世無同。", "不復重商榷，騎鯨浩渺中。"]'),
('f5e3b11c-315f-48e4-b055-ce9b68900704','次韻實之春日二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','向來文字擅中朝，留落而今賦大招。',64,'全唐诗/poet.song.198000.json','["向來文字擅中朝，留落而今賦大招。", "才子左遷追屈賈，相君高蹈友松喬。", "山行或與樵爭席，澗飲聊將掬代瓢。", "借使終身無一事，亦令千載仰孤標。"]'),
('08973c6a-724d-4dd8-9035-e45faa420c80','次韻實之春日二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','梅醭朝衣塵滿靴，曾穿細仗對延和。',64,'全唐诗/poet.song.198000.json','["梅醭朝衣塵滿靴，曾穿細仗對延和。", "角巾久已尋初服，錦帳何須戀舊窩。", "能讀書人天下少，不如意事古來多。", "半生寂寂因迂闊，垂老方驚歲月蹉。"]'),
('3fd6d8e8-3b36-4bcb-a349-d10583323b18','再和二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','滎陽相昔獨當朝，曾忝弓旌第一招。',64,'全唐诗/poet.song.198000.json','["滎陽相昔獨當朝，曾忝弓旌第一招。", "無力不能捄房琯，有書安敢托洪喬。", "如聞徒步輕千駟，未覺堂厨勝一瓢。", "鄧禹封侯子陵釣，君看二者孰風標。"]'),
('2c153c64-6716-430c-8ea2-09de7444c9c8','再和二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','少小從軍事袴鞾，祇今廟算主通和。',64,'全唐诗/poet.song.198000.json','["少小從軍事袴鞾，祇今廟算主通和。", "胡來復去兔三窟，民散未收蜂一窩。", "病覺風光於我薄，老知書冊誤人多。", "罪言著就深藏取，自笑狂生壯志蹉。"]'),
('f7af65b5-45fd-4ea2-98fb-a11f70068d66','三和二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','豈有絲毫補聖朝，去來擾擾費麾招。',64,'全唐诗/poet.song.198000.json','["豈有絲毫補聖朝，去來擾擾費麾招。", "不能履屐供羣謝，未暇綸巾擁二喬。", "著老萊衣侔服冕，食於陵粟勝操瓢。", "臣之少也猶疎懶，何况頭今插素標。"]'),
('0e53474d-cb8d-4ccf-97f2-b19ee29d54f0','三和二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','長劍拄頤刀納鞾，得如曝背趁陽和。',64,'全唐诗/poet.song.198000.json','["長劍拄頤刀納鞾，得如曝背趁陽和。", "買鄰底用百萬價，好事爭爲十二窩。", "異日史臣應有考，同時朝士欲無多。", "與君死守西山學，莫遣人譏末路蹉。"]'),
('e2cba38b-d47e-40ef-ad52-464bdb630891','四和二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','夢魂久不到清朝，縱遣巫咸未易招。',64,'全唐诗/poet.song.198000.json','["夢魂久不到清朝，縱遣巫咸未易招。", "塞北今惟一韋叡，江南前此幾陳喬。", "扶顛个个無長策，排悶時時引大瓢。", "它日松根深掩骨，何須竹帛有名標。"]'),
('2ec0ddbd-b0a8-49d9-957d-4bd4c31deb16','四和二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','朱門畫鼓舞宮靴，應笑狂歌似采和。',64,'全唐诗/poet.song.198000.json','["朱門畫鼓舞宮靴，應笑狂歌似采和。", "露坐一生無步障，春游是處有行窩。", "紹興讜議誰當續，元祐全人本不多。", "辦取九年同面壁，未應末後話頭蹉。"]'),
('aad90c5b-032d-4da0-a635-a4ca44162121','五和二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','尚記諸賢聚本朝，當時君相急旁招。',64,'全唐诗/poet.song.198000.json','["尚記諸賢聚本朝，當時君相急旁招。", "簫韶九奏鳳諧樂，金彈一聲鶑下喬。", "彊項昔嘗攀殿檻，饑腸今欲把僧瓢。", "蚤知不得文章力，却悔從初奪錦標。"]'),
('a09dabf6-071f-4ce5-bb5b-41fcaee54df5','五和二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','頹然一榻懶巾靴，二月東風尚未和。',64,'全唐诗/poet.song.198000.json','["頹然一榻懶巾靴，二月東風尚未和。", "雀闖屋簷來作宿，蜂銜窗紙去爲窩。", "牢愁余髮五分白，健思君才十倍多。", "欲訪東臯賢鼻祖，幾回路與醉鄉蹉。"]'),
('a3208faa-9e22-420a-b406-bf15154facc7','六和二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','那復熏衣事早朝，杖藜時赴野人招。',64,'全唐诗/poet.song.198000.json','["那復熏衣事早朝，杖藜時赴野人招。", "謀身不善交韓呂，度世猶堪訪賀喬。", "杖有百錢尋酒琖，家無一物止詩瓢。", "君看莘渭三王佐，何似夷齊萬世標。"]'),
('bff450ff-437a-45fd-8251-6771a39506ae','六和二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','生怕將軍手涴靴，安能柔軟舞靈和。',64,'全唐诗/poet.song.198000.json','["生怕將軍手涴靴，安能柔軟舞靈和。", "艱虞夷甫方謀窟，老懶堯夫少出窩。", "時事纍棋如許急，春愁抽繭未爲多。", "終南一徑非常捷，自是吾徒問路蹉。"]'),
('38a32f47-f968-4189-8ef4-cb7ffc68d26f','別張季','劉克莊','宋','宋诗','song-poetry','','[]','昔謁西山過里中，談兵論易氣如虹。',64,'全唐诗/poet.song.198000.json','["昔謁西山過里中，談兵論易氣如虹。", "若非遇彼負苓者，必是傳於墜履翁。", "至竟白袍無諂屈，何曾黄策有英雄。", "秋風定訪蒙齋否，爲說馮唐老更窮。"]'),
('572d4e08-ae05-445c-b6d1-8347f0b97c68','挽淮東丘升撫幹','劉克莊','宋','宋诗','song-poetry','','[]','子美曼卿流，遠携書劍遊。',48,'全唐诗/poet.song.198000.json','["子美曼卿流，遠携書劍遊。", "惜攀丹桂晚，勇赴白檀秋。", "尚喜前籌壯，聊紓左衽憂。", "時危奇士夭，無淚可供愁。"]'),
('8bbbffe8-126a-4103-8968-05c5fae7c89b','五月旦日鷄鳴夢袖疏墀下先君問言何事答曰猶素論也先君太息稱善聞追班聲驚寤以詩識之','劉克莊','宋','宋诗','song-poetry','','[]','夢中候對殿東廂，解后先親問答詳。',64,'全唐诗/poet.song.198000.json','["夢中候對殿東廂，解后先親問答詳。", "碓磨不能移素論，曝芹終欲獻清光。", "觸屏訓諂生猶臭，攀檻傳名死亦香。", "君父臨之安所避，凌晨起坐涕淋浪。"]'),
('bdc8872b-4f1b-41c5-8075-10d577522f3c','和張使君一首','劉克莊','宋','宋诗','song-poetry','','[]','里巷傳呼府座來，柴門草戶亦榮哉。',64,'全唐诗/poet.song.198000.json','["里巷傳呼府座來，柴門草戶亦榮哉。", "相忘金鯽忽然躍，慣見白鷗渾不猜。", "墨客堵牆觀落筆，花神步水出行杯。", "定知入奉吾丘計，萬一君王訪草萊。"]'),
('3a9e0050-08f1-4547-ab4d-ff1884b573be','題趙別駕委齋','劉克莊','宋','宋诗','song-poetry','','[]','乍看華扁費尋思，徐叩微言極坦夷。',64,'全唐诗/poet.song.198000.json','["乍看華扁費尋思，徐叩微言極坦夷。", "無可奈何安命者，吾非惡此欲逃之。", "萬羊賦祿渠前定，二鳥蒙恩彼一時。", "總被委齋參透了，不求符竹止求祠。"]'),
('2e1b4fb6-fcb4-41b8-bea9-4a4d19a84feb','次張使君韻','劉克莊','宋','宋诗','song-poetry','','[]','欲架茅堂久不成，蕭然身世托專城。',64,'全唐诗/poet.song.198000.json','["欲架茅堂久不成，蕭然身世托專城。", "日無車轄非常靜，月有餐錢未是清。", "髠首向來輸白粲，短衣老去斸黄精。", "絕憐不及梁間燕，歲歲新巢巧自營。"]'),
('7ac63344-9da0-4e5d-b62a-a59716ad0118','讀邸報二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','並驅華轂適通逵，中路安知判兩岐。',64,'全唐诗/poet.song.198000.json','["並驅華轂適通逵，中路安知判兩岐。", "邪等惟余尤甚者，好官非汝孰爲之。", "纍臣放逐無還理，陛下英明有寤時。", "聞向蕭山呼渡急，想追前事亦顰眉。"]'),
('fabf41b1-957f-4476-8d5d-c4ddf9786002','讀邸報二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','瑶編對秉初修筆，粉署同携夜直衾。',64,'全唐诗/poet.song.198000.json','["瑶編對秉初修筆，粉署同携夜直衾。", "虎既蒙皮甘搏噬，鶴因瘡羽久呻吟。", "盡歸一網機猶淺，橫說三綱害最深。", "想到鄮山多暇日，軻書毋惜細研尋。"]'),
('ac1bf31f-7d70-41dd-bd55-540be045d183','自和二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','橫身久塞楊朱路，灑泣俄悲墨子岐。',64,'全唐诗/poet.song.198000.json','["橫身久塞楊朱路，灑泣俄悲墨子岐。", "陋矣射鉤而中者，壯哉鳴鼓以攻之。", "侍讀自無遷府分，中丞還有僦船時。", "八風舞罷君恩歇，贏得閑愁上兩眉。"]'),
('624cb9e8-88b3-42f6-aeeb-91547ebcedae','自和二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','貴豪渠已重金带，貧病儂猶舊布衾。',64,'全唐诗/poet.song.198000.json','["貴豪渠已重金带，貧病儂猶舊布衾。", "鍾阜解仇無宿憾，荆江感事有新吟。", "早知餘耳交難保，晚覺王何罪未深。", "白首還鄉應閉戶，斷無保社肯追尋。"]'),
('b99c9633-bca4-44d7-b06e-dc3086c5e284','和實之讀邸報四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','祝鮀非是佞，莒僕未爲凶。',48,'全唐诗/poet.song.198000.json','["祝鮀非是佞，莒僕未爲凶。", "鬼谷從橫舌，終南詭秘蹤。", "斷無麟在藪，獨有鼠穿墉。", "千古誰儔匹，依稀似敬宗。"]'),
('1f98c51a-3f90-475b-ae5c-c39fb90ad865','和實之讀邸報四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','穿鑿彊揮麈，跳梁勇執弓。',48,'全唐诗/poet.song.198000.json','["穿鑿彊揮麈，跳梁勇執弓。", "矯誣天亦怒，驅逐國爲空。", "笑裏刀常有，盟邊甲已衷。", "拾遺端可拜，誅佞筆生風。"]'),
('04f18358-0caa-41dc-974c-cdb9eb1a511c','和實之讀邸報四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','外觀殊偉岸，內稟極憸柔。',48,'全唐诗/poet.song.198000.json','["外觀殊偉岸，內稟極憸柔。", "欲取漢清議，盡投唐濁流。", "鬼車鳴甚惡，猛虎死方羞。", "芳臭須臾判，哀哉不善謀。"]'),
('8dc6ee13-37e2-4887-b5f7-33dad31f2653','和實之讀邸報四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','一抨初駭聽，雙淚謾求哀。',48,'全唐诗/poet.song.198000.json','["一抨初駭聽，雙淚謾求哀。", "極口誣賢者，甘心譽彼哉。", "早知豺不食，安用鴆爲媒。", "試問高陽里，迎車幾兩來。"]'),
('9810a383-6668-4d8d-8309-801e2381c2c3','再和四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','狐鳴工作祟，鴉噪每爲凶。',48,'全唐诗/poet.song.198000.json','["狐鳴工作祟，鴉噪每爲凶。", "魯觀初尸罪，丘門永削蹤。", "謀身真有窟，鑿趾欲無墉。", "力擊延齡去，堂堂似亢宗。"]'),
('eba68a4c-eb98-4566-b9d2-2bd5ef945597','再和四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','舊知偏下石，遠避亦傷弓。',48,'全唐诗/poet.song.198000.json','["舊知偏下石，遠避亦傷弓。", "留落周南衆，蕭條冀北空。", "萬言徒飾詐，雙淚却由衷。", "王績何曾醉，劉蕡本不風。"]'),
('17c607a6-791a-4392-9617-daf5d9331b2c','再和四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','噬人侔虺毒，害物比貓柔。',48,'全唐诗/poet.song.198000.json','["噬人侔虺毒，害物比貓柔。", "清議姑驅逐，寬恩未放流。", "劍誅張禹佞，扇障褚淵羞。", "諫筆非私忿，惓惓爲國謀。"]'),
('c94b6e16-9079-4670-a47c-57d9fcb09da7','再和四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','伏閣何其壯，登舟得許哀。',48,'全唐诗/poet.song.198000.json','["伏閣何其壯，登舟得許哀。", "人多稱快者，上豈少恩哉。", "惡草毋留種，夭桃不待媒。", "九重方遠佞，寧放鄭詹來。"]'),
('ebc339db-3101-431a-a4ee-f08d0cd7d984','挽李卿儔老二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','苦說兵財少，臣非怯塞垣。',48,'全唐诗/poet.song.198000.json','["苦說兵財少，臣非怯塞垣。", "上思前語驗，人歎左遷冤。", "老大雲中守，風寒國北門。", "故交頭白盡，空爲賦招魂。"]'),
('7fb73018-9cc4-4f22-bf47-9deb5a59d907','挽李卿儔老二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','人物今衰少，惟侯智勇兼。',48,'全唐诗/poet.song.198000.json','["人物今衰少，惟侯智勇兼。", "悲風起關塞，斜日薄嵫崦。", "老子無從涕，諸賢不及髯。", "知心惟蜀李，應爲發幽潜。"]'),
('b3454eb4-2e18-43bc-98e1-6f72b7e70277','挽鄭貢士','劉克莊','宋','宋诗','song-poetry','','[]','少日鳴秋賦，中年讀古書。',48,'全唐诗/poet.song.198000.json','["少日鳴秋賦，中年讀古書。", "寧游魯侯泮，不詣漢公車。", "鄭老先生行，申公八十餘。", "何妨鳳雛小，玉潤亢門閭。"]'),
('da07e5ec-d3d4-48e1-8b4e-ee66a9048b93','梅州楊守鐵庵','劉克莊','宋','宋诗','song-poetry','','[]','北客由來憚入南，僕家諫議飽曾諳。',64,'全唐诗/poet.song.198000.json','["北客由來憚入南，僕家諫議飽曾諳。", "誰云瘴霧非吾土，曾有魁躔住此庵。", "身重豈容眉斧伐，時危猶要脊梁檐。", "公歸未必懷陳迹，留與州人作美談。"]'),
('d83658c1-61f8-4969-a152-75695728acc0','梅州重建中和堂','劉克莊','宋','宋诗','song-poetry','','[]','中和堂昔隳於火，今剪荒榛再落成。',64,'全唐诗/poet.song.198000.json','["中和堂昔隳於火，今剪荒榛再落成。", "博士尊師重演說，史君存古不更名。", "漸摩伋學三風熄，流布褒詩五瘴清。", "天子金聲兼玉振，會徵褚大與兒生。"]'),
('6c36f207-5153-484a-a346-58676669dca1','題張簿尉槎溪集','劉克莊','宋','宋诗','song-poetry','','[]','千載枯槎無主名，才翁子晦各偷撐。',32,'全唐诗/poet.song.198000.json','["千載枯槎無主名，才翁子晦各偷撐。", "分明博望昇天訴，不許人間別姓爭。"]'),
('eeae80ea-23eb-49c2-8702-4b62c7f2b10c','陳景升頃遺余化度寺碑甚佳闕後三行歸自龍溪始爲余補足記以絕句','劉克莊','宋','宋诗','song-poetry','','[]','端平曾歎闕三行，淳祐重來爲補亡。',32,'全唐诗/poet.song.198000.json','["端平曾歎闕三行，淳祐重來爲補亡。", "收拾一碑勞十載，此生凡事不須忙。"]'),
('5f97e620-6615-4203-876d-3de14d68c966','端嘉雜詩二十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','幅裂常包割地羞，掃平忽雪戴天讎。',32,'全唐诗/poet.song.198000.json','["幅裂常包割地羞，掃平忽雪戴天讎。", "穹廬已蹀完顔血，露布新函守緒頭。"]'),
('282887e8-61d4-4a5e-9489-06999da87e68','端嘉雜詩二十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','聞說關河唾掌收，擬爲跛子看花遊。',32,'全唐诗/poet.song.198000.json','["聞說關河唾掌收，擬爲跛子看花遊。", "可憐逸少興公輩，說著中原得許愁。"]'),
('562d874f-c880-4ce6-b478-48d1e7b6517b','端嘉雜詩二十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','由北圖南有混并，自南取北費經營。',32,'全唐诗/poet.song.198000.json','["由北圖南有混并，自南取北費經營。", "從今束起書生論，噉飯看人致太平。"]'),
('dae9e4f4-a4be-4044-b44a-729d5fdfcbe3','端嘉雜詩二十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','不及生前見虜亡，放翁易簀憤堂堂。',32,'全唐诗/poet.song.198000.json','["不及生前見虜亡，放翁易簀憤堂堂。", "遥知小陸羞時薦，定告王師入洛陽。"]'),
('a71b8ca4-be23-456d-b286-f1275b869658','端嘉雜詩二十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','少年意氣慕橫行，不覺蹉跎過一生。',32,'全唐诗/poet.song.198000.json','["少年意氣慕橫行，不覺蹉跎過一生。", "便脫深衣籠窄袖，去參留守看東京。"]'),
('d6f1f3a4-571b-47ef-99e9-1bfa01a22fd7','端嘉雜詩二十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','鞏洛山川幾過兵，漢家初遣使修陵。',32,'全唐诗/poet.song.198000.json','["鞏洛山川幾過兵，漢家初遣使修陵。", "可無神物呵豺虎，直護香煙到柏城。"]'),
('409182ae-99ba-4a8f-8098-c332b59c06c8','端嘉雜詩二十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','萇尤桀點於堅者，勒固姦雄奈虎何。',32,'全唐诗/poet.song.198000.json','["萇尤桀點於堅者，勒固姦雄奈虎何。", "剩製赭袍添曲蓋，中原假帝不勝多。"]'),
('4fd3bc7f-75a8-474e-b57e-30efefbe2c6e','端嘉雜詩二十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','鞠躬解作華人語，辮髮來持虜帳書。',32,'全唐诗/poet.song.198000.json','["鞠躬解作華人語，辮髮來持虜帳書。", "祇合索綯牽畜狗，不煩伐鼓享鶢鶋。"]'),
('d99d846b-924c-49be-9b16-ef599c09cc23','端嘉雜詩二十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','倴僝將軍約早回，楚材相國更頻催。',32,'全唐诗/poet.song.198000.json','["倴僝將軍約早回，楚材相國更頻催。", "江東將相真如虎，去報胡雛莫過來。"]'),
('40e505ca-a820-4837-828b-bdd2f6636431','端嘉雜詩二十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','全衆回軍未可非，反旗鳴鼓亦兵機。',32,'全唐诗/poet.song.198000.json','["全衆回軍未可非，反旗鳴鼓亦兵機。", "不知三帥揚鞭際，誰爲君王殿後歸。"]'),
('656a6b95-74fa-44af-b12f-36d1442bd9fb','端嘉雜詩二十首  其一一','劉克莊','宋','宋诗','song-poetry','','[]','勢窮斯變變斯通，局面初更便不同。',32,'全唐诗/poet.song.198000.json','["勢窮斯變變斯通，局面初更便不同。", "西北怕他小老子，東南有箇太平翁。"]'),
('bd8cc10e-2f41-43d8-bf49-fcabbe938186','端嘉雜詩二十首  其一二','劉克莊','宋','宋诗','song-poetry','','[]','一番旗鼓建行臺，勇者投軀富輦財。',32,'全唐诗/poet.song.198000.json','["一番旗鼓建行臺，勇者投軀富輦財。", "邊將不消橫草戰，國王祇要撒花回。"]'),
('468d95a0-1cd3-4cda-9366-4b5875c3d488','端嘉雜詩二十首  其一三','劉克莊','宋','宋诗','song-poetry','','[]','不妨割肉餧豺狼，和約依然墮渺茫。',32,'全唐诗/poet.song.198000.json','["不妨割肉餧豺狼，和約依然墮渺茫。", "未必與吾盟夾谷，且須防彼劫平凉。"]'),
('3bd1a285-760f-4e18-8634-eb200c0c8c5a','端嘉雜詩二十首  其一四','劉克莊','宋','宋诗','song-poetry','','[]','蠲除一倍臺符下，權借三分督檄傳。',32,'全唐诗/poet.song.198000.json','["蠲除一倍臺符下，權借三分督檄傳。", "頼已奪麾耕壟上，不然伏鑕徇軍前。"]'),
('ad803f11-d419-4e23-aaef-6e84c8634b9b','端嘉雜詩二十首  其一五','劉克莊','宋','宋诗','song-poetry','','[]','說向丁男與小姑，各勤耕織了軍需。',32,'全唐诗/poet.song.198000.json','["說向丁男與小姑，各勤耕織了軍需。", "莫教塞北同文軌，却爲江南減賦輸。"]'),
('51e3d4dd-3af1-4d4a-88d8-491ec327244d','端嘉雜詩二十首  其一六','劉克莊','宋','宋诗','song-poetry','','[]','胡來如鬼去如風，哨騎何曾待棗紅。',32,'全唐诗/poet.song.198000.json','["胡來如鬼去如風，哨騎何曾待棗紅。", "峴首一春無使至，興元六月在圍中。"]'),
('183c8c0f-384a-476b-b8f4-9b0c44279b87','端嘉雜詩二十首  其一七','劉克莊','宋','宋诗','song-poetry','','[]','擁旄佩印各榮華，已貴無官可復加。',32,'全唐诗/poet.song.198000.json','["擁旄佩印各榮華，已貴無官可復加。", "若不掃門丞相府，必曾養馬侍中家。"]'),
('fcac9417-5f3d-4005-b7f1-d77949d20263','端嘉雜詩二十首  其一八','劉克莊','宋','宋诗','song-poetry','','[]','蘇衛滅胡同拜爵，裴韓平蔡亦聯鑣。',32,'全唐诗/poet.song.198000.json','["蘇衛滅胡同拜爵，裴韓平蔡亦聯鑣。", "祇今光範門前客，太半河陽幕下寮。"]'),
('8ab9c034-2e6f-46cc-b3d5-2d5ebc953bc2','端嘉雜詩二十首  其一九','劉克莊','宋','宋诗','song-poetry','','[]','元子置人防壁後，穰侯搜客到車中。',32,'全唐诗/poet.song.198000.json','["元子置人防壁後，穰侯搜客到車中。", "鴆杯定不疑羊傅，匕首何曾害魏公。"]'),
('34847e6a-bbf3-4a0b-a045-9fdfd167bb3b','端嘉雜詩二十首  其二○','劉克莊','宋','宋诗','song-poetry','','[]','秺侯世世襲蟬冠，庾氏人人築將壇。',32,'全唐诗/poet.song.198000.json','["秺侯世世襲蟬冠，庾氏人人築將壇。", "但見門中俱貴盛，誰憐陛下最孤寒。"]'),
('df2454d4-8e6c-48e5-87de-55044145a6a7','洛陽橋三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','周時宮室漢時城，廢址遺基剗已平。',32,'全唐诗/poet.song.198000.json','["周時宮室漢時城，廢址遺基剗已平。", "乍見橋名驚老眼，南州安得有西京。"]'),
('f43c0256-3cea-458a-8204-f3a761c25d02','洛陽橋三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','嬴氏曾驅六合人，蔡侯只用一州民。',32,'全唐诗/poet.song.198000.json','["嬴氏曾驅六合人，蔡侯只用一州民。", "立犀豈不賢川守，鞭石何須役海神。"]'),
