('2ee04e1d-c95e-4c8c-9dfd-7e21151b8995','江南五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','鋹也騃孺子，并蛙徒自尊。',24,'全唐诗/poet.song.198000.json','["鋹也騃孺子，并蛙徒自尊。", "如何南武帝，面縛向夷門。"]'),
('c6848972-e409-40bc-9889-26173b9959a4','江南五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','具艦逃安往，焚巢潰不支。',24,'全唐诗/poet.song.198000.json','["具艦逃安往，焚巢潰不支。", "區區一州力，不足辱王師。"]'),
('f55fb600-58ea-40c4-bcf7-943083e2640d','江南五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','宣勸猶疑鴆，龍顔笑引觴。',24,'全唐诗/poet.song.198000.json','["宣勸猶疑鴆，龍顔笑引觴。", "絡鞍奉明主，執梃長降王。"]'),
('134de282-a5e7-446e-abcf-0c3a8d98b290','江南五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','身是假皇帝，國由內太師。',24,'全唐诗/poet.song.198000.json','["身是假皇帝，國由內太師。", "僞朝舊宮殿，歷歷有遺基。"]'),
('b5dbe079-2764-4151-ac0c-85ae256b49da','即事十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','香火萬家市，煙花二月時。',24,'全唐诗/poet.song.198000.json','["香火萬家市，煙花二月時。", "居人空巷出，去賽海神祠。"]'),
('1fb49afb-b10c-4082-b0e2-4e358cd4469e','即事十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','東廟小兒隊，南風大賈舟。',24,'全唐诗/poet.song.198000.json','["東廟小兒隊，南風大賈舟。", "不知今廣市，何似古楊州。"]'),
('b16da148-d953-44a5-b1f9-6fc77e956f03','即事十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','俗情重蒲飲，故事按舟師。',24,'全唐诗/poet.song.198000.json','["俗情重蒲飲，故事按舟師。", "莫倚無山越，閑將作水嬉。"]'),
('4ba9e630-4d38-4c49-8820-3ade05813d88','即事十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','占斷百花白，摘來三伏涼。',24,'全唐诗/poet.song.198000.json','["占斷百花白，摘來三伏涼。", "著身素馨國，荀令未爲香。"]'),
('2951b904-0722-41b3-8f6e-2b59fe9d5813','即事十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','瓜果跽拳祝，㬋羅撲賣聲。',24,'全唐诗/poet.song.198000.json','["瓜果跽拳祝，㬋羅撲賣聲。", "粵人重巧夕，燈火到天明。"]'),
('8fa322ce-c4ce-4de8-b911-a6f9ed3ce6c2','即事十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','名荔絕甘冷，與莆爭長雄。',24,'全唐诗/poet.song.198000.json','["名荔絕甘冷，與莆爭長雄。", "不逢蔡公譜，埋沒瘴煙中。"]'),
('262f42eb-c135-433b-9337-dbf7024c29b2','即事十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','吾生分裂後，不到舊京遊。',24,'全唐诗/poet.song.198000.json','["吾生分裂後，不到舊京遊。", "空作樊樓夢，安知在越樓。"]'),
('a5bf3f37-a8e5-414a-b6e6-d90852cf22aa','即事十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','突薪初不戒，綆缶始言功。',24,'全唐诗/poet.song.198000.json','["突薪初不戒，綆缶始言功。", "累甓爲牆壁，前人智未工。"]'),
('0b373146-3ff9-44f9-bfd6-504dffe190f6','即事十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','復關無雅操，涉洧有遺音。',24,'全唐诗/poet.song.198000.json','["復關無雅操，涉洧有遺音。", "未可繩三尺，檳榔當委禽。"]'),
('cd2e20c5-a0e7-4860-bfdd-f79b685b83f8','即事十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','沐髮眠常晏，濡脣飲不多。',24,'全唐诗/poet.song.198000.json','["沐髮眠常晏，濡脣飲不多。", "誰云五瘴毒，常備四時和。"]'),
('43e4ebf4-c42d-47a7-b934-ad1cc951f46e','藥洲四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','非有干時策，聊爲避地圖。',24,'全唐诗/poet.song.198000.json','["非有干時策，聊爲避地圖。", "昔人補勾漏，老子管仙湖。"]'),
('12d99085-1fa1-45cc-8013-127a113d2b20','藥洲四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','役民如犬馬，國破作降俘。',24,'全唐诗/poet.song.198000.json','["役民如犬馬，國破作降俘。", "往往湖中石，宣和艮嶽無。"]'),
('ead620a8-a34b-4857-b748-cb98ab67cc08','藥洲四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','怪怪奇奇石，誰能辨醜妍。',24,'全唐诗/poet.song.198000.json','["怪怪奇奇石，誰能辨醜妍。", "莫教贊皇見，定輦入平泉。"]'),
('de27ec3d-6546-4f6c-bad9-be4870c309c3','藥洲四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','觀寺臨湖上，亭臺出柳間。',24,'全唐诗/poet.song.198000.json','["觀寺臨湖上，亭臺出柳間。", "都忘來五嶺，將謂在孤山。"]'),
('d38726dd-7c4b-4bb7-acae-636f9a9861df','登城五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','尉佗故秦吏，堪執酇侯鞭。',24,'全唐诗/poet.song.198000.json','["尉佗故秦吏，堪執酇侯鞭。", "箕踞問使者，吾方帝孰賢。"]'),
('e119c4ea-4c9b-4b0a-8687-40a2f0d28b2f','登城五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','已作南夷長，那爲北面臣。',24,'全唐诗/poet.song.198000.json','["已作南夷長，那爲北面臣。", "未忘真定冢，畢竟是華人。"]'),
('71387ca9-10ea-4ea8-9942-182c5063c3ba','登城五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','漢人稱勁粵，累世不加兵。',24,'全唐诗/poet.song.198000.json','["漢人稱勁粵，累世不加兵。", "狂卒纔三百，如何便縋城。"]'),
('b9f3603f-3d3d-4936-b5c7-b66c94ef2027','登城五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','漫費人蒸土，常如物潰堤。',24,'全唐诗/poet.song.198000.json','["漫費人蒸土，常如物潰堤。", "傍疑爲息壤，下恐有蟠泥。"]'),
('db40ed52-55a0-47cd-b5a9-4a6b49029dda','登城五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','郭外皆鯨浸，區中等螘窠。',24,'全唐诗/poet.song.198000.json','["郭外皆鯨浸，區中等螘窠。", "若無西鴈翅，客子奈愁何。"]'),
('537c5edb-40fc-42f2-989a-717d6fe94694','城南','劉克莊','宋','宋诗','song-poetry','','[]','瀕江多海物，比屋盡閩人。',24,'全唐诗/poet.song.198000.json','["瀕江多海物，比屋盡閩人。", "四野方多壘，三間欲卜鄰。"]'),
('3597132c-50db-4367-8a4b-6195cc88a816','題蕭令山則文編二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','繭紙銀鈎寫一通，殷勤投贈愧空空。',64,'全唐诗/poet.song.198000.json','["繭紙銀鈎寫一通，殷勤投贈愧空空。", "轍環晚乃交吾子，稛載天將富此翁。", "著論未容符獨步，操琴欲與愈爭雄。", "兒童錯認眉間喜，疑有珠犀滿篋中。"]'),
('6a2482fc-b7d1-47f5-8ff4-d5ec80cc3a71','題蕭令山則文編二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','咄咄人皆怪老夫，奈何此客去難呼。',64,'全唐诗/poet.song.198000.json','["咄咄人皆怪老夫，奈何此客去難呼。", "招溫處士爲羅否，待穆先生設醴無。", "我有青芻堪秣馬，君言白髮久占烏。", "人生蟬冕腰金印，未抵斑衣膝下娛。"]'),
('75fcf5b8-c9e1-4910-9a75-5a0281ceab8a','題唐察院詩卷二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','細讀公詩屢絕編，心知妙處口難傳。',64,'全唐诗/poet.song.198000.json','["細讀公詩屢絕編，心知妙處口難傳。", "言言箴儆堪垂世，歷歷行藏自譜年。", "但覺朱絃餘倡嘆，不煩玉斧更雕鎸。", "小儒可是通身膽，擬爲坡仙注大全。"]'),
('340f43e4-8b7e-48d3-986b-7a5eb2f30037','題唐察院詩卷二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','不見林夫與子方，坦翁健筆亦堂堂。',64,'全唐诗/poet.song.199000.json','["不見林夫與子方，坦翁健筆亦堂堂。", "孝誠親有終身慕，忠愛君無一飯忘。", "銘座六章韋作佩，入臺五字鐵爲腸。", "未應徑欲投吟社，諫草長留御榻傍。"]'),
('ed202f34-7214-4cd6-86d3-f03d8bb6a185','次黄殿講鳴珮亭','劉克莊','宋','宋诗','song-poetry','','[]','誰引扶胥水入城，循除終日愛琮琤。',64,'全唐诗/poet.song.199000.json','["誰引扶胥水入城，循除終日愛琮琤。", "天風何許珮環響，秋色自然竽籟聲。", "盡洗珠犀寧受涴，少留琴鶴未須行。", "它年父老傳都漕，名與濂翁一樣清。"]'),
('741402bf-ca7b-4434-8f7b-e36fb29cc34d','廣州勸駕一首','劉克莊','宋','宋诗','song-poetry','','[]','番禺文物於今盛，閩浙彬彬未足夸。',64,'全唐诗/poet.song.199000.json','["番禺文物於今盛，閩浙彬彬未足夸。", "丞相宅曾住南郭，鼎魁坊止在東家。", "好陳董子三篇策，莫看唐人一日花。", "珍重詔書相勉意，士先器識後詞華。"]'),
('44c39197-9b19-4917-9f7a-394da58d6950','廣州都試','劉克莊','宋','宋诗','song-poetry','','[]','自昔番禺統府雄，君恩暫許領元戎。',64,'全唐诗/poet.song.199000.json','["自昔番禺統府雄，君恩暫許領元戎。", "不羞短髮垂肩白，且愛前旌照眼紅。", "筆久不靈妨草檄，臂新無力怯開弓。", "即今超距多梟俊，安用輜車載此翁。"]'),
('5ac7b221-1e63-4dd8-9e7d-165c3dc6e77a','燈夕二首呈劉帥  其一','劉克莊','宋','宋诗','song-poetry','','[]','士女如雲服珥鮮，暫陪獵較亦欣然。',64,'全唐诗/poet.song.199000.json','["士女如雲服珥鮮，暫陪獵較亦欣然。", "清於坡老游杭市，儉似乖崖在劍川。", "使指何功煩卜夜，遨頭此念可通天。", "粵人擁道千層看，不見狨鞍三十年。"]'),
('d105deb5-b205-42c9-8da0-6233f6868872','燈夕二首呈劉帥  其二','劉克莊','宋','宋诗','song-poetry','','[]','陌上遊人趁筦絃，豈知君相尚籌邊。',64,'全唐诗/poet.song.199000.json','["陌上遊人趁筦絃，豈知君相尚籌邊。", "細聽野老交談處，猶記兵端未動前。", "草市收燈如許早，端門瞻蹕定何年。", "書生晚抱憂時志，歸畫殘灰理舊編。"]'),
('c19b6229-c4b9-4c23-ad6b-35dafbca8f46','次韻二首併呈倉使  其一','劉克莊','宋','宋诗','song-poetry','','[]','晚霧徐收月色鮮，承平物態尚依然。',64,'全唐诗/poet.song.199000.json','["晚霧徐收月色鮮，承平物態尚依然。", "斷無颶母起吹海，應有蚌胎還媚川。", "遠俗熙恬猶樂土，孤臣流落謾憂天。", "夜歸聽得輿人語，且願新年勝舊年。"]'),
('ad459c62-aa90-4718-b279-64fc489a080b','次韻二首併呈倉使  其二','劉克莊','宋','宋诗','song-poetry','','[]','歸念常如危柱絃，春來夢繞白雲邊。',64,'全唐诗/poet.song.199000.json','["歸念常如危柱絃，春來夢繞白雲邊。", "不知新雪添頭上，但見繁星滿目前。", "即事有詩聊記節，捄時無策但祈年。", "二公語妙堪傳遠，嚴杜何因可共編。"]'),
('a0b79444-0b3f-4501-9955-d83c9cb1c745','余哭蟾子潮士鍾大鳴有詩相寬次韻  其一','劉克莊','宋','宋诗','song-poetry','','[]','愁眉暫展頼君詩，欲以先知覺後知。',64,'全唐诗/poet.song.199000.json','["愁眉暫展頼君詩，欲以先知覺後知。", "歷引竺乾寬此老，未甘嬴博窆吾兒。", "寄阿蘭若俄經昔，祔短松岡會有期。", "欲訪巫咸何處在，憂來自向理中推。"]'),
('eedf8131-3f98-475b-80eb-15bc665a6d7f','余哭蟾子潮士鍾大鳴有詩相寬次韻  其二','劉克莊','宋','宋诗','song-poetry','','[]','彭聃俱未離乎死，况汝孩提未有知。',64,'全唐诗/poet.song.199000.json','["彭聃俱未離乎死，况汝孩提未有知。", "自昔丈夫憐少子，即今王母惜孫兒。", "探環尚記曾遊處，建鼓應無再見期。", "三紀七揮兒女淚，孰尸壽夭莽難推。"]'),
('e27cc88c-f2de-40d3-bad0-8ae1fce8b018','蒲澗寺','劉克莊','宋','宋诗','song-poetry','','[]','齊人陳跡此流傳，班史蘇詩豈必然。',64,'全唐诗/poet.song.199000.json','["齊人陳跡此流傳，班史蘇詩豈必然。", "故老皆言家即寺，癡兒誤入海求僊。", "莫將劉項分羹鼎，來涴巢由洗耳泉。", "欲採菖蒲無覓處，且隨簫鼓樂新年。"]'),
('1deb4a06-ce1a-46bd-9a6e-93a001027553','越臺','劉克莊','宋','宋诗','song-poetry','','[]','南帝當年此築臺，稱雄亦豈偶然哉。',64,'全唐诗/poet.song.199000.json','["南帝當年此築臺，稱雄亦豈偶然哉。", "謾通異國求陽燧，不道偷兒飲漆杯。", "能使越人存舊跡，始知秦吏有奇才。", "祇今黄屋歸何處，但見牛羊夕下來。"]'),
('fdb5f407-afb4-4a2d-a5c1-70fc7b464277','次韻劉帥出郊一首','劉克莊','宋','宋诗','song-poetry','','[]','競逐朱轓載酒行，熙熙物態與人情。',64,'全唐诗/poet.song.199000.json','["競逐朱轓載酒行，熙熙物態與人情。", "浴沂我欲尋儒服，涉洧公方厭鄭聲。", "試問冶容遨夜市，何如赤脚饁春耕。", "故山瓜圃應無恙，老去深知愧邵平。"]'),
('56e0fc4a-fb43-4c07-80ae-0f1af37eb3cc','次韻李倉春遊一首','劉克莊','宋','宋诗','song-poetry','','[]','秧馬從今漸可行，林鳩未好便呼晴。',64,'全唐诗/poet.song.199000.json','["秧馬從今漸可行，林鳩未好便呼晴。", "敢云使者乘軺傳，聊爲君王式耦耕。", "有一日留憂職曠，無三宿戀覺身輕。", "此生不復持高論，願友臺佟與尚平。"]'),
('bc711380-c001-48e7-af46-b223acf3c422','挽崔丞相三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','先帝謀元帥，煩公護蜀淮。',48,'全唐诗/poet.song.199000.json','["先帝謀元帥，煩公護蜀淮。", "軍皆歌范老，民各像乖崖。", "北顧猶關慮，西歸已卷懷。", "早令扶日月，寧不掃氛霾。"]'),
('acae6fe7-dde0-4564-80f2-c2128b4ec710','挽崔丞相三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','麻卷揚庭久，蒲輪就道遲。',48,'全唐诗/poet.song.199000.json','["麻卷揚庭久，蒲輪就道遲。", "虛傳楊綰用，不奈蔡謨辭。", "祝柱從渠誚，摧梁得許悲。", "流傳千載下，猶足勵清規。"]'),
('ad4a23cd-4c89-4346-b4d2-cf983ff957c8','挽崔丞相三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','昔侍瓊花宴，回頭二紀餘。',48,'全唐诗/poet.song.199000.json','["昔侍瓊花宴，回頭二紀餘。", "嵇康作書懶，魏勃掃門疎。", "尚意開黄閣，安知尾素車。", "蕭然旋馬第，人指相君居。"]'),
('d06abc52-72a6-4bf0-b25d-0fe85e3820b7','陸賈二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','田橫死士今亡矣，陳豨從車安在哉。',32,'全唐诗/poet.song.199000.json','["田橫死士今亡矣，陳豨從車安在哉。", "獨有尉佗尚黄屋，故應兩費陸生來。"]'),
('477050b3-1993-4366-985e-3bda29286e11','陸賈二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','酈烹未久蒯幾烹，陸子優游享令名。',32,'全唐诗/poet.song.199000.json','["酈烹未久蒯幾烹，陸子優游享令名。", "南帝稱臣橐金返，更推餘智教陳平。"]'),
('a2990075-bfdf-400c-ad61-d3c260b489dc','浴日亭一首','劉克莊','宋','宋诗','song-poetry','','[]','歸客飄然一葉身，尚能飛屐陟嶙峋。',64,'全唐诗/poet.song.199000.json','["歸客飄然一葉身，尚能飛屐陟嶙峋。", "危亭下瞰嵎夷宅，積水上通河漢津。", "叱馭爲臣前有志，乘桴從我更無人。", "暮年筆力全衰退，甘與韓蘇作後塵。"]'),
('7d148c6c-82e1-41fa-97a1-e0eb96d281f9','又追和坡韻一首','劉克莊','宋','宋诗','song-poetry','','[]','亭傍喬木拂雲天，亭下高桅泊晚灣。',64,'全唐诗/poet.song.199000.json','["亭傍喬木拂雲天，亭下高桅泊晚灣。", "白是張騫曾泛水，青疑徐福所求山。", "羊城隔霧愁回首，鯨浸收風喜見顔。", "却笑金烏并玉兔，辛勤出沒雪濤間。"]'),
('59c58d49-43be-4b75-ba73-7a8d8f95b1c2','白鶴故居','劉克莊','宋','宋诗','song-poetry','','[]','天稔中原禍，朝分黨部爭。',48,'全唐诗/poet.song.199000.json','["天稔中原禍，朝分黨部爭。", "當年誰宰相，此地著先生。", "故國難歸去，新巢甫落成。", "如何鯨浸外，更遣打包行。"]'),
('49fd6961-a5c9-4364-9e59-8d3678e5efb0','唐博士祠','劉克莊','宋','宋诗','song-poetry','','[]','博士位尤卑，投名入黨碑。',48,'全唐诗/poet.song.199000.json','["博士位尤卑，投名入黨碑。", "今觀名世作，多在謫官時。", "太史沅湘筆，儀曹永柳詩。", "新祠綿蕞爾，未盡復遺基。"]'),
('028af7c7-14e1-4733-bb79-b7daeb829fbe','六如亭','劉克莊','宋','宋诗','song-poetry','','[]','吳兒解記真娘墓，杭俗猶存蘇小墳。',32,'全唐诗/poet.song.199000.json','["吳兒解記真娘墓，杭俗猶存蘇小墳。", "誰與惠州耆舊說，可無抔土覆朝雲。"]'),
('afbdecf5-f116-40ab-87ab-c6b26ac99426','再題六如亭','劉克莊','宋','宋诗','song-poetry','','[]','昔人喜說墜樓姬，前輩尤高斷臂妃。',32,'全唐诗/poet.song.199000.json','["昔人喜說墜樓姬，前輩尤高斷臂妃。", "肯伴主君來過嶺，不妨扶起六如碑。"]'),
('53205bd0-225a-4f0d-b1ee-2c7c96d1b364','十五里沙','劉克莊','宋','宋诗','song-poetry','','[]','只見如山白浪飛，更堪動地黑風吹。',64,'全唐诗/poet.song.199000.json','["只見如山白浪飛，更堪動地黑風吹。", "渺茫直際九州外，洶湧常如八月時。", "河伯豈能窮海若，靈胥僅可嚇吳兒。", "惜無散髮騎鯨友，共了南游一段奇。"]'),
('844e3a4e-1df5-4aac-bc6f-6c763d6df9b9','道中讀孚若題壁有感用其韻','劉克莊','宋','宋诗','song-poetry','','[]','淮雪江風裂面寒，往來萬里一征鞍。',64,'全唐诗/poet.song.199000.json','["淮雪江風裂面寒，往來萬里一征鞍。", "三千客謾曾彈鋏，十九人誰肯捧盤。", "自古英才多頓挫，只今世運尚艱難。", "空餘敗壁龍蛇字，黄鵠高飛不復還。"]'),
('6399daad-236c-48e4-a00d-c3cb20789fe4','送項使君季約二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','世有凝香樂，君侯總未知。',48,'全唐诗/poet.song.199000.json','["世有凝香樂，君侯總未知。", "清齋燈火夕，閉閤荔支時。", "郡小留難住，民愚去始思。", "兩年案頭筆，一字不容私。"]'),
('d58ad35f-cc4c-4b47-badd-e3f3a9815d62','送項使君季約二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','但見兩眉顰，何曾一饌珍。',48,'全唐诗/poet.song.199000.json','["但見兩眉顰，何曾一饌珍。", "節如僧更苦，家比郡尤貧。", "琴鶴均爲贅，蓴鱸頗切身。", "蕩山有來鴈，莫惜寄聲頻。"]'),
('5dbc8dc4-5f20-43ca-8b92-8559d4274dbd','送王梅州二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','州境與潮鄰，徐行止浹旬。',48,'全唐诗/poet.song.199000.json','["州境與潮鄰，徐行止浹旬。", "瘴鄉均一氣，鹽子亦吾民。", "日晏煙嵐歛，兵餘戶口貧。", "定將田里事，閉閤細條陳。"]'),
('7abc3ecf-1f44-4fd8-897c-95c5524008aa','送王梅州二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','禍始自三槍，菑猶被一方。',48,'全唐诗/poet.song.199000.json','["禍始自三槍，菑猶被一方。", "帝將安渤海，君肯薄淮陽。", "老手何憂斲，新眉尚費粧。", "漢庭褒郡最，蚤晚入爲郎。"]'),
('4d0b4f58-a5e3-4f0e-b2c1-da81fd895b07','癸卯上元即席次楊使君韻二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','初陽收久雨，淳祐第三春。',48,'全唐诗/poet.song.199000.json','["初陽收久雨，淳祐第三春。", "聊與衆行樂，稍欣農食新。", "俱蒙青帝力，莫問紫姑神。", "座上遨頭作，流傳遍郡人。"]'),
('7dc9bb9b-4bc6-4f60-a452-c05da3e5dfdd','癸卯上元即席次楊使君韻二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','縱觀姑遊目，殷憂欲碎心。',48,'全唐诗/poet.song.199000.json','["縱觀姑遊目，殷憂欲碎心。", "馬嘶淮祲惡，鵑叫蜀冤深。", "玉座方停箸，椒塗亦脫簪。", "好爲諫臣論，莫作醉翁吟。"]'),
('57f75009-b8a5-40cf-b4ab-a774224a69e3','辛卯春日','劉克莊','宋','宋诗','song-poetry','','[]','甫報弓旌召，俄聞彈射攻。',48,'全唐诗/poet.song.199000.json','["甫報弓旌召，俄聞彈射攻。", "匹如飲甘露，又似斬春風。", "雲夢吞伊輩，須彌納箇中。", "故山多芧栗，不必問狙公。"]'),
('7f74e335-b4c6-47af-bfc9-70f48bffa8b0','挽林煥章二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','昔在端平際，臨朝想老成。',48,'全唐诗/poet.song.199000.json','["昔在端平際，臨朝想老成。", "但聞轅固召，不見伏生行。", "霜柏無寒暑，朝華有悴榮。", "由來天所靳，上壽與高名。"]'),
('485be53b-25b8-4db0-a340-b3d635f2bb6e','挽林煥章二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','束帛徵諸老，深衣立一儒。',48,'全唐诗/poet.song.199000.json','["束帛徵諸老，深衣立一儒。", "鄉人偕獵較，童子共風雩。", "屑屑羞來往，兢兢迨舉扶。", "自慚衰竭久，書墓覺詞蕪。"]'),
('da5dd73f-a6de-4233-a5f6-6e4ec7fc0d2e','送趙阜主簿','劉克莊','宋','宋诗','song-poetry','','[]','罷稅無兼局，蕭然古廨寒。',48,'全唐诗/poet.song.199000.json','["罷稅無兼局，蕭然古廨寒。", "士稱爲善類，民說是清官。", "力薄難推轂，身輕易起單。", "竹林逢大阮，試爲問平安。"]'),
('80f46201-8139-4940-9a84-adb50999e71d','挽游勉之侍郎二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','不假橫金貴，居然比玉溫。',48,'全唐诗/poet.song.199000.json','["不假橫金貴，居然比玉溫。", "諸公從上雍，一老立東門。", "伯氏推難弟，先師有嫡孫。", "耆英凋落盡，舊事向誰論。"]'),
('d878aeb3-f2a8-494e-85af-cb1cefb7a0f2','挽游勉之侍郎二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昔在高陽里，曾登夫子堂。',48,'全唐诗/poet.song.199000.json','["昔在高陽里，曾登夫子堂。", "武城愧言偃，畏壘化庚桑。", "病臂書全闕，驚心鑑忽亡。", "平生芻一束，道遠不能將。"]'),
('ab09c2f6-2f05-4075-aca2-045ff8617891','挽唐伯玉常卿二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','身自無安處，昇州更廣州。',48,'全唐诗/poet.song.199000.json','["身自無安處，昇州更廣州。", "逐教子方去，死到了翁休。", "鳳至虞廷喜，麟亡魯野愁。", "憂時兼悼友，白却九分頭。"]'),
('7f283ef7-5c92-476d-9aac-2a3ffb5ddb8c','挽唐伯玉常卿二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','久欲携蓴鯽，呻吟去未能。',48,'全唐诗/poet.song.199000.json','["久欲携蓴鯽，呻吟去未能。", "甫封陶母墓，俄吊董生陵。", "言立何曾死，騷招更不譍。", "那須論宿草，身盡淚方冰。"]'),
('49fb7a36-bb54-48ac-8802-7f8daa7620c8','送居厚弟堂稟二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','俱被光華遣，同歸寂寞濱。',48,'全唐诗/poet.song.199000.json','["俱被光華遣，同歸寂寞濱。", "吾災因抱槧，子咎在埋輪。", "記憶煩明主，招徠到遠臣。", "要須留晚節，它日白先人。"]'),
('64a541a7-a697-4325-88af-74503d292ce4','送居厚弟堂稟二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','怕與親朋別，那堪送子行。',48,'全唐诗/poet.song.199000.json','["怕與親朋別，那堪送子行。", "天威難俟駕，秋暑勿貪程。", "若見知名士，爲言不慧兄。", "孤危托君相，耕釣畢殘生。"]'),
('013cc11b-908b-4e6b-ba44-c9a5f8055f9a','居厚不果行次韻二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','物色來林下，安排起海濱。',48,'全唐诗/poet.song.199000.json','["物色來林下，安排起海濱。", "居然蒙錦穽，幸未駕蒲輪。", "非我瑕疵女，云誰毀譽臣。", "只愁從此去，未易致虞人。"]'),
('02132884-ee36-4a19-8d22-b9c56a4df695','居厚不果行次韻二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','祖帳方涓吉，公車已尼行。',48,'全唐诗/poet.song.199000.json','["祖帳方涓吉，公車已尼行。", "若非露消息，未免迫期程。", "水菽姑娛母，茅柴且酌兄。", "未應天祿閣，便欠一更生。"]'),
('281e85e0-3b98-4cf5-9f90-1156e0474a5b','聞居厚得祠復次韻二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','諸賢談稷下，孤士卧漳濱。',48,'全唐诗/poet.song.199000.json','["諸賢談稷下，孤士卧漳濱。", "母亦爲投杼，兒宜勿斲輪。", "無書留逐客，有些吊纍臣。", "一室纔容榻，奚煩問疾人。"]'),
('f54cca66-5d00-44c0-8f3a-6c36cdef2074','聞居厚得祠復次韻二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','稍欣公議白，又報嘖言行。',48,'全唐诗/poet.song.199000.json','["稍欣公議白，又報嘖言行。", "上漫招東馬，人方毀李程。", "迎來新觀主，伴取老師兄。", "漢士方雲合，何須魯兩生。"]'),
('784c0cb4-279d-41f1-a75d-b2bd4c951268','贈蜀士盧石受二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','蜀郡盧夫子，沉冥不偶時。',48,'全唐诗/poet.song.199000.json','["蜀郡盧夫子，沉冥不偶時。", "幽深病梨賦，奇怪磔蟇詩。", "古有嚴并李，今無曠與夔。", "何當短檠下，歷歷叩羣疑。"]'),
('4fcf01f6-7822-4771-a796-983fc4742381','贈蜀士盧石受二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','井絡纏兵慘，瞿塘下棹輕。',48,'全唐诗/poet.song.199000.json','["井絡纏兵慘，瞿塘下棹輕。", "命寧一錢直，腹載五車行。", "姑覽無諸跡，休聽望帝聲。", "世無韓十八，誰識玉川生。"]'),
('ba2f425f-9bc6-4ab1-9822-ac815eba751a','送陳霆之官連州','劉克莊','宋','宋诗','song-poetry','','[]','郡接湖南境，孤城若箇邊。',48,'全唐诗/poet.song.199000.json','["郡接湖南境，孤城若箇邊。", "茆寮愁問宿，峽石善驚船。", "官小無迎吏，詩工有續編。", "古人高妙處，不過覽山川。"]'),
('c54ce494-23db-4a56-8886-410f9f0bf6a2','挽林承奉','劉克莊','宋','宋诗','song-poetry','','[]','性與聃書合，平生寶儉慈。',48,'全唐诗/poet.song.199000.json','["性與聃書合，平生寶儉慈。", "鹿門妻采藥，蟾窟子攀枝。", "君可先賢傳，吾慙幼婦碑。", "衰年窘才思，呵凍課哀詩。"]'),
('ae8610bc-c535-426d-8074-c4e0d1f1e6dd','挽姚漕貴叔','劉克莊','宋','宋诗','song-poetry','','[]','昔建經離亂，煩公出拊循。',48,'全唐诗/poet.song.199000.json','["昔建經離亂，煩公出拊循。", "魯宮恢故宇，蔡卒即吾人。", "薏苡何傷我，甘棠尚在民。", "悲哉元日召，當宁記名臣。"]'),
('f061e1fc-32d2-42d0-97a1-cc5b4327171b','挽開國陳寺丞二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','昨御祥琴後，多傳吉語通。',48,'全唐诗/poet.song.199000.json','["昨御祥琴後，多傳吉語通。", "虛令占列宿，不料奏悲風。", "華表孫從祖，生芻壻吊翁。", "九原一無憾，全璧見先公。"]'),
('55f1717d-39fb-4a04-8694-bb426299a2cc','挽開國陳寺丞二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','伯也不可作，叔兮猶典刑。',48,'全唐诗/poet.song.199000.json','["伯也不可作，叔兮猶典刑。", "公車玉堂薦，書室鶴山銘。", "久上通侯印，新營太祝廳。", "衰年親舊少，吟罷涕先零。"]'),
('8dea93bd-0904-4411-85a3-bf66e230c8cb','挽王居之寺丞二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','元老登庸晚，同年召用初。',48,'全唐诗/poet.song.199000.json','["元老登庸晚，同年召用初。", "惜哉武公耄，甚矣董生迂。", "汾曲廬旋返，平津閤寖疎。", "空令雙鬢白，猶待兩輪朱。"]'),
('7b4c8bb7-9293-4737-bd3c-f00d7e308795','挽王居之寺丞二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','憶昔陪真率，華居甫落成。',48,'全唐诗/poet.song.199000.json','["憶昔陪真率，華居甫落成。", "坐賓來墮幘，侍女出彈箏。", "無復吳趨曲，空餘楚些聲。", "九泉見忠簡，應問老門生。"]'),
('f8e98fed-8bd6-4a0d-9da5-5cf61da359fd','挽方𥳞貢士','劉克莊','宋','宋诗','song-poetry','','[]','秋賦曾賓送，春卿偶脫遺。',48,'全唐诗/poet.song.199000.json','["秋賦曾賓送，春卿偶脫遺。", "離羣嗟老境，同隊記兒時。", "終制從家禮，高懷見墓碑。", "亦如陶處士，自作誄兼詩。"]'),
('41f271bf-2d89-4bfd-b2bd-91c230790321','題永嘉黄仲炎文卷二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','書坊黄冊誘兒童，朝取封侯夕拜公。',64,'全唐诗/poet.song.199000.json','["書坊黄冊誘兒童，朝取封侯夕拜公。", "賈董奇材無地立，歐蘇精鑒與人同。", "安知李廌麾門外，不覺劉幾入彀中。", "蚤晚君王求極諫，莫教豪傑泣途窮。"]'),
('3f2ecb0f-5087-4208-bc71-a8cdeb608bfe','題永嘉黄仲炎文卷二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','龍泉筆絕文章熄，此作居然可貴珍。',64,'全唐诗/poet.song.199000.json','["龍泉筆絕文章熄，此作居然可貴珍。", "激處飜嫌董生緩，新來却笑退之陳。", "假令覆瓿無知者，尚可藏山待後人。", "外物區區均糞土，祝君愛取不貲身。"]'),
('9ce5d6fd-3584-43f2-9c52-7ed56a166e89','和吳教授投贈二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','三徑荒涼手自開，旋移花竹剪蒿萊。',64,'全唐诗/poet.song.199000.json','["三徑荒涼手自開，旋移花竹剪蒿萊。", "休休豈不緣迂惰，屑屑何爲費往來。", "明主祇今蒐墜典，故人太半客翹材。", "纍臣方卧漳濱疾，錯夢鈞天聽樂迴。"]'),
('20f892ae-e168-45cb-b273-b2345eb95809','和吳教授投贈二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','衮衮登瀛更上坡，且容老子釣煙波。',64,'全唐诗/poet.song.199000.json','["衮衮登瀛更上坡，且容老子釣煙波。", "鳳麟自合呈祥瑞，鳧鴈何曾繫少多。", "時有耦耕人共語，亦無問字客相過。", "倒囊欲答驪珠贈，柰此家徒四壁何。"]'),
('4f8bf07b-95c1-4da6-82ec-e7646d273517','和張簡簿尉韻','劉克莊','宋','宋诗','song-poetry','','[]','舊案依俙在柏臺，寄聲杭本莫翻開。',64,'全唐诗/poet.song.199000.json','["舊案依俙在柏臺，寄聲杭本莫翻開。", "騎馿導從兩黥挾，羅爵門庭幾客來。", "務觀可堪供史草，補之不會作宮梅。", "男兒盍建橫行策，免使君王歎乏材。"]'),
('4208a8af-9b90-4805-8f9a-5f37c04617f0','用王去非侍郎韻二首送林元質提幹秩滿造朝併呈侍郎  其一','劉克莊','宋','宋诗','song-poetry','','[]','戍滿歸來薇亦剛，策名不覺十年彊。',64,'全唐诗/poet.song.199000.json','["戍滿歸來薇亦剛，策名不覺十年彊。", "素無沂國三場志，曾有西山一瓣香。", "晁董未能免科舉，孔顔方可語行藏。", "要爲天下奇男子，寧論區區國與鄉。"]'),
('b0ed0c2e-46a4-4e76-ba26-6dc7e22130b9','用王去非侍郎韻二首送林元質提幹秩滿造朝併呈侍郎  其二','劉克莊','宋','宋诗','song-poetry','','[]','叔季滔滔未見剛，每聞健論意差强。',64,'全唐诗/poet.song.199000.json','["叔季滔滔未見剛，每聞健論意差强。", "向來曾劾燈籠錦，老去聊凝畫戟香。", "世運橫流安所止，聖朝未舍豈容藏。", "幾回欲上鈴齋謁，衰病無因可去鄉。"]'),
('a1fe0bef-5016-4dfd-9d1a-f1311c2f1365','送李用之察院赴潮州二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','烏府名臣暫擁麾，霜稜聊復變春熙。',64,'全唐诗/poet.song.199000.json','["烏府名臣暫擁麾，霜稜聊復變春熙。", "行人猶謂驄當避，聖世初無鱷可移。", "粵俗相携看上日，韓祠配食付它時。", "極知不作周南滯，禁闥須君補闕遺。"]'),
('0489a3a9-471e-46a8-9d31-c44b898abe15','送李用之察院赴潮州二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昔在番禺鬻筴時，瞽言不敢計從違。',64,'全唐诗/poet.song.199000.json','["昔在番禺鬻筴時，瞽言不敢計從違。", "固知國有三空患，又欲民無再榷譏。", "篛裹爲生尤瘠薄，牙籌所積恐纖微。", "公卿文學方矛盾，應待囊封决是非。"]'),
('66d6dd8d-48b8-4cf1-8ad2-159f923104d1','賀王實之得第二子','劉克莊','宋','宋诗','song-poetry','','[]','臞翁活計未全迂，老驥新生汗血駒。',64,'全唐诗/poet.song.199000.json','["臞翁活計未全迂，老驥新生汗血駒。", "攀桂肯輸郎罷否，分梨還讓阿兄無。", "應陳俎豆爲嬉戲，想見詩書被抹塗。", "報與厨人多釀酒，王家例合有三珠。"]'),
('d79aad45-b1d3-4224-8b80-ab38140e7864','送方蒙仲赴省','劉克莊','宋','宋诗','song-poetry','','[]','童年觜距已專場，何况而今益老蒼。',64,'全唐诗/poet.song.199000.json','["童年觜距已專場，何况而今益老蒼。", "天網恢然罩鸞鵠，朝陽鳴矣革蜩螗。", "士誰與賀爭同進，衆亦推弘詣太常。", "可惜祠官無氣力，不能搢笏誦阿房。"]'),
('53a862d2-0ea4-4721-abe5-852b287e1f5b','書事二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','謙之紼翣迎歸福，平甫灰釘送返莆。',64,'全唐诗/poet.song.199000.json','["謙之紼翣迎歸福，平甫灰釘送返莆。", "空累兩家營後事，僅留四壁遺諸孤。", "學徒誰是單傳者，史藁曾經乙覽無。", "貧富皆當終牖下，招魂何處有神巫。"]'),
('536f0549-46d5-454f-92a9-b553c1dcc1e4','書事二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','二士平生極好修，簞瓢之外尚何求。',64,'全唐诗/poet.song.199000.json','["二士平生極好修，簞瓢之外尚何求。", "暮年更傍誰門戶，故國寧無某水丘。", "華簀殊非愛曾子，短衾自可覆黔婁。", "小車處士差安穩，十二行窩取次游。"]'),
('7e29fcd4-98af-4c53-94a1-3282e6e92284','送葉士巖二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','曾約還轅訪爵羅，幾迴掃榻佇經過。',64,'全唐诗/poet.song.199000.json','["曾約還轅訪爵羅，幾迴掃榻佇經過。", "待先生敬雖如此，與老人期柰後何。", "走馬看花消許急，殺雞爲黍誤儂多。", "吳中故舊還相問，一臂偏枯兩鬢皤。"]'),
('1de4ed43-9d0c-49db-80bc-489681a5bc42','送葉士巖二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','向來參請徧諸方，恍惚如癡亦似狂。',64,'全唐诗/poet.song.199000.json','["向來參請徧諸方，恍惚如癡亦似狂。", "雪與膝平猶未退，斤從鼻過了無傷。", "拈花弟子知誰悟，撼樹羣兒不自量。", "極欲爲君露消息，天寒日短話頭長。"]'),
('7503e0ce-68a5-407b-9942-ca85e39cb377','甲辰春日二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','買牛搜粟向蠻煙，衰病安知璧偶全。',64,'全唐诗/poet.song.199000.json','["買牛搜粟向蠻煙，衰病安知璧偶全。", "使者召歸曾四輩，臣之得罪又三年。", "柳劉漏語誰云爾，絳灌憐才定不然。", "縱使有泉堪洗耳，先生此愧若爲湔。"]'),
('4b7baccb-10bb-4343-b993-a2d61dff6a1b','甲辰春日二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','學問過時已悍堅，文章垂老未精專。',64,'全唐诗/poet.song.199000.json','["學問過時已悍堅，文章垂老未精專。", "薰琴何患無賡載，秋扇明知有棄捐。", "舊讀溫尋渾不記，新吟鍛鍊久方圓。", "此生幸不當詞翰，免被人嘲上水船。"]'),
('d1f5709a-e4c8-48e6-bcc3-25e5e22bc840','題小室二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','已向深林卓小庵，是中僅可著禪龕。',64,'全唐诗/poet.song.199000.json','["已向深林卓小庵，是中僅可著禪龕。", "士師何止三無慍，中散居然七不堪。", "一去重華那復得，方當盛漢勿多談。", "近來弟子俱行脚，誰伴山僧面壁參。"]'),
('59ad49cd-c395-4e9d-a8da-20861e7794ef','題小室二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','阡陌東西山北南，半生常带散人銜。',64,'全唐诗/poet.song.199000.json','["阡陌東西山北南，半生常带散人銜。", "何曾雲夢芥八九，一任狙公芧四三。", "閤上大夫投欲死，甕間吏部寢方酣。", "可憐子駿無家法，下見先人面有慚。"]'),
('60eb4fbc-cb0d-49d8-8b32-8eb9c8c4bf8b','送表弟方時父','劉克莊','宋','宋诗','song-poetry','','[]','棄置空村飽世情，高軒乃肯顧柴荆。',64,'全唐诗/poet.song.199000.json','["棄置空村飽世情，高軒乃肯顧柴荆。", "韓甥殷浩貧親戚，李益盧綸外弟兄。", "兩鬢蕭疎驚老大，一燈明滅話平生。", "刺桐花下逢予季，多致詩人未害清。"]'),
('9c2fe65e-de0a-4907-b42c-43958c2ad307','葉桂發助教從李用之祕監于潮陽李持節使廣部葉辭歸福唐小詩話別','劉克莊','宋','宋诗','song-poetry','','[]','賀監空多惜別情，木綿花得似三荆。',64,'全唐诗/poet.song.199000.json','["賀監空多惜別情，木綿花得似三荆。", "打包便是參禪客，垂橐何須使鬼兄。", "小郭今寧無趙子，四門古亦有歐生。", "南轅不涉貪泉境，歸去詩腸徹底清。"]'),
('f97255aa-fc08-4c8f-828e-fbcb76e03ae3','寄題建陽馬氏晚香堂','劉克莊','宋','宋诗','song-poetry','','[]','自鉏空曠汲潺湲，占斷清溪第幾灣。',64,'全唐诗/poet.song.199000.json','["自鉏空曠汲潺湲，占斷清溪第幾灣。", "傍九日開侵歲晏，居千花殿覺天慳。", "餐英飲露平生事，遺臭流芳一念間。", "菊不負君君負菊，年年秋不在家山。"]'),
('988914e4-1c61-47a3-96e2-554ff3cc02c5','贈施道州二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','施先生學有源流，家自長安徙益州。',64,'全唐诗/poet.song.199000.json','["施先生學有源流，家自長安徙益州。", "疇昔建牙當一面，祇今失國託諸侯。", "身僑嶽麓無生計，目斷岷峨起暮愁。", "聞道漢廷須黼黻，蜀珍那得此淹留。"]'),
('01674f39-9bd2-4afb-8b57-41ca6078356b','贈施道州二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','胡塵突過劍門關，西顧于今尚未寬。',64,'全唐诗/poet.song.199000.json','["胡塵突過劍門關，西顧于今尚未寬。", "早晚相如通僰道，蒼皇子美問長安。", "拮据自笑營巢拙，枘鑿明知合轍難。", "縱有望鄉樓百尺，淡煙衰草莫凭欄。"]'),
('b6080fd6-801c-4285-8678-266ef7619a05','送楊彥極提刑二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','閩蜀相望萬里遥，敢圖斗壘屈魁杓。',64,'全唐诗/poet.song.199000.json','["閩蜀相望萬里遥，敢圖斗壘屈魁杓。", "南州處士蒙殊禮，魏府牙兵不更驕。", "邦伯如今安得結，國人它日會思僑。", "瓣香垂去猶精禱，果有甘霖溉旱苗。"]'),
('85aa90e0-4429-486b-9516-b499ac113b27','送楊彥極提刑二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','繡斧翩翩向福唐，百城歛衽避風霜。',64,'全唐诗/poet.song.199000.json','["繡斧翩翩向福唐，百城歛衽避風霜。", "夢迴桑下初何戀，手植棠陰故未忘。", "判筆有神皆可錄，抄書無數即行裝。", "從今病叟牢扃戶，莫望嚴公訪草堂。"]'),
('ec3358e1-964c-41dc-b87c-49dfe9306ed2','題陳霆詩卷','劉克莊','宋','宋诗','song-poetry','','[]','讀它人作多遺恨，君似連城璧少瑕。',64,'全唐诗/poet.song.199000.json','["讀它人作多遺恨，君似連城璧少瑕。", "楮葉國工如許刻，菖蒲靈物偶然花。", "今無摩詰携同宿，後有荆公選百家。", "不惜矮窗殘燭下，與將朱筆擷菁華。"]'),
('06ede129-124f-46a9-aee8-b27ec484f214','夢方孚若二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','仙鬼微茫果是非，不如遼鶴有歸期。',64,'全唐诗/poet.song.199000.json','["仙鬼微茫果是非，不如遼鶴有歸期。", "鑄成范蠡何嗟及，繡作平原未必知。", "歌扇舞裙風雨散，野田荒草古今悲。", "可憐一覺寒窗夢，猶記聯鞍出塞時。"]'),
('087a20b1-03ef-4afa-ad1f-0b2d9811eb63','夢方孚若二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','寤寐中原獨著鞭，往來絕域幾餐氈。',64,'全唐诗/poet.song.199000.json','["寤寐中原獨著鞭，往來絕域幾餐氈。", "封侯反出李蔡下，成佛却居靈運先。", "八百里烹饗軍炙，九千縑輦作碑錢。", "祇今誰是田橫客，回首荒丘一慨然。"]'),
('9c0e7bd6-46c1-44f5-a905-30f8c28bdbf6','哭孫季蕃二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','歲晚湖山寄幅巾，浩然不見兩眉顰。',64,'全唐诗/poet.song.199000.json','["歲晚湖山寄幅巾，浩然不見兩眉顰。", "看花李益無同伴，顧曲周郎有後身。", "厚祿殷勤營葬地，隠君歡喜得吟鄰。", "看來造物於君厚，判斷風光七十春。"]'),
('ed2f6f7f-98b2-4292-b620-663c642c2bbf','哭孫季蕃二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','每歲鶑花要主盟，一生風月最關情。',64,'全唐诗/poet.song.199000.json','["每歲鶑花要主盟，一生風月最關情。", "相君未識陳三面，兒女多知柳七名。", "自有菊泉供祭享，不消麥飯作清明。", "老身獨殿諸人後，吟罷無端雪涕橫。"]'),
('34a37020-e99a-443f-b602-bd61fc2d493e','懷曾景建二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','造物生才自昔難，此君夭矯類龍鸞。',64,'全唐诗/poet.song.199000.json','["造物生才自昔難，此君夭矯類龍鸞。", "聖賢本柄藏椰子，佛祖機鋒寓棘端。", "疇昔諸人多北面，暮年萬里著南冠。", "傷心海內交游盡，篋有遺書不忍看。"]'),
('003de0dd-efff-4a9b-9ccd-ed8f5dccdd32','懷曾景建二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','曾有舂陵逐客篇，流傳哀動紫陽仙。',64,'全唐诗/poet.song.199000.json','["曾有舂陵逐客篇，流傳哀動紫陽仙。", "安知太白長流處，亦在重華野葬邊。", "碎板一如坡貶日，蓋棺不見檜薨年。", "誰云老眼枯無涕，聞說臨川即泫然。"]'),
('6eec98dd-f6f9-4b65-85a4-c15e1dc337ca','內翰洪公舜俞哀詩二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','憶昔端平典冊新，三麻九制筆如神。',64,'全唐诗/poet.song.199000.json','["憶昔端平典冊新，三麻九制筆如神。", "內庭喚作真學士，晚輩推爲老舍人。", "垂死遺言尤苦口，平生諫疏最嬰鱗。", "建功不作於潜死，誰爲君王說厚倫。"]'),
('12bc3067-ce8e-47f0-a63f-1932ce0598f9','內翰洪公舜俞哀詩二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','回首楊州一夢餘，故交已直玉堂廬。',64,'全唐诗/poet.song.199000.json','["回首楊州一夢餘，故交已直玉堂廬。", "寒暄未省通君實，窮薄空煩誦子虛。", "甚愧丈人於甫厚，孰云夫子不回如。", "殘年無復陪精論，開闔平生幾幅書。"]'),
('e11c94a9-24be-47ae-a22a-512365ecea9f','送李漕用之二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','斜飛慶曆皇華遠，捷出熙寧使指新。',64,'全唐诗/poet.song.199000.json','["斜飛慶曆皇華遠，捷出熙寧使指新。", "但記歐公更此職，不知趙濟是何人。", "剡章徧及孤寒士，奮筆先誅聚歛臣。", "自歎暮年衰颯甚，羨君老手獨埋輪。"]'),
('f35a9494-3071-4ca4-98ba-b4be8197ad5f','送李漕用之二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','漢廷鹽鐵議交攻，有詔姑惟舊法從。',64,'全唐诗/poet.song.199000.json','["漢廷鹽鐵議交攻，有詔姑惟舊法從。", "聞道嶺南歌聖主，一如河北感仁宗。", "向舒自是堪王佐，桑孔安知富大農。", "它日公歸奉清問，可無鯁論贊烹封。"]'),
('b15846f9-82ec-40cf-94c7-4a96f82fa98b','答謝法曹','劉克莊','宋','宋诗','song-poetry','','[]','二詩簡澹掃穠華，作者幾無以復加。',64,'全唐诗/poet.song.199000.json','["二詩簡澹掃穠華，作者幾無以復加。", "璧十五城方定價，桃三千歲一開花。", "選騷意度卑唐體，晉宋文章讓謝家。", "莫道老夫今耄矣，平章此事不應差。"]'),
('b5f2275c-5c53-4336-92da-409ba84d1487','次王實之家塾韻','劉克莊','宋','宋诗','song-poetry','','[]','新敞朱甍映碧岑，高門誰識慶源深。',64,'全唐诗/poet.song.199000.json','["新敞朱甍映碧岑，高門誰識慶源深。", "畤郊已解傳家學，石禮皆堪直禁林。", "七葉文章真有種，二郎官職本無心。", "庭前玉樹成陰未，著手栽培昉自今。"]'),
('fd607c40-82ee-482e-bf48-8ea2e75725b6','喜湯伯紀登第','劉克莊','宋','宋诗','song-poetry','','[]','老覺人間無一忻，怪來乾鵲耳邊聞。',64,'全唐诗/poet.song.199000.json','["老覺人間無一忻，怪來乾鵲耳邊聞。", "休嗔窮鬼揶揄我，絕喜春官摸索君。", "疇昔先生有高第，即今後死與斯文。", "不應也躍看花馬，忘却江天樹與雲。"]'),
('a45eae4e-3a81-423c-b727-69d3b4af80f9','三月二十一日泛舟十絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','少游款段何從借，伯厚雞栖未易求。',32,'全唐诗/poet.song.199000.json','["少游款段何從借，伯厚雞栖未易求。", "看取後村翁簡徑，百錢聊稅一漁舟。"]'),
('0576edab-9ca8-41a4-9d9d-618532159f62','三月二十一日泛舟十絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','退之歲晚南溪上，把釣聯詩得幾迴。',32,'全唐诗/poet.song.199000.json','["退之歲晚南溪上，把釣聯詩得幾迴。", "便與烏衣羣從約，及身强健更頻來。"]'),
('fe65f9d1-d3cd-4b1e-a10e-d94345f81e7c','三月二十一日泛舟十絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','向來平勃頗相知，使粵歸來歲月移。',32,'全唐诗/poet.song.199000.json','["向來平勃頗相知，使粵歸來歲月移。", "只以一篙爲導從，亦無劍馬可相隨。"]'),
('4274127b-3b1a-4f28-a5af-fb309887b1ba','三月二十一日泛舟十絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','橋低水漲過船難，旋拆船篷復旋安。',32,'全唐诗/poet.song.199000.json','["橋低水漲過船難，旋拆船篷復旋安。", "未免屈蟠篷底坐，誰教君愛切雲冠。"]'),
('4f0d118b-71ff-4b08-8f92-ea78397553db','三月二十一日泛舟十絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','弟兄玉映更珠聯，豈減玄暉與惠連。',32,'全唐诗/poet.song.199000.json','["弟兄玉映更珠聯，豈減玄暉與惠連。", "却笑漢人無具眼，羨它李郭作神仙。"]'),
('bf23fba3-af74-4ec2-97b4-2b2184075d58','三月二十一日泛舟十絕  其六','劉克莊','宋','宋诗','song-poetry','','[]','眉洲嶼隔雪濤中，聞此山川髣髴同。',32,'全唐诗/poet.song.199000.json','["眉洲嶼隔雪濤中，聞此山川髣髴同。", "但是至人游息地，邦人處處作離宮。"]'),
('d0dfd412-076a-4154-ae74-949cf0605596','三月二十一日泛舟十絕  其七','劉克莊','宋','宋诗','song-poetry','','[]','雖沉璧馬計安施，倏忽桑田變渺瀰。',32,'全唐诗/poet.song.199000.json','["雖沉璧馬計安施，倏忽桑田變渺瀰。", "說與神通君看取，潮頭不到艮山祠。"]'),
('b31fbeb0-ddb9-402f-93af-9606897c88ce','三月二十一日泛舟十絕  其八','劉克莊','宋','宋诗','song-poetry','','[]','溪北溪南一雨通，山村佳處便掀篷。',32,'全唐诗/poet.song.199000.json','["溪北溪南一雨通，山村佳處便掀篷。", "老身不怕無安處，著在漁翁保社中。"]'),
('c4e3fc3f-16da-493a-8edd-424103958862','三月二十一日泛舟十絕  其九','劉克莊','宋','宋诗','song-poetry','','[]','稚子呼牛婦饁耕，早秧水足麥風清。',32,'全唐诗/poet.song.199000.json','["稚子呼牛婦饁耕，早秧水足麥風清。", "老農喜極還垂涕，白首安知再太平。"]'),
('b8aaa8b6-54e8-4070-bfe3-1904760531eb','三月二十一日泛舟十絕  其一○','劉克莊','宋','宋诗','song-poetry','','[]','本朝耆舊數吾宗，老監軒昂洛社中。',32,'全唐诗/poet.song.199000.json','["本朝耆舊數吾宗，老監軒昂洛社中。", "後五百年人定說，過江復有戴花翁。"]'),
('7256465c-df5d-4757-9346-440908fd0894','三月二十五日飲方校書園十絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','纔入中年會面難，安知白首此團欒。',32,'全唐诗/poet.song.199000.json','["纔入中年會面難，安知白首此團欒。", "不妨時駕柴車出，只作初騎竹馬看。"]'),
('8e43096d-b1f4-4ad6-94d1-02bda4888d5d','三月二十五日飲方校書園十絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','伯兄廼漢司徒掾，季子亦唐行祕書。',32,'全唐诗/poet.song.199000.json','["伯兄廼漢司徒掾，季子亦唐行祕書。", "只願荆花常爛熳，莫令瓜蔓稍稀疎。"]'),
('0c42291d-2ff8-492d-8463-886d0bf041cf','三月二十五日飲方校書園十絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','自古根深枝葉蕃，百年喬木到今存。',32,'全唐诗/poet.song.199000.json','["自古根深枝葉蕃，百年喬木到今存。", "只留諫草傳家世，莫著軺車辱戶門。"]'),
('3799cc9a-92c8-423d-8bb8-159f9fd33cfd','三月二十五日飲方校書園十絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','西舍鳴笳索賦詩，東家拽石請書碑。',32,'全唐诗/poet.song.199000.json','["西舍鳴笳索賦詩，東家拽石請書碑。", "眼中除却壺山外，多是新知少舊知。"]'),
('97f93fde-2269-4ffb-ba25-ef8dd1c0b2da','三月二十五日飲方校書園十絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','呼來不許望清光，麾去奚堪作省郎。',32,'全唐诗/poet.song.199000.json','["呼來不許望清光，麾去奚堪作省郎。", "莫是後身劉快活，插花重入少年場。"]'),
('9d0c207b-b1b7-4f2e-90a7-eb268a699b49','三月二十五日飲方校書園十絕  其六','劉克莊','宋','宋诗','song-poetry','','[]','石室千年不復開，庭花無語委蒼苔。',32,'全唐诗/poet.song.199000.json','["石室千年不復開，庭花無語委蒼苔。", "席間舊客惟枚叟，白髮重將屐齒來。"]'),
('deb2e2ea-c290-4294-8952-743887b3ee05','三月二十五日飲方校書園十絕  其七','劉克莊','宋','宋诗','song-poetry','','[]','空留蘚石仆斜陽，不見奇章與贊皇。',32,'全唐诗/poet.song.199000.json','["空留蘚石仆斜陽，不見奇章與贊皇。", "何必雍門彈一曲，蟬聲極意說凄凉。"]'),
('8ed50480-ed5a-4f0e-b1db-a0a59ab12912','三月二十五日飲方校書園十絕  其八','劉克莊','宋','宋诗','song-poetry','','[]','百年如電復如風，昨日孩提今日翁。',32,'全唐诗/poet.song.199000.json','["百年如電復如風，昨日孩提今日翁。", "乍可生前稱醉漢，也勝死後謚愚公。"]'),
('8fa931cc-48f3-4493-8ee2-806782ac7ce8','三月二十五日飲方校書園十絕  其九','劉克莊','宋','宋诗','song-poetry','','[]','早退分明勝一籌，年行六十復何求。',32,'全唐诗/poet.song.199000.json','["早退分明勝一籌，年行六十復何求。", "東門瓜與南山豆，誰道君恩薄故侯。"]'),
('ae4404fd-13af-4b77-b817-06cff0c1efa6','三月二十五日飲方校書園十絕  其一○','劉克莊','宋','宋诗','song-poetry','','[]','後有良工識苦心，今無善聽孰知音。',32,'全唐诗/poet.song.199000.json','["後有良工識苦心，今無善聽孰知音。", "老來字字趨平易，免被兒童議刻深。"]'),
('ce7b405a-fa2f-4fd9-9e78-fad692c1fc5d','題江貫道山水十絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','世間平遠景，萬幅在洪家。',24,'全唐诗/poet.song.199000.json','["世間平遠景，萬幅在洪家。", "晚至番君國，方知不是夸。"]'),
('0cfefa0e-ea57-465f-b2a6-5c11a1b2c303','題江貫道山水十絕  其二','劉克莊','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','一棹微茫裏，孤亭紫翠間。',24,'全唐诗/poet.song.199000.json','["一棹微茫裏，孤亭紫翠間。", "恍疑涉彭蠡，又似訪廬山。"]'),
('13ba91da-e743-4870-af1a-fa59726353e5','題江貫道山水十絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','江險不容極，禹功胡可忘。',24,'全唐诗/poet.song.199000.json','["江險不容極，禹功胡可忘。", "向來小龍子，衮冕食千羊。"]'),
('8f9fda73-3f51-4837-af3f-b10b301ead11','題江貫道山水十絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','夾立朝羣玉，濃粧列萬筓。',24,'全唐诗/poet.song.199000.json','["夾立朝羣玉，濃粧列萬筓。", "中州不敢頓，拋在瘴雲西。"]'),
('41d4df07-fae9-4ceb-94bd-140738640c5d','題江貫道山水十絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','茆山千萬疊，不得見天全。',24,'全唐诗/poet.song.199000.json','["茆山千萬疊，不得見天全。", "帆出扶胥口，無山只有天。"]'),
('cb1f5825-e98e-4465-b72b-e35b25a5867b','題江貫道山水十絕  其六','劉克莊','宋','宋诗','song-poetry','','[]','雪冒禹碑石，雲埋泌草堂。',24,'全唐诗/poet.song.199000.json','["雪冒禹碑石，雲埋泌草堂。", "早知抱遺恨，悔不挾乾糧。"]'),
('5c3548cc-deaf-47e9-96e7-b7f79741b50c','題江貫道山水十絕  其七','劉克莊','宋','宋诗','song-poetry','','[]','半夜黄天蕩，樓船雪浪中。',24,'全唐诗/poet.song.199000.json','["半夜黄天蕩，樓船雪浪中。", "當年草檄客，今日負樵翁。"]'),
('d87786bf-702a-417c-8990-2938aa0fa5c3','題江貫道山水十絕  其八','劉克莊','宋','宋诗','song-poetry','','[]','太武求溲處，支祁著鏁邊。',24,'全唐诗/poet.song.199000.json','["太武求溲處，支祁著鏁邊。", "淮風晨裂面，淮浪夜驚船。"]'),
('87116cce-6f10-4d6b-8b80-92ac4e4738bd','題江貫道山水十絕  其九','劉克莊','宋','宋诗','song-poetry','','[]','展卷嗟丘也，東西南北人。',24,'全唐诗/poet.song.199000.json','["展卷嗟丘也，東西南北人。", "昔還行脚債，今作卧遊身。"]'),
('cbc577db-8af1-4a43-9591-b53ff8cdce9d','題江貫道山水十絕  其一○','劉克莊','宋','宋诗','song-poetry','','[]','一匹好東絹，天寒家未溫。',24,'全唐诗/poet.song.199000.json','["一匹好東絹，天寒家未溫。", "儘教兒拆繡，閑管婦無禈。"]'),
('05c211a3-b5b0-46e3-b0f5-c9f64410e748','雜詠一百首 萇弘','劉克莊','宋','宋诗','song-poetry','','[]','宗周危可憫，萇叔死非難。',24,'全唐诗/poet.song.199000.json','["宗周危可憫，萇叔死非難。", "臣血三年碧，臣心一寸丹。"]'),
('bb20f3f5-b416-4e3a-9511-c02854cc8a9e','雜詠一百首 柳下惠','劉克莊','宋','宋诗','song-poetry','','[]','不怨窮并佚，能安小與卑。',24,'全唐诗/poet.song.199000.json','["不怨窮并佚，能安小與卑。", "何須立奇節，展季即吾師。"]'),
('d8250f07-d4eb-4e24-9e71-6759c06c15bc','雜詠一百首 樂毅','劉克莊','宋','宋诗','song-poetry','','[]','忿懟及韓駟，荒唐入郢鞭。',24,'全唐诗/poet.song.199000.json','["忿懟及韓駟，荒唐入郢鞭。", "樂生端可拜，寧死不謀燕。"]'),
